def migrate_guild_economy_tables():
    c.execute("PRAGMA table_info(users)")
    user_columns = [row[1] for row in c.fetchall()]
    if "guild_id" not in user_columns:
        c.execute("ALTER TABLE users RENAME TO users_old")
        c.execute("""
        CREATE TABLE users (
            guild_id INTEGER DEFAULT 0,
            user_id INTEGER,
            point INTEGER DEFAULT 0,
            attendance_count INTEGER DEFAULT 0,
            streak INTEGER DEFAULT 0,
            last_attendance TEXT,
            PRIMARY KEY (guild_id, user_id)
        )
        """)
        c.execute("""
        INSERT OR IGNORE INTO users(guild_id, user_id, point, attendance_count, streak, last_attendance)
        SELECT 0, user_id, point, attendance_count, streak, last_attendance FROM users_old
        """)
        c.execute("DROP TABLE users_old")

    c.execute("PRAGMA table_info(daily_rewards)")
    reward_columns = [row[1] for row in c.fetchall()]
    if "guild_id" not in reward_columns:
        c.execute("ALTER TABLE daily_rewards RENAME TO daily_rewards_old")
        c.execute("""
        CREATE TABLE daily_rewards (
            guild_id INTEGER DEFAULT 0,
            user_id INTEGER,
            last_reward TEXT,
            PRIMARY KEY (guild_id, user_id)
        )
        """)
        c.execute("""
        INSERT OR IGNORE INTO daily_rewards(guild_id, user_id, last_reward)
        SELECT 0, user_id, last_reward FROM daily_rewards_old
        """)
        c.execute("DROP TABLE daily_rewards_old")
    conn.commit()



migrate_guild_economy_tables()


def migrate_guild_embed_config_tables():
    """예전 database.db의 임베드 설정 테이블을 서버별 저장 구조로 자동 변환합니다.

    예전 버전에서 auto_embeds/recruit_embeds가 embed_type/recruit_key 하나만 기준으로
    저장되어 있으면, 한 서버에서 수정한 /패널 디자인이 다른 서버에도 같이 적용될 수 있습니다.
    이 마이그레이션은 PRIMARY KEY를 (guild_id, embed_type), (guild_id, recruit_key)로
    다시 만들어서 서버마다 독립적으로 저장되게 합니다.
    """

    def _table_info(table_name: str):
        c.execute(f"PRAGMA table_info({table_name})")
        return c.fetchall()

    def _pk_columns(info):
        return [row[1] for row in sorted([row for row in info if row[5] > 0], key=lambda row: row[5])]

    def _value_expr(column: str, old_columns: set, default_sql: str = "NULL"):
        return column if column in old_columns else default_sql

    def _rebuild_auto_like_table(table_name: str, key_column: str):
        info = _table_info(table_name)
        if not info:
            return
        old_columns = {row[1] for row in info}
        expected_pk = ["guild_id", key_column]
        if "guild_id" in old_columns and key_column in old_columns and _pk_columns(info) == expected_pk:
            return

        backup_table = f"{table_name}_old_guild_migrate"
        c.execute(f"DROP TABLE IF EXISTS {backup_table}")
        c.execute(f"ALTER TABLE {table_name} RENAME TO {backup_table}")
        c.execute(f"""
        CREATE TABLE {table_name} (
            guild_id INTEGER DEFAULT 0,
            {key_column} TEXT,
            title TEXT,
            description TEXT,
            color TEXT,
            image_url TEXT,
            footer TEXT,
            updated_at TEXT,
            PRIMARY KEY (guild_id, {key_column})
        )
        """)

        guild_expr = "COALESCE(guild_id, 0)" if "guild_id" in old_columns else "0"
        key_expr = _value_expr(key_column, old_columns, "'default'")
        title_expr = _value_expr("title", old_columns)
        description_expr = _value_expr("description", old_columns)
        color_expr = _value_expr("color", old_columns)
        image_expr = _value_expr("image_url", old_columns)
        footer_expr = _value_expr("footer", old_columns)
        updated_expr = _value_expr("updated_at", old_columns)

        c.execute(f"""
        INSERT OR IGNORE INTO {table_name}(
            guild_id, {key_column}, title, description, color, image_url, footer, updated_at
        )
        SELECT
            {guild_expr}, {key_expr}, {title_expr}, {description_expr},
            {color_expr}, {image_expr}, {footer_expr}, {updated_expr}
        FROM {backup_table}
        WHERE {key_expr} IS NOT NULL AND {key_expr} != ''
        """)
        c.execute(f"DROP TABLE IF EXISTS {backup_table}")

    def _rebuild_welcome_table():
        table_name = "welcome_embeds"
        info = _table_info(table_name)
        if not info:
            return
        old_columns = {row[1] for row in info}
        if "guild_id" in old_columns and _pk_columns(info) == ["guild_id"]:
            return

        backup_table = f"{table_name}_old_guild_migrate"
        c.execute(f"DROP TABLE IF EXISTS {backup_table}")
        c.execute(f"ALTER TABLE {table_name} RENAME TO {backup_table}")
        c.execute("""
        CREATE TABLE welcome_embeds (
            guild_id INTEGER PRIMARY KEY,
            title TEXT,
            description TEXT,
            color TEXT,
            image_url TEXT,
            footer TEXT,
            updated_at TEXT
        )
        """)

        guild_expr = "COALESCE(guild_id, 0)" if "guild_id" in old_columns else "0"
        c.execute(f"""
        INSERT OR IGNORE INTO welcome_embeds(
            guild_id, title, description, color, image_url, footer, updated_at
        )
        SELECT
            {guild_expr},
            {_value_expr('title', old_columns)},
            {_value_expr('description', old_columns)},
            {_value_expr('color', old_columns)},
            {_value_expr('image_url', old_columns)},
            {_value_expr('footer', old_columns)},
            {_value_expr('updated_at', old_columns)}
        FROM {backup_table}
        """)
        c.execute(f"DROP TABLE IF EXISTS {backup_table}")

    _rebuild_welcome_table()
    _rebuild_auto_like_table("auto_embeds", "embed_type")
    _rebuild_auto_like_table("recruit_embeds", "recruit_key")
    conn.commit()


migrate_guild_embed_config_tables()

