def default_censor_category_state(category_key: str) -> bool:
    return bool(CENSOR_CATEGORY_LABELS.get(category_key, {}).get("default", True))


def ensure_censor_category_settings(guild_id: int):
    """카테고리별 검열 설정을 서버별 기본값으로 준비합니다."""
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    try:
        for key in CENSOR_CATEGORY_ORDER:
            c.execute(
                """
                INSERT OR IGNORE INTO censor_category_settings(guild_id, category_key, enabled, updated_at)
                VALUES (?, ?, ?, ?)
                """,
                (guild_id, key, 1 if default_censor_category_state(key) else 0, now)
            )
        conn.commit()
    except sqlite3.Error:
        pass


def get_censor_category_settings(guild_id: int):
    ensure_censor_category_settings(guild_id)
    defaults = {key: default_censor_category_state(key) for key in CENSOR_CATEGORY_ORDER}
    try:
        c.execute(
            "SELECT category_key, enabled FROM censor_category_settings WHERE guild_id=?",
            (guild_id,)
        )
        for key, enabled in c.fetchall():
            if key in defaults:
                defaults[key] = bool(enabled)
    except sqlite3.Error:
        pass
    return defaults


def set_censor_category_setting(guild_id: int, category_key: str, enabled: bool):
    if category_key not in CENSOR_CATEGORY_LABELS:
        return
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    try:
        c.execute(
            """
            INSERT INTO censor_category_settings(guild_id, category_key, enabled, updated_at)
            VALUES (?, ?, ?, ?)
            ON CONFLICT(guild_id, category_key) DO UPDATE SET
                enabled=excluded.enabled,
                updated_at=excluded.updated_at
            """,
            (guild_id, category_key, 1 if enabled else 0, now)
        )
        conn.commit()
    except sqlite3.Error:
        pass


def set_all_censor_category_settings(guild_id: int, enabled: bool):
    for key in CENSOR_CATEGORY_ORDER:
        set_censor_category_setting(guild_id, key, enabled)


def build_censor_panel_embed(guild: discord.Guild):
    settings = get_security_settings(guild.id)
    censor_settings = get_censor_category_settings(guild.id)
    custom_word_count = len(get_custom_filter_words(guild.id))
    recent_logs = count_security_logs(guild.id, 24)

    embed = create_embed(
        "🧹 검열켜기 통합 패널",
        "버튼을 누르면 해당 검열/스팸 보호가 바로 켜집니다.\n"
        "이 패널과 버튼은 **관리자만 사용**할 수 있고, 관리자 메시지는 검열하지 않습니다.\n\n"
        f"🧹 자동검열 마스터: **{security_state_text(settings['auto_filter'])}**\n"
        f"⚠️ 스팸보호 마스터: **{security_state_text(settings['spam_protection'])}**\n"
        f"📑 보안로그 저장: **{security_state_text(settings['security_log_enabled'])}**\n"
        f"최근 24시간 검열/보안 기록: `{recent_logs}`건"
    )

    message_text = []
    spam_text = []
    for key in CENSOR_CATEGORY_ORDER:
        info = CENSOR_CATEGORY_LABELS[key]
        line = (
            f"{info['emoji']} **{info['label']}**: {security_state_text(censor_settings.get(key, default_censor_category_state(key)))}\n"
            f"└ {info['desc']}"
        )
        if info.get("group") == "spam":
            spam_text.append(line)
        else:
            message_text.append(line)

    embed.add_field(
        name="📂 메시지 검열 카테고리",
        value="\n".join(message_text),
        inline=False
    )
    embed.add_field(
        name="🚨 스팸/도배 검열 카테고리",
        value="\n".join(spam_text),
        inline=False
    )
    embed.add_field(
        name="🛡️ 추가 보호 기능",
        value=(
            f"📣 멘션검열: **{security_state_text(settings['mention_spam_detection'])}**\n"
            f"📎 위험파일검열: **{security_state_text(settings['dangerous_file_block'])}**\n"
            f"🔐 토큰보호: **{security_state_text(settings['token_leak_guard'])}**\n"
            f"👶 새계정보호: **{security_state_text(settings['new_account_guard'])}**\n"
            f"🚨 테러감지: **{security_state_text(settings['raid_detection'])}**\n"
            f"🛡️ 권한보호: **{security_state_text(settings['permission_guard'])}**"
        ),
        inline=False
    )
    embed.add_field(
        name="🧾 차단단어 관리",
        value=(
            f"서버 추가 차단단어: `{custom_word_count}`개\n"
            "단어 추가: `/설정 차단단어추가`\n"
            "단어 삭제: `/설정 차단단어삭제`\n"
            "단어 확인: `/설정 차단단어목록`"
        ),
        inline=False
    )
    embed.set_footer(text="만능 봇 | /검열켜기 | 관리자 전용")
    return embed


def add_security_log(guild_id: int, user_id: int, action: str, reason: str, channel_id: int = 0):
    settings = get_security_settings(guild_id)
    if not settings.get("security_log_enabled"):
        return
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute(
        """
        INSERT INTO security_logs(guild_id, user_id, action, reason, channel_id, created_at)
        VALUES (?, ?, ?, ?, ?, ?)
        """,
        (guild_id, user_id or 0, action[:100], reason[:700], channel_id or 0, now)
    )
    conn.commit()


def list_security_logs(guild_id: int, limit: int = SECURITY_LOG_PREVIEW_LIMIT):
    c.execute(
        """
        SELECT user_id, action, reason, channel_id, created_at
        FROM security_logs
        WHERE guild_id=?
        ORDER BY log_id DESC
        LIMIT ?
        """,
        (guild_id, limit)
    )
    return c.fetchall()


def count_security_logs(guild_id: int, hours: int = 24):
    cutoff = (datetime.datetime.now() - datetime.timedelta(hours=hours)).strftime("%Y-%m-%d %H:%M:%S")
    c.execute(
        "SELECT COUNT(*) FROM security_logs WHERE guild_id=? AND created_at>=?",
        (guild_id, cutoff)
    )
    row = c.fetchone()
    return row[0] if row else 0


def looks_like_discord_token(content: str) -> bool:
    return bool(content and SECURITY_TOKEN_REGEX.search(content))


def find_dangerous_attachment_name(message: discord.Message):
    for attachment in getattr(message, "attachments", []):
        filename = (attachment.filename or "").lower().strip()
        if not filename:
            continue
        if any(filename.endswith(ext) for ext in SECURITY_DANGEROUS_EXTENSIONS):
            return attachment.filename
        # 예: image.png.exe, file.txt.js 처럼 이중 확장자 위장도 잡습니다.
        parts = filename.split(".")
        if len(parts) >= 3 and f".{parts[-1]}" in SECURITY_DANGEROUS_EXTENSIONS:
            return attachment.filename
    return None


def dangerous_permissions_from(perms: discord.Permissions):
    result = []
    for attr, label in SECURITY_DANGEROUS_PERMISSION_NAMES.items():
        if getattr(perms, attr, False):
            result.append(label)
    return result


def dangerous_permissions_added(before: discord.Permissions, after: discord.Permissions):
    result = []
    for attr, label in SECURITY_DANGEROUS_PERMISSION_NAMES.items():
        if not getattr(before, attr, False) and getattr(after, attr, False):
            result.append(label)
    return result


async def add_auto_warning(member: discord.Member, reason: str):
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute("INSERT INTO warnings VALUES (?, ?, ?, ?)", (member.id, bot.user.id if bot.user else 0, reason, now))
    conn.commit()
    try:
        return await update_warning_role(member)
    except Exception:
        return 0


async def get_audit_log_user(guild: discord.Guild, action: discord.AuditLogAction, target_id: int):
    try:
        async for entry in guild.audit_logs(limit=5, action=action):
            if entry.target and getattr(entry.target, "id", None) == target_id:
                return entry.user
    except (discord.Forbidden, discord.HTTPException):
        return None
    return None


async def track_raid_action(guild: discord.Guild, actor: discord.User, action_text: str):
    settings = get_security_settings(guild.id)
    if not settings.get("raid_detection") or actor is None or actor.bot:
        return

    member = guild.get_member(actor.id)
    if member and member == guild.owner:
        return

    now_ts = datetime.datetime.now().timestamp()
    key = (guild.id, actor.id)
    SECURITY_ACTION_TRACKER.setdefault(key, []).append(now_ts)
    SECURITY_ACTION_TRACKER[key] = [t for t in SECURITY_ACTION_TRACKER[key] if now_ts - t <= 30]
    count = len(SECURITY_ACTION_TRACKER[key])
    add_security_log(guild.id, actor.id, "테러감지", f"{action_text} / 최근 30초 {count}회", 0)

    if count >= 3:
        await send_log(
            guild,
            f"🚨 테러감지 경고\n대상: {actor.mention}\n최근 30초 내 위험 작업: `{count}`회\n마지막 작업: `{action_text}`\n관리자는 권한/역할을 바로 확인해주세요.",
            "punishment"
        )
    else:
        await send_log(
            guild,
            f"🛡️ 테러감지 기록\n대상: {actor.mention}\n작업: `{action_text}`\n최근 기록: `{count}/3`",
            "general"
        )


def get_channel_by_id_or_name(guild: discord.Guild, channel_id: int = 0, names=None, channel_type: str = "text"):
    if guild is None:
        return None

    if channel_id:
        channel = guild.get_channel(channel_id)
        if channel:
            return channel

    names = names or []
    channel_list = guild.text_channels if channel_type == "text" else guild.voice_channels
    for name in names:
        channel = discord.utils.get(channel_list, name=name)
        if channel:
            return channel
    return None


def get_role_by_id_or_name(guild: discord.Guild, role_id: int = 0, names=None):
    if guild is None:
        return None

    if role_id:
        role = guild.get_role(role_id)
        if role:
            return role

    names = names or []
    for name in names:
        role = discord.utils.get(guild.roles, name=name)
        if role:
            return role
    return None


def channel_mention_by_id_or_name(guild: discord.Guild, channel_id: int = 0, names=None):
    channel = get_channel_by_id_or_name(guild, channel_id, names, "text")
    return channel.mention if channel else "미설정"


def role_mention_by_id_or_name(guild: discord.Guild, role_id: int = 0, names=None):
    role = get_role_by_id_or_name(guild, role_id, names)
    return role.mention if role else "미설정"


BOOST_CHANNEL_NAMES = [
    "🚀︱서버부스트",
    "🚀ㅣ서버부스트",
    "🚀-서버부스트",
    "💎︱서버부스트",
    "💎-서버부스트",
    "서버부스트",
    "부스트",
    "server-boost",
    "boost",
]


def get_boost_channel(guild: discord.Guild):
    """서버별 부스트 알림 채널을 찾습니다. 없으면 인사-퇴장 채널로 대체합니다."""
    if guild is None:
        return None

    saved_id = get_saved_channel_id(guild.id, "boost_channel_id")
    channel = get_channel_by_id_or_name(guild, saved_id or BOOST_CHANNEL_ID, BOOST_CHANNEL_NAMES, "text")
    if channel:
        return channel

    return get_channel_by_id_or_name(
        guild,
        get_saved_channel_id(guild.id, "welcome_channel_id") or WELCOME_CHANNEL_ID,
        ["👋︱인사-퇴장", "👋ㅣ인사-퇴장", "👋-인사-퇴장", "인사-퇴장", "환영", "welcome"],
        "text"
    )


def build_boost_notification_embed(member: discord.Member, *, removed: bool = False):
    guild = member.guild
    boost_count = getattr(guild, "premium_subscription_count", 0) or 0
    boost_tier = getattr(guild, "premium_tier", 0) or 0

    # 해제 알림은 별도 커스텀 설정이 없으면 예전 기본 문구를 유지합니다.
    # 관리자가 /패널에서 서버부스트알림을 저장하면 해제 알림도 같은 커스텀 임베드를 사용합니다.
    if removed and not has_auto_embed_config(guild.id, "panel_boost"):
        embed = discord.Embed(
            title="💔 서버 부스트 알림",
            description=(
                f"{member.mention} 님의 서버 부스트가 해제되었어요.\n\n"
                f"현재 서버 부스트 수: **{boost_count}개**\n"
                f"현재 서버 부스트 레벨: **Lv.{boost_tier}**"
            ),
            color=0xF47FFF
        )
    else:
        config = get_auto_embed_config(guild.id, "panel_boost")
        embed = discord.Embed(
            title=render_boost_embed_text(config.get("title", ""), member, removed=removed)[:256],
            description=render_boost_embed_text(config.get("description", ""), member, removed=removed)[:4096],
            color=normalize_embed_color(config.get("color", "F47FFF"))
        )
        footer = render_boost_embed_text(config.get("footer", ""), member, removed=removed)[:2048]
        if footer:
            embed.set_footer(text=footer)
        image_url = safe_url(config.get("image_url", ""))
        if image_url:
            embed.set_image(url=image_url)

    embed.set_author(name=str(member), icon_url=member.display_avatar.url)
    if guild.icon:
        embed.set_thumbnail(url=guild.icon.url)
    if not embed.footer.text:
        embed.set_footer(text=f"{guild.name} | 서버 부스트 알림")
    return embed

async def send_server_boost_notification(before: discord.Member, after: discord.Member):
    """서버별 부스트 시작/해제 알림을 전송합니다."""
    if after.guild is None or after.bot:
        return

    before_boost = getattr(before, "premium_since", None)
    after_boost = getattr(after, "premium_since", None)

    # 부스트 상태가 바뀌지 않았다면 알림을 보내지 않습니다.
    if before_boost == after_boost:
        return

    channel = get_boost_channel(after.guild)
    if channel is None:
        return

    removed = bool(before_boost and not after_boost)
    embed = build_boost_notification_embed(after, removed=removed)

    try:
        if removed:
            await channel.send(embed=embed)
        else:
            await channel.send(content=f"🎉 {after.mention}", embed=embed)
        await send_log(
            after.guild,
            f"{'💔 서버 부스트 해제' if removed else '🚀 서버 부스트'}\n유저: {after.mention}\n채널: {channel.mention}",
            "general"
        )
    except (discord.Forbidden, discord.HTTPException):
        pass


def get_log_channel(guild: discord.Guild, log_type: str = "general"):
    if guild is None:
        return None

    # 웹 대시보드에서 연결한 로그 채널을 최우선으로 사용합니다.
    log_column_map = {
        "general": "general_log_channel_id",
        "warning": "warning_log_channel_id",
        "punishment": "punishment_log_channel_id",
        "chat": "chat_log_channel_id",
        "voice": "voice_log_channel_id",
        "nickname": "nickname_log_channel_id",
        "level": "level_log_channel_id",
        "security": "security_log_channel_id",
        "clean": "clean_log_channel_id",
    }
    saved_id = get_saved_channel_id(guild.id, log_column_map.get(log_type, "log_channel_id")) or get_saved_channel_id(guild.id, "log_channel_id")
    if saved_id:
        channel = guild.get_channel(saved_id)
        if channel:
            return channel

    channel_name = LOG_CHANNEL_NAMES.get(log_type, LOG_CHANNEL_NAMES["general"])
    channel = discord.utils.get(guild.text_channels, name=channel_name)
    if channel:
        return channel

    # 로그 카테고리를 아직 만들지 않았을 때 기존 LOG_CHANNEL_ID 또는 일반적인 로그 채널명으로도 로그가 가게 유지
    fallback = get_channel_by_id_or_name(guild, LOG_CHANNEL_ID, ["📋-일반로그", "bot-log", "로그", "관리로그"], "text")
    return fallback


def mnb_should_skip_duplicate_log(guild_id: int, log_type: str, message: str) -> bool:
    """같은 로그가 짧은 시간에 2번 찍히는 것을 막습니다.

    전역 슬래시+서버 슬래시 중복, on_ready 재진입, 같은 이벤트 중복 처리,
    같은 서버에서 봇 프로세스가 2개 켜진 상황에서 같은 DB를 공유하는 경우까지 최대한 줄입니다.
    """
    now_ts = time.time()
    raw_key = f"{guild_id}:{log_type}:{message}"
    key = hashlib.sha256(raw_key.encode("utf-8", errors="ignore")).hexdigest()

    # 메모리 1차 방어
    old_ts = MNB_LOG_DEDUPE_MEMORY.get(key, 0)
    if now_ts - old_ts < MNB_LOG_DEDUPE_SECONDS:
        return True
    MNB_LOG_DEDUPE_MEMORY[key] = now_ts

    # 메모리 정리
    if len(MNB_LOG_DEDUPE_MEMORY) > 500:
        cutoff = now_ts - 60
        for old_key, ts in list(MNB_LOG_DEDUPE_MEMORY.items()):
            if ts < cutoff:
                MNB_LOG_DEDUPE_MEMORY.pop(old_key, None)

    # DB 2차 방어: 같은 database.db를 공유하는 중복 프로세스도 줄임
    try:
        with DB_MUTEX:
            c.execute("""
            CREATE TABLE IF NOT EXISTS runtime_dedupe_logs (
                dedupe_key TEXT PRIMARY KEY,
                created_ts REAL
            )
            """)
            c.execute("DELETE FROM runtime_dedupe_logs WHERE created_ts < ?", (now_ts - 60,))
            c.execute(
                "INSERT OR IGNORE INTO runtime_dedupe_logs(dedupe_key, created_ts) VALUES (?, ?)",
                (key, now_ts),
            )
            inserted = c.rowcount
            conn.commit()
        if inserted == 0:
            return True
    except Exception:
        # DB 방어가 실패해도 메모리 방어는 이미 적용됨
        pass

    return False


async def send_log(guild: discord.Guild, message: str, log_type: str = "general"):
    if guild is None:
        return
    if mnb_should_skip_duplicate_log(getattr(guild, "id", 0), log_type, message):
        return
    channel = get_log_channel(guild, log_type)
    if not channel:
        return
    try:
        await channel.send(message)
    except (discord.NotFound, discord.Forbidden, discord.HTTPException):
        pass


# =========================
# 봇 관리자 역할 권한
# =========================
# 이제 봇 세팅/관리 명령어는 특정 유저 ID를 따로 등록하지 않고,
# 서버에서 아래 역할을 가진 사람만 사용할 수 있습니다.
BOT_MANAGER_ROLE_NAMES = [
    "대표", "부대표", "총관리자", "부관리자",
    "운영진", "관리자", "팀장", "부팀장",
]


def get_authorized_user_ids():
    # 예전 DB 호환용입니다. 새 방식에서는 사용하지 않습니다.
    return set()


def has_bot_manager_role(member: discord.Member):
    if member is None:
        return False
    return any(role.name in BOT_MANAGER_ROLE_NAMES for role in getattr(member, "roles", []))


async def is_bot_owner_user(user: discord.User):
    if user.id in BOT_OWNER_IDS:
        return True
    try:
        return await bot.is_owner(user)
    except Exception:
        return False


async def reject_if_not_support_template_owner(interaction: discord.Interaction, action_name: str = "지원서버템플릿"):
    """지원서버템플릿/지원서버 전용 패널은 봇 소유자만 사용할 수 있게 막습니다."""
    if await is_bot_owner_user(interaction.user):
        return False

    message = (
        f"❌ `{action_name}`은 봇 소유자만 사용할 수 있습니다.\n"
        "Render 환경변수 `BOT_OWNER_IDS`에 본인 디스코드 ID를 넣어두면 더 확실하게 제한됩니다."
    )
    try:
        if interaction.response.is_done():
            await interaction.followup.send(message, ephemeral=True)
        else:
            await safe_interaction_send(interaction, message, ephemeral=True)
    except Exception:
        pass
    return True


async def can_use_owner_commands(user: discord.User):
    # 봇 소유자 전용 명령어도 서버 안에서는 대표~부팀장 역할이 사용할 수 있게 변경합니다.
    if isinstance(user, discord.Member) and has_bot_manager_role(user):
        return True
    return await is_bot_owner_user(user)


async def can_use_setup_commands(user: discord.User):
    if isinstance(user, discord.Member):
        if has_bot_manager_role(user):
            return True
        # 새 서버에서 역할을 만들기 전 최초 세팅은 서버 관리자도 사용할 수 있게 둡니다.
        if user.guild_permissions.administrator:
            return True
    return await is_bot_owner_user(user)


async def can_manage_bot_in_guild(interaction: discord.Interaction):
    if interaction.guild is None:
        return False
    return await can_use_setup_commands(interaction.user)


async def reject_if_not_setup_manager(interaction: discord.Interaction):
    if await can_manage_bot_in_guild(interaction):
        return False
    await safe_interaction_send(interaction, 
        "❌ 봇 관리자 역할(대표/부대표/총관리자/부관리자/운영진/관리자/팀장/부팀장)만 사용할 수 있습니다.",
        ephemeral=True
    )
    return True


async def reject_if_not_bot_manager(interaction: discord.Interaction):
    if await can_manage_bot_in_guild(interaction):
        return False
    await safe_interaction_send(interaction, 
        "❌ 봇 관리자 역할(대표~부팀장)만 사용할 수 있습니다.",
        ephemeral=True
    )
    return True


def save_guild_settings(guild: discord.Guild, *, welcome_channel=None, goodbye_channel=None, rule_channel=None, game_role_channel=None, log_channel=None):
    c.execute("SELECT guild_id FROM guild_settings WHERE guild_id=?", (guild.id,))
    exists = c.fetchone() is not None
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    values = {
        "welcome_channel_id": welcome_channel.id if welcome_channel else 0,
        "goodbye_channel_id": goodbye_channel.id if goodbye_channel else 0,
        "rule_channel_id": rule_channel.id if rule_channel else 0,
        "game_role_channel_id": game_role_channel.id if game_role_channel else 0,
        "log_channel_id": log_channel.id if log_channel else 0,
    }
    if exists:
        c.execute("""
            UPDATE guild_settings
            SET welcome_channel_id=COALESCE(NULLIF(?, 0), welcome_channel_id),
                goodbye_channel_id=COALESCE(NULLIF(?, 0), goodbye_channel_id),
                rule_channel_id=COALESCE(NULLIF(?, 0), rule_channel_id),
                game_role_channel_id=COALESCE(NULLIF(?, 0), game_role_channel_id),
                log_channel_id=COALESCE(NULLIF(?, 0), log_channel_id),
                updated_at=?
            WHERE guild_id=?
        """, (values["welcome_channel_id"], values["goodbye_channel_id"], values["rule_channel_id"], values["game_role_channel_id"], values["log_channel_id"], now, guild.id))
    else:
        c.execute("""
            INSERT INTO guild_settings(guild_id, welcome_channel_id, goodbye_channel_id, rule_channel_id, game_role_channel_id, log_channel_id, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
        """, (guild.id, values["welcome_channel_id"], values["goodbye_channel_id"], values["rule_channel_id"], values["game_role_channel_id"], values["log_channel_id"], now))
    conn.commit()



def save_guild_channel_ids(guild: discord.Guild, **channel_map):
    """guild_settings에 여러 채널/카테고리 ID를 한 번에 저장합니다."""
    if guild is None or not channel_map:
        return
    ensure_dashboard_sync_tables()
    allowed = set(dashboard_table_columns("guild_settings"))
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    try:
        c.execute("INSERT OR IGNORE INTO guild_settings(guild_id, updated_at) VALUES (?, ?)", (guild.id, now))
        for column, value in channel_map.items():
            if column not in allowed or column == "guild_id":
                continue
            if hasattr(value, "id"):
                saved_value = int(value.id)
            else:
                try:
                    saved_value = int(value or 0)
                except (TypeError, ValueError):
                    saved_value = 0
            c.execute(f"UPDATE guild_settings SET {column}=?, updated_at=? WHERE guild_id=?", (saved_value, now, guild.id))
        conn.commit()
    except sqlite3.Error:
        pass


def save_detected_guild_channels(guild: discord.Guild):
    """서버에 이미 만들어진 주요 채널들을 이름으로 찾아 서버별 설정에 저장합니다."""
    if guild is None:
        return {}

    welcome_channel = get_channel_by_id_or_name(
        guild, WELCOME_CHANNEL_ID,
        ["👋︱인사-퇴장", "👋ㅣ인사-퇴장", "👋-인사-퇴장", "인사-퇴장", "환영", "welcome"],
        "text"
    )
    goodbye_channel = get_channel_by_id_or_name(
        guild, GOODBYE_CHANNEL_ID,
        ["👋︱인사-퇴장", "👋ㅣ인사-퇴장", "👋-인사-퇴장", "인사-퇴장", "퇴장", "goodbye"],
        "text"
    )
    rule_channel = get_channel_by_id_or_name(
        guild, RULE_CHANNEL_ID,
        ["📌-필독", "📌︱필독", "📜︱이용규칙", "📜-규칙", "필독", "규칙"],
        "text"
    )
    intro_channel = get_channel_by_id_or_name(guild, 0, ["📝-자기소개", "📝︱자기소개", "자기소개"], "text")
    verify_channel = get_channel_by_id_or_name(guild, 0, ["✅-인증", "✅︱인증", "인증"], "text")
    notice_channel = get_channel_by_id_or_name(guild, 0, ["📢︱공지사항", "📢-공지사항", "공지사항", "공지"], "text")
    support_ticket_channel = get_channel_by_id_or_name(guild, 0, ["🎫︱티켓문의", "🎫-티켓문의", "티켓문의"], "text")
    support_welcome_channel = get_channel_by_id_or_name(
        guild, 0,
        ["👋︱인사-퇴장", "👋ㅣ인사-퇴장", "👋-인사-퇴장", "👋︱가입인사", "가입인사"],
        "text"
    )
    boost_channel = get_channel_by_id_or_name(guild, BOOST_CHANNEL_ID, BOOST_CHANNEL_NAMES, "text")
    game_role_channel = get_channel_by_id_or_name(guild, GAME_ROLE_CHANNEL_ID, ["🎮-게임역할선택", "🎮︱게임역할선택", "게임역할선택", "🎮-게임채팅"], "text")
    log_channel = get_log_channel(guild, "general")

    save_guild_settings(
        guild,
        welcome_channel=welcome_channel,
        goodbye_channel=goodbye_channel,
        rule_channel=rule_channel,
        game_role_channel=game_role_channel,
        log_channel=log_channel,
    )
    save_guild_channel_ids(
        guild,
        welcome_channel_id=welcome_channel,
        goodbye_channel_id=goodbye_channel,
        rule_channel_id=rule_channel,
        intro_channel_id=intro_channel,
        verify_channel_id=verify_channel,
        notice_channel_id=notice_channel,
        support_notice_channel_id=notice_channel,
        support_welcome_channel_id=support_welcome_channel,
        boost_channel_id=boost_channel,
        ticket_channel_id=support_ticket_channel,
        game_role_channel_id=game_role_channel,
        log_channel_id=log_channel,
    )
    return {
        "welcome_channel": welcome_channel,
        "goodbye_channel": goodbye_channel,
        "rule_channel": rule_channel,
        "intro_channel": intro_channel,
        "verify_channel": verify_channel,
        "notice_channel": notice_channel,
        "support_welcome_channel": support_welcome_channel,
        "support_ticket_channel": support_ticket_channel,
        "boost_channel": boost_channel,
        "game_role_channel": game_role_channel,
        "log_channel": log_channel,
    }


def get_saved_channel_id(guild_id: int, column: str):
    ensure_dashboard_sync_tables()
    if column not in DASHBOARD_GUILD_SETTING_COLUMNS and column not in {
        "welcome_channel_id", "goodbye_channel_id", "boost_channel_id", "rule_channel_id", "game_role_channel_id", "log_channel_id"
    }:
        return 0

    def _read_local():
        try:
            c.execute(f"SELECT {column} FROM guild_settings WHERE guild_id=?", (guild_id,))
            row = c.fetchone()
            return int(row[0]) if row and row[0] else 0
        except sqlite3.Error:
            return 0

    value = _read_local()
    if value:
        return value

    # 로컬 DB에 없으면 웹 대시보드 DB를 자동으로 읽어와서 저장합니다.
    ensure_dashboard_sync_for_guild(guild_id)
    return _read_local()



def get_default_role_ids(guild_id: int):
    c.execute("SELECT role_id FROM default_roles WHERE guild_id=?", (guild_id,))
    return [row[0] for row in c.fetchall()]


async def give_default_roles(member: discord.Member):
    """서버에 등록된 기본 역할을 신규 멤버에게 자동 지급합니다."""
    if member.bot or member.guild is None:
        return

    role_ids = get_default_role_ids(member.guild.id)
    if not role_ids:
        return

    roles = []
    for role_id in role_ids:
        role = member.guild.get_role(role_id)
        if role and not role.managed and role not in member.roles:
            roles.append(role)

    if not roles:
        return

    try:
        await member.add_roles(*roles, reason="기본 역할 자동 지급")
        role_text = ", ".join(role.mention for role in roles)
        await send_log(member.guild, f"🎭 기본 역할 자동 지급\n대상: {member.mention}\n역할: {role_text}", "general")
    except discord.Forbidden:
        await send_log(member.guild, f"❌ 기본 역할 자동 지급 실패\n대상: {member.mention}\n사유: 봇 역할 위치 또는 권한 부족", "general")
    except discord.HTTPException as e:
        await send_log(member.guild, f"❌ 기본 역할 자동 지급 실패\n대상: {member.mention}\n오류: `{e}`", "general")


# 봇권한추가/삭제/목록 명령어는 제거했습니다.
# 이제 별도 유저 등록 없이 서버 역할(대표~부팀장/관리자/운영진)로 권한을 판단합니다.


# 통합 하위명령어로 이동됨: @bot.tree.command(name="역할기본등록", description="구분선 역할(게임역할/멤버등급/프로필/특수역할/미인증)을 기본 역할로 자동 등록합니다.")
async def register_default_role(interaction: discord.Interaction):
    if await reject_if_not_setup_manager(interaction):
        return
    if await reject_if_not_bot_manager(interaction):
        return
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    guild = interaction.guild
    bot_member = guild.me or guild.get_member(bot.user.id)

    # 네가 원한 구분선 역할들을 기본 역할로 자동 등록
    auto_default_role_names = [
        "˚₊‧꒰ა 🎮 게임역할 ໒꒱ ‧₊˚",
        "˚₊‧꒰ა 🌸 멤버등급 ໒꒱ ‧₊˚",
        "˚₊‧꒰ა 💗 프로필 ໒꒱ ‧₊˚",
        "˚₊‧꒰ა ✨ 특수역할 ໒꒱ ‧₊˚",
        "미인증",
    ]

    registered = []
    missing = []
    skipped = []

    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")

    for role_name in auto_default_role_names:
        role = discord.utils.get(guild.roles, name=role_name)

        if role is None:
            missing.append(role_name)
            continue

        if role == guild.default_role or role.managed:
            skipped.append(role_name)
            continue

        if bot_member and role >= bot_member.top_role:
            skipped.append(f"{role_name}(봇 역할보다 높음)")
            continue

        c.execute(
            "INSERT OR REPLACE INTO default_roles(guild_id, role_id, added_by, added_at) VALUES (?, ?, ?, ?)",
            (guild.id, role.id, interaction.user.id, now)
        )
        registered.append(role)

    conn.commit()

    registered_text = "\n".join(f"• {role.mention}" for role in registered) if registered else "없음"
    missing_text = "\n".join(f"• `{name}`" for name in missing) if missing else "없음"
    skipped_text = "\n".join(f"• `{name}`" for name in skipped) if skipped else "없음"

    await safe_interaction_send(interaction, 
        "✅ 구분선 역할 기본 자동등록이 완료됐습니다.\n\n"
        f"**등록됨**\n{registered_text}\n\n"
        f"**없는 역할**\n{missing_text}\n\n"
        f"**건너뜀**\n{skipped_text}",
        ephemeral=True
    )

    await send_log(
        guild,
        f"🎭 구분선 역할 기본 자동등록\n관리자: {interaction.user.mention}\n등록 수: {len(registered)}개",
        "general"
    )


# 통합 하위명령어로 이동됨: @bot.tree.command(name="역할기본해제", description="등록된 기본 역할을 해제합니다.")
async def unregister_default_role(interaction: discord.Interaction, role: discord.Role):
    if await reject_if_not_setup_manager(interaction):
        return
    if await reject_if_not_bot_manager(interaction):
        return
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    c.execute("DELETE FROM default_roles WHERE guild_id=? AND role_id=?", (interaction.guild.id, role.id))
    conn.commit()
    await safe_interaction_send(interaction, f"✅ 기본 역할에서 {role.mention} 을 해제했습니다.", ephemeral=True)
    await send_log(interaction.guild, f"🎭 기본 역할 해제\n역할: {role.mention}\n관리자: {interaction.user.mention}", "general")


# 통합 하위명령어로 이동됨: @bot.tree.command(name="역할기본목록", description="현재 서버의 기본 역할 목록을 확인합니다.")
async def list_default_roles(interaction: discord.Interaction):
    if await reject_if_not_setup_manager(interaction):
        return
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    role_ids = get_default_role_ids(interaction.guild.id)
    roles = [interaction.guild.get_role(role_id) for role_id in role_ids]
    roles = [role for role in roles if role]

    if not roles:
        return await safe_interaction_send(interaction, "현재 등록된 기본 역할이 없습니다.", ephemeral=True)

    text = "\n".join(f"• {role.mention} (`{role.id}`)" for role in roles)
    await safe_interaction_send(interaction, f"✅ 기본 역할 목록\n{text}", ephemeral=True)



# 통합 하위명령어로 이동됨: @bot.tree.command(name="서버추가", description="현재 서버 채널을 봇 세팅 서버로 저장합니다. 직접 만든 채널도 자동으로 연결합니다.")
async def register_server(interaction: discord.Interaction):
    if await reject_if_not_setup_manager(interaction):
        return
    if await reject_if_not_bot_manager(interaction):
        return
    guild = interaction.guild
    if guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    detected = save_detected_guild_channels(guild)
    welcome_channel = detected.get("welcome_channel")
    goodbye_channel = detected.get("goodbye_channel")
    rule_channel = detected.get("rule_channel")
    intro_channel = detected.get("intro_channel")
    verify_channel = detected.get("verify_channel")
    notice_channel = detected.get("notice_channel")
    support_ticket_channel = detected.get("support_ticket_channel")
    boost_channel = detected.get("boost_channel")
    game_role_channel = detected.get("game_role_channel")
    log_channel = detected.get("log_channel")

    await safe_interaction_send(interaction, 
        f"✅ 서버 설정을 저장했습니다.\n"
        f"서버 ID: `{guild.id}`\n"
        f"환영/인사-퇴장 채널: {welcome_channel.mention if welcome_channel else '미설정'}\n"
        f"퇴장 채널: {goodbye_channel.mention if goodbye_channel else '미설정'}\n"
        f"필독/규칙 채널: {rule_channel.mention if rule_channel else '미설정'}\n"
        f"자기소개 채널: {intro_channel.mention if intro_channel else '미설정'}\n"
        f"인증 채널: {verify_channel.mention if verify_channel else '미설정'}\n"
        f"공지 채널: {notice_channel.mention if notice_channel else '미설정'}\n"
        f"티켓문의 채널: {support_ticket_channel.mention if support_ticket_channel else '미설정'}\n"
        f"서버부스트 알림 채널: {boost_channel.mention if boost_channel else '미설정'}\n"
        f"게임역할 채널: {game_role_channel.mention if game_role_channel else '미설정'}\n"
        f"로그 채널: {log_channel.mention if log_channel else '미설정'}",
        ephemeral=True
    )



