def normalize_auto_button_embed_key(embed_type: str):
    key = (embed_type or "").strip().lower()
    key = key.replace(" ", "_").replace("-", "_")
    aliases = {
        "인증": "verify",
        "인증패널": "verify",
        "verify_panel": "verify",
        "티켓": "panel_ticket",
        "티켓패널": "panel_ticket",
        "ticket_panel": "panel_ticket",
        "공식지원티켓문의": "panel_support_ticket",
        "support_ticket_panel": "panel_support_ticket",
        "뮤직": "panel_music",
        "음악": "panel_music",
            "서버부스트": "panel_boost",
        "부스트": "panel_boost",
        "boost": "panel_boost",
        "상점": "panel_shop",
        "게임역할": "panel_game_role",
        "보안": "panel_security",
        "경고": "panel_warning",
        "경제": "panel_economy",
        "관리도구": "panel_staff_tools",
        "관리자": "panel_admin",
        "이벤트": "panel_event",
        "이벤트종료": "panel_event_end",
        "칭호": "panel_title",
        "개발로그": "panel_devlog",
        "도움말": "panel_help",
        "help": "panel_help",
        "생일": "panel_birthday",
        "생일등록": "panel_birthday",
        "생일패널": "panel_birthday",
        "birthday": "panel_birthday",
        "birthday_panel": "panel_birthday",
    }
    key = aliases.get(key, key)
    if key in PANEL_CUSTOM_EMBED_TYPES:
        key = PANEL_CUSTOM_EMBED_TYPES[key]
    return key


def get_auto_button_display_name(embed_key: str):
    key = normalize_auto_button_embed_key(embed_key)
    return AUTO_BUTTON_DISPLAY_NAMES.get(key, key or "알 수 없음")


def is_auto_button_enabled(guild_id: int, embed_type: str):
    key = normalize_auto_button_embed_key(embed_type)
    if not key or key not in AUTO_BUTTON_VIEW_CLASS_BY_EMBED_KEY:
        return False
    try:
        c.execute(
            "SELECT enabled FROM auto_button_settings WHERE guild_id=? AND embed_key=?",
            (guild_id or 0, key)
        )
        row = c.fetchone()
        if row is None:
            return True
        return bool(row[0])
    except sqlite3.Error:
        return True


def set_auto_button_enabled(guild_id: int, embed_type: str, enabled: bool, updated_by: int = 0):
    key = normalize_auto_button_embed_key(embed_type)
    if not key or key not in AUTO_BUTTON_VIEW_CLASS_BY_EMBED_KEY:
        return False
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute(
        """
        INSERT INTO auto_button_settings(guild_id, embed_key, enabled, updated_by, updated_at)
        VALUES (?, ?, ?, ?, ?)
        ON CONFLICT(guild_id, embed_key) DO UPDATE SET
            enabled=excluded.enabled,
            updated_by=excluded.updated_by,
            updated_at=excluded.updated_at
        """,
        (guild_id or 0, key, 1 if enabled else 0, updated_by or 0, now)
    )
    conn.commit()
    return True


def make_auto_button_view(embed_type: str = "", guild_id: int = 0, *, ignore_setting: bool = False):
    key = normalize_auto_button_embed_key(embed_type)
    class_name = AUTO_BUTTON_VIEW_CLASS_BY_EMBED_KEY.get(key)
    if not class_name:
        return None
    if not ignore_setting and not is_auto_button_enabled(guild_id, key):
        return None
    view_class = globals().get(class_name)
    if view_class is None:
        return None
    try:
        return view_class()
    except Exception:
        return None


def detect_auto_button_embed_key(embed: discord.Embed, channel: discord.abc.Messageable = None):
    # 제목/내용 자동감지는 꺼둡니다.
    # 환영 메시지에 "인증" 또는 "티켓" 문구가 들어가도 버튼이 붙지 않게 하기 위해서입니다.
    return None


def get_auto_button_view_for_embed(embed_type: str = "", embed: discord.Embed = None, channel: discord.abc.Messageable = None):
    # embed_type이 명확할 때만 자동 버튼을 붙입니다.
    # embed_type이 없으면 환영/공지/규칙/대시보드 메시지로 판단하고 버튼을 붙이지 않습니다.
    guild_id = getattr(getattr(channel, "guild", None), "id", 0) or 0
    key = normalize_auto_button_embed_key(embed_type)
    if not key:
        return None
    return make_auto_button_view(key, guild_id)


async def send_embed_with_auto_buttons(channel: discord.TextChannel, *, embed: discord.Embed, embed_type: str = "", **kwargs):
    view = kwargs.pop("view", None) or get_auto_button_view_for_embed(embed_type, embed, channel)
    if view is not None:
        return await channel.send(embed=embed, view=view, **kwargs)
    return await channel.send(embed=embed, **kwargs)


