class UnifiedSupportEmbedSettingView(discord.ui.View):
    def __init__(self, target_channel_id: int = 0):
        super().__init__(timeout=300)
        self.target_channel_id = target_channel_id
        self.add_support_buttons()

    def add_support_buttons(self):
        row_counts = {row: 0 for row in range(5)}
        for support_key in SUPPORT_PANEL_CUSTOM_EMBED_DISPLAY_META.keys():
            target_row = None
            for row in range(5):
                if row_counts[row] < 5:
                    target_row = row
                    break
            if target_row is None:
                break
            self.add_item(UnifiedSupportPanelCustomEmbedButton(support_key, self.target_channel_id, row=target_row))
            row_counts[target_row] += 1

class UnifiedEmbedSettingView(discord.ui.View):
    def __init__(self, target_channel_id: int = 0):
        super().__init__(timeout=300)
        self.target_channel_id = target_channel_id
        self.add_panel_custom_embed_buttons()

    def add_panel_custom_embed_buttons(self):
        """/패널 메뉴에 있는 주요 임베드를 /임베드설정 화면에 버튼으로 추가합니다."""
        row_counts = {row: 0 for row in range(5)}
        for child in self.children:
            row = getattr(child, "row", None)
            if row is None:
                row = 0
            if row in row_counts:
                row_counts[row] += 1

        for panel_key in PANEL_CUSTOM_EMBED_DISPLAY_META.keys():
            target_row = None
            for row in range(5):
                if row_counts[row] < 5:
                    target_row = row
                    break
            if target_row is None:
                break
            self.add_item(UnifiedPanelCustomEmbedButton(panel_key, self.target_channel_id, row=target_row))
            row_counts[target_row] += 1

