# 생일 버튼형 등록 패널
# =========================

def birthday_public_bool_text(value: str) -> bool:
    value = (value or "").strip().lower()
    return value in {"true", "t", "yes", "y", "1", "예", "네", "공개", "ㅇ", "응"}


async def save_birthday_record_for_interaction(
    interaction: discord.Interaction,
    date_text: str,
    age_public: bool = False,
    note: str = "",
    *,
    action_label: str = "등록",
):
    if interaction.guild is None:
        return await interaction.followup.send("❌ 서버에서만 사용할 수 있어요.", ephemeral=True)

    parsed = parse_birthday_date(date_text or "")
    if not parsed:
        return await interaction.followup.send(
            "❌ 날짜 형식이 올바르지 않아요. `03-14` 또는 `2009-03-14` 처럼 입력해주세요.",
            ephemeral=True,
        )

    year, month, day = parsed
    now_text = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    try:
        c.execute(
            """
            INSERT INTO birthday_records(guild_id, user_id, month, day, birth_year, age_visible, note, updated_at)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?)
            ON CONFLICT(guild_id, user_id) DO UPDATE SET
                month=excluded.month,
                day=excluded.day,
                birth_year=excluded.birth_year,
                age_visible=excluded.age_visible,
                note=excluded.note,
                updated_at=excluded.updated_at
            """,
            (
                interaction.guild.id,
                interaction.user.id,
                month,
                day,
                year,
                1 if age_public else 0,
                (note or "")[:80],
                now_text,
            ),
        )
        conn.commit()
    except sqlite3.Error as e:
        return await interaction.followup.send(f"❌ 생일 저장 중 오류가 발생했어요: `{e}`", ephemeral=True)

    await sync_birthday_record_channel(interaction.guild)
    return await interaction.followup.send(
        f"✅ 생일이 **{action_label}**됐어요!\n"
        f"🎂 생일: **{month:02d}/{day:02d}**\n"
        f"🔒 나이 공개: **{'공개' if age_public else '비공개'}**\n"
        f"📝 메모: **{(note or '없음')[:80]}**",
        ephemeral=True,
    )


async def delete_birthday_record_for_interaction(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
    c.execute("DELETE FROM birthday_records WHERE guild_id=? AND user_id=?", (interaction.guild.id, interaction.user.id))
    changed = c.rowcount
    conn.commit()
    await sync_birthday_record_channel(interaction.guild)
    await safe_interaction_send(interaction, 
        "✅ 생일 기록을 삭제했어요." if changed else "ℹ️ 삭제할 생일 기록이 없어요.",
        ephemeral=True,
    )


async def show_my_birthday_record(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
    c.execute(
        "SELECT user_id, month, day, birth_year, age_visible, note FROM birthday_records WHERE guild_id=? AND user_id=?",
        (interaction.guild.id, interaction.user.id),
    )
    row = c.fetchone()
    if not row:
        return await safe_interaction_send(interaction, 
            "ℹ️ 아직 생일을 등록하지 않았어요. `생일 등록` 버튼을 눌러서 등록해보세요.",
            ephemeral=True,
        )
    await safe_interaction_send(interaction, "🎂 **내 생일 기록**\n" + format_birthday_record(interaction.guild, row), ephemeral=True)


async def show_birthday_list_for_interaction(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
    await sync_birthday_record_channel(interaction.guild)
    c.execute(
        "SELECT user_id, month, day, birth_year, age_visible, note FROM birthday_records WHERE guild_id=? ORDER BY month ASC, day ASC LIMIT 30",
        (interaction.guild.id,),
    )
    rows = c.fetchall()
    if not rows:
        return await safe_interaction_send(interaction, "ℹ️ 아직 등록된 생일이 없어요.", ephemeral=True)
    text = "\n".join(format_birthday_record(interaction.guild, row) for row in rows)
    await safe_interaction_send(interaction, "🎁 **생일 목록**\n" + text, ephemeral=True)


class BirthdayRegisterModal(discord.ui.Modal):
    def __init__(self, action_label: str = "등록"):
        super().__init__(title=f"🎂 생일 {action_label}")
        self.action_label = action_label
        self.date = discord.ui.TextInput(
            label="생일 날짜",
            placeholder="예: 03-14 또는 2009-03-14",
            required=True,
            max_length=10,
        )
        self.age_public = discord.ui.TextInput(
            label="나이 공개 여부",
            placeholder="예/아니오 중 입력하세요. 기본값: 아니오",
            required=False,
            max_length=10,
        )
        self.note = discord.ui.TextInput(
            label="메모",
            placeholder="예: 케이크 좋아함, 축하 DM 환영 등",
            required=False,
            max_length=80,
        )
        self.add_item(self.date)
        self.add_item(self.age_public)
        self.add_item(self.note)

    async def on_submit(self, interaction: discord.Interaction):
        await safe_interaction_defer(interaction, ephemeral=True)
        await save_birthday_record_for_interaction(
            interaction,
            str(self.date.value),
            birthday_public_bool_text(str(self.age_public.value)),
            str(self.note.value),
            action_label=self.action_label,
        )


class BirthdayPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="생일 등록", emoji="🎂", style=discord.ButtonStyle.green, custom_id="birthday_panel_register")
    async def register_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(BirthdayRegisterModal("등록"))

