    async def edit_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(BirthdayRegisterModal("수정"))

    @discord.ui.button(label="내 생일 확인", emoji="🔍", style=discord.ButtonStyle.gray, custom_id="birthday_panel_check")
    async def check_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await show_my_birthday_record(interaction)

