    embed = discord.Embed(
        title="🎁 다가오는 생일 목록",
        description="가까운 생일부터 최대 20명까지 보여줘요.",
        color=0x87CEEB,
    )
    embed.add_field(name="다가오는 생일", value="\n".join(format_birthday_record(interaction.guild, row) for row in rows)[:1024], inline=False)
    embed.set_footer(text="만능 봇 | 생일 목록")
