class BirthdayMonthSelect(discord.ui.Select):
    def __init__(self):
        options = [
            discord.SelectOption(label=f"{month}월 생일", value=str(month), emoji="🎂", description=f"{month}월 생일만 확인")
            for month in range(1, 13)
        ]
        super().__init__(placeholder="월별 생일 보기", min_values=1, max_values=1, options=options, custom_id="birthday_panel_month_select", row=2)

    async def callback(self, interaction: discord.Interaction):
        month = int(self.values[0])
        rows = fetch_birthday_rows(interaction.guild.id, month=month, limit=80)
        embed = discord.Embed(
            title=f"🎂 {month}월 생일",
            color=0x87CEEB,
        )
        if rows:
            embed.description = "\n".join(format_birthday_record(interaction.guild, row) for row in rows[:30])[:4000]
            if len(rows) > 30:
                embed.set_footer(text=f"외 {len(rows) - 30}명은 생일기록 채널에 저장되어 있어요.")
        else:
            embed.description = f"아직 {month}월에 등록된 생일이 없어요."
        await safe_ephemeral_send(interaction, embed=embed)


class BirthdayRegisterModal(discord.ui.Modal):
    def __init__(self, action_label: str = "등록"):
        super().__init__(title=f"🎂 생일 {action_label}")
        self.action_label = action_label
        self.date = discord.ui.TextInput(
            label="생일 날짜",
            placeholder="예: 03-14 / 0314 / 3월14일 / 2009-03-14",
            required=True,
            max_length=20,
        )
        self.age_public = discord.ui.TextInput(
            label="나이 공개 여부",
            placeholder="예/아니오 중 입력하세요. 기본값: 아니오",
            required=False,
            max_length=10,
        )
        self.note = discord.ui.TextInput(
            label="메모",
            placeholder="예: 케이크 좋아함, 축하 DM 환영 등",
            required=False,
            max_length=80,
        )
        self.add_item(self.date)
        self.add_item(self.age_public)
        self.add_item(self.note)

    async def on_submit(self, interaction: discord.Interaction):
        await safe_interaction_defer(interaction, ephemeral=True)
        await save_birthday_record_for_interaction(
            interaction,
            str(self.date.value),
            birthday_public_bool_text(str(self.age_public.value)),
            str(self.note.value),
            action_label=self.action_label,
        )


