async def send_birthday_register_panel_once(channel: discord.TextChannel):
    embed = build_birthday_register_panel_embed(channel.guild)
    view = BirthdayPanelView()
    try:
        async for msg in channel.history(limit=40):
            if msg.author == bot.user and msg.embeds:
                title = msg.embeds[0].title or ""
                if "생일" in title and ("등록 패널" in title or "등록 센터" in title):
                    await msg.edit(embed=embed, view=view)
                    return False
        await channel.send(embed=embed, view=view)
        return True
    except (discord.Forbidden, discord.HTTPException):
        return False


@tasks.loop(minutes=30)
async def birthday_daily_reminder():
    """매일 오전 9시(KST)에 오늘 생일을 한 번만 축하합니다."""
    now = datetime.datetime.now(KST_TIMEZONE)
    # 09:00~09:29 사이에만 작동해서 30분 루프가 하루 1회만 발송합니다.
    if now.hour != 9 or now.minute >= 30:
        return

    today_text = now.date().isoformat()
    for guild in list(bot.guilds):
        try:
            c.execute("SELECT 1 FROM birthday_notification_logs WHERE guild_id=? AND sent_date=?", (guild.id, today_text))
            if c.fetchone():
                continue

            c.execute(
                """
                SELECT user_id, month, day, birth_year, age_visible, note
                FROM birthday_records
                WHERE guild_id=? AND month=? AND day=?
                ORDER BY user_id ASC
                """,
                (guild.id, now.month, now.day),
            )
            rows = c.fetchall()
            if not rows:
                continue

            channel = get_channel_by_id_or_name(guild, 0, ["🎁-생일기록", "🎂-생일등록", "생일기록", "생일등록"], "text")
            if not channel:
                continue

            mentions = " ".join(f"<@{int(row[0])}>" for row in rows[:10])
            embed = discord.Embed(
                title="🎉 오늘 생일이에요!",
                description=(
                    f"오늘 생일인 멤버를 다 같이 축하해줘요!\n\n{mentions}\n\n"
                    + "\n".join(format_birthday_record(guild, row) for row in rows[:15])
                )[:4000],
                color=0x87CEEB,
            )
            if guild.icon:
                embed.set_thumbnail(url=guild.icon.url)
            embed.set_footer(text="만능 봇 | 매일 오전 9시 생일 알림")
            await channel.send(embed=embed)
            await sync_birthday_record_channel(guild)

            c.execute(
                "INSERT OR IGNORE INTO birthday_notification_logs(guild_id, sent_date, created_at) VALUES (?, ?, ?)",
                (guild.id, today_text, now.strftime("%Y-%m-%d %H:%M:%S")),
            )
            conn.commit()
        except Exception as e:
            print(f"⚠️ {getattr(guild, 'name', guild.id)} 생일 알림 실패: {e}")


