def build_security_log_embed(guild: discord.Guild):
    rows = list_security_logs(guild.id, SECURITY_LOG_PREVIEW_LIMIT)
    embed = create_embed(
        "📑 보안 로그",
        f"최근 보안 감지/차단 기록 {len(rows)}개를 표시합니다."
    )
    if not rows:
        embed.add_field(name="기록 없음", value="아직 저장된 보안 로그가 없습니다.", inline=False)
    else:
        for user_id, action, reason, channel_id, created_at in rows:
            target = f"<@{user_id}>" if user_id else "알 수 없음"
            channel_text = f"<#{channel_id}>" if channel_id else "채널 없음"
            embed.add_field(
                name=f"{action} · {created_at}",
                value=f"대상: {target}\n채널: {channel_text}\n사유: `{reason or '없음'}`",
                inline=False
            )
    embed.set_footer(text="/설정 보안로그 로도 확인할 수 있어요.")
    return embed


@setting_group.command(name="보안로그", description="최근 보안 감지/차단 기록을 확인합니다.")
async def setting_security_logs(interaction: discord.Interaction):
    if not await require_admin_interaction(interaction):
        return
    await safe_interaction_send(interaction, embed=build_security_log_embed(interaction.guild), ephemeral=True)


@setting_group.command(name="보안점검", description="봇 권한과 위험 역할을 빠르게 점검합니다.")
async def setting_security_check(interaction: discord.Interaction):
    if not await require_admin_interaction(interaction):
        return

    guild = interaction.guild
    bot_member = guild.me or guild.get_member(bot.user.id)
    missing = []
    if bot_member:
        needed = {
            "manage_messages": "메시지 관리",
            "manage_roles": "역할 관리",
            "ban_members": "멤버 차단",
            "kick_members": "멤버 추방",
            "moderate_members": "타임아웃",
            "view_audit_log": "감사 로그 보기",
        }
        for attr, label in needed.items():
            if not getattr(bot_member.guild_permissions, attr, False):
                missing.append(label)

    risky_roles = []
    for role in guild.roles:
        if role.is_default() or role.managed:
            continue
        risky = dangerous_permissions_from(role.permissions)
        if risky:
            risky_roles.append(f"{role.mention}: {', '.join(risky[:3])}")

    embed = create_embed(
        "🧪 보안점검 결과",
        "현재 서버의 보안 상태를 빠르게 확인했습니다."
    )
    embed.add_field(
        name="봇 권한",
        value="✅ 주요 권한이 충분합니다." if not missing else "⚠️ 부족 권한: " + ", ".join(missing),
        inline=False
    )
    embed.add_field(
        name="위험 권한 역할",
        value="없음" if not risky_roles else "\n".join(risky_roles[:12]) + (f"\n외 {len(risky_roles) - 12}개" if len(risky_roles) > 12 else ""),
        inline=False
    )
    embed.add_field(
        name="추천",
        value="`/보안패널`에서 자동검열, 도배보호, 멘션테러, 위험파일, 토큰보호, 권한보호를 켜두는 것을 추천합니다.",
        inline=False
    )
    await safe_interaction_send(interaction, embed=embed, ephemeral=True)


class CensorEnablePanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=300)

    async def _enable_censor_category(self, interaction: discord.Interaction, category_key: str):
        if not await require_admin_interaction(interaction):
            return
        info = CENSOR_CATEGORY_LABELS.get(category_key, {"label": category_key})
        set_security_setting(interaction.guild.id, "auto_filter", True)
        set_security_setting(interaction.guild.id, "security_log_enabled", True)
        set_censor_category_setting(interaction.guild.id, category_key, True)
        await safe_interaction_edit(interaction, embed=build_censor_panel_embed(interaction.guild), view=CensorEnablePanelView())
        await send_log(
            interaction.guild,
            f"🧹 검열켜기 패널\n카테고리: `{info.get('label', category_key)}`\n상태: 켜짐 ✅\n관리자: {interaction.user.mention}",
            "general"
        )

    async def _enable_spam_category(self, interaction: discord.Interaction, category_key: str):
        if not await require_admin_interaction(interaction):
            return
        info = CENSOR_CATEGORY_LABELS.get(category_key, {"label": category_key})
        set_security_setting(interaction.guild.id, "spam_protection", True)
        set_security_setting(interaction.guild.id, "security_log_enabled", True)
        set_censor_category_setting(interaction.guild.id, category_key, True)
        await safe_interaction_edit(interaction, embed=build_censor_panel_embed(interaction.guild), view=CensorEnablePanelView())
        await send_log(
            interaction.guild,
            f"⚠️ 스팸검열 패널\n카테고리: `{info.get('label', category_key)}`\n상태: 켜짐 ✅\n관리자: {interaction.user.mention}",
            "general"
        )

    async def _enable_security_feature(self, interaction: discord.Interaction, setting_key: str, label: str):
        if not await require_admin_interaction(interaction):
            return
        set_security_setting(interaction.guild.id, setting_key, True)
        set_security_setting(interaction.guild.id, "security_log_enabled", True)
        await safe_interaction_edit(interaction, embed=build_censor_panel_embed(interaction.guild), view=CensorEnablePanelView())
        await send_log(
            interaction.guild,
            f"🧹 검열켜기 패널\n카테고리: `{label}`\n상태: 켜짐 ✅\n관리자: {interaction.user.mention}",
            "general"
        )

    async def _set_all(self, interaction: discord.Interaction, enabled: bool):
        if not await require_admin_interaction(interaction):
            return
        for setting_key in [
            "auto_filter",
            "spam_protection",
            "mention_spam_detection",
            "dangerous_file_block",
            "token_leak_guard",
            "new_account_guard",
            "raid_detection",
            "permission_guard",
        ]:
            set_security_setting(interaction.guild.id, setting_key, enabled)
        set_security_setting(interaction.guild.id, "security_log_enabled", True)
        set_all_censor_category_settings(interaction.guild.id, enabled)
        await safe_interaction_edit(interaction, embed=build_censor_panel_embed(interaction.guild), view=CensorEnablePanelView())
        await send_log(
            interaction.guild,
            f"🧹 검열패널 전체 {'켜기' if enabled else '끄기'}\n관리자: {interaction.user.mention}",
            "general"
        )

