# 통합 하위명령어로 이동됨: @bot.tree.command(name="생일", description="생일을 등록/수정/삭제/확인합니다.")
@app_commands.describe(
    작업="등록, 수정, 삭제, 확인, 목록 중 선택하세요.",
    날짜="MM-DD 또는 YYYY-MM-DD 형식입니다. 예: 03-14 / 2009-03-14",
    나이공개="True면 생일기록에 나이를 표시합니다. 생년이 없으면 월/일만 표시됩니다.",
    메모="선택 메모입니다. 예: 케이크 좋아함"
)
@app_commands.choices(작업=[
    app_commands.Choice(name="등록", value="register"),
    app_commands.Choice(name="수정", value="edit"),
    app_commands.Choice(name="삭제", value="delete"),
    app_commands.Choice(name="확인", value="check"),
    app_commands.Choice(name="목록", value="list"),
])
async def birthday_command(
    interaction: discord.Interaction,
    작업: app_commands.Choice[str],
    날짜: str = None,
    나이공개: bool = False,
    메모: str = None,
):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    guild = interaction.guild
    await safe_interaction_defer(interaction, ephemeral=True)
    await create_birthday_channels(guild)

    action = 작업.value
    if action in {"register", "edit"}:
        parsed = parse_birthday_date(날짜 or "")
        if not parsed:
            return await interaction.followup.send("❌ 날짜 형식이 올바르지 않습니다. `03-14` 또는 `2009-03-14` 처럼 입력해주세요.", ephemeral=True)
        year, month, day = parsed
        now_text = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        try:
            c.execute(
                """
                INSERT INTO birthday_records(guild_id, user_id, month, day, birth_year, age_visible, note, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    month=excluded.month,
                    day=excluded.day,
                    birth_year=excluded.birth_year,
                    age_visible=excluded.age_visible,
                    note=excluded.note,
                    updated_at=excluded.updated_at
                """,
                (guild.id, interaction.user.id, month, day, year, 1 if 나이공개 else 0, (메모 or "")[:80], now_text)
            )
            conn.commit()
        except sqlite3.Error as e:
            return await interaction.followup.send(f"❌ 생일 저장 중 오류가 발생했습니다: `{e}`", ephemeral=True)
        await sync_birthday_record_channel(guild)
        return await interaction.followup.send(
            f"✅ 생일이 {'수정' if action == 'edit' else '등록'}됐어요.\n"
            f"생일: **{month:02d}/{day:02d}**\n"
            f"나이 공개: **{'공개' if 나이공개 else '비공개'}**",
            ephemeral=True
        )

    if action == "delete":
        c.execute("DELETE FROM birthday_records WHERE guild_id=? AND user_id=?", (guild.id, interaction.user.id))
        changed = c.rowcount
        conn.commit()
        await sync_birthday_record_channel(guild)
        return await interaction.followup.send("✅ 생일 기록을 삭제했어요." if changed else "ℹ️ 삭제할 생일 기록이 없어요.", ephemeral=True)

    if action == "check":
        c.execute("SELECT user_id, month, day, birth_year, age_visible, note FROM birthday_records WHERE guild_id=? AND user_id=?", (guild.id, interaction.user.id))
        row = c.fetchone()
        if not row:
            return await interaction.followup.send("ℹ️ 아직 생일을 등록하지 않았어요. `/생일 등록` 또는 생일 등록 버튼으로 등록해보세요.", ephemeral=True)
        return await interaction.followup.send("🎂 내 생일 기록\n" + format_birthday_record(guild, row), ephemeral=True)

    c.execute("SELECT user_id, month, day, birth_year, age_visible, note FROM birthday_records WHERE guild_id=? ORDER BY month ASC, day ASC LIMIT 30", (guild.id,))
    rows = c.fetchall()
    if not rows:
        return await interaction.followup.send("ℹ️ 아직 등록된 생일이 없어요.", ephemeral=True)
    text = "\n".join(format_birthday_record(guild, row) for row in rows)
    await sync_birthday_record_channel(guild)
    return await interaction.followup.send("🎁 생일 목록\n" + text, ephemeral=True)


def get_or_create_user(guild_id: int, user_id: int = None):
    """서버별 포인트/출석 유저 데이터를 가져오거나 생성합니다."""
    if user_id is None:
        user_id = guild_id
        guild_id = 0
    c.execute(
        "SELECT point, attendance_count, streak, last_attendance FROM users WHERE guild_id=? AND user_id=?",
        (guild_id, user_id)
    )
    user = c.fetchone()
    if user is None:
        c.execute("INSERT OR IGNORE INTO users(guild_id, user_id) VALUES (?, ?)", (guild_id, user_id))
        conn.commit()
        return 0, 0, 0, None
    return user


def get_user_point(guild_id: int, user_id: int = None):
    if user_id is None:
        user_id = guild_id
        guild_id = 0
    point, _, _, _ = get_or_create_user(guild_id, user_id)
    return point


def set_user_point(guild_id: int, user_id: int = None, point: int = None):
    if point is None:
        point = user_id
        user_id = guild_id
        guild_id = 0
    get_or_create_user(guild_id, user_id)
    c.execute(
        "UPDATE users SET point=? WHERE guild_id=? AND user_id=?",
        (max(point, 0), guild_id, user_id)
    )
    conn.commit()

def get_or_create_level_user(user_id: int):
    c.execute("SELECT exp, level FROM levels WHERE user_id=?", (user_id,))
    data = c.fetchone()
    if data is None:
        c.execute("INSERT INTO levels(user_id, exp, level) VALUES (?, ?, ?)", (user_id, 0, 1))
        conn.commit()
        return 0, 1
    return data


def get_or_create_voice_level_user(user_id: int):
    c.execute("SELECT exp, level, total_seconds FROM voice_levels WHERE user_id=?", (user_id,))
    data = c.fetchone()
    if data is None:
        c.execute("INSERT INTO voice_levels(user_id, exp, level, total_seconds) VALUES (?, ?, ?, ?)", (user_id, 0, 1, 0))
        conn.commit()
        return 0, 1, 0
    return data


async def add_voice_level_exp(member: discord.Member, seconds: int):
    """음성방에 머문 시간만큼 음성 EXP를 지급하고 레벨업은 레벨로그에 기록합니다."""
    if member.bot or member.guild is None:
        return

    seconds = max(0, int(seconds or 0))
    minutes = seconds // 60
    if minutes <= 0:
        return

    exp_gain = minutes * VOICE_EXP_PER_MINUTE
    if has_exp_booster(member.id):
        exp_gain *= 2
    exp, level, total_seconds = get_or_create_voice_level_user(member.id)
    total_seconds += seconds
    exp += exp_gain

    leveled = False
    old_level = level
    while exp >= level * 100:
        exp -= level * 100
        level += 1
        leveled = True

    c.execute(
        "UPDATE voice_levels SET exp=?, level=?, total_seconds=? WHERE user_id=?",
        (exp, level, total_seconds, member.id)
    )
    conn.commit()

    if leveled:
        await send_log(
            member.guild,
            f"🎉 음성 레벨업!\n유저: {member.mention}\n음성 레벨: Lv.{old_level} → Lv.{level}\n획득 EXP: +{exp_gain}",
            "level"
        )


async def update_warning_role(member: discord.Member):
    warning_roles = ["경고 1회", "경고 2회", "경고 3회", "경고 4회", "경고 5회"]

    for role_name in warning_roles:
        role = discord.utils.get(member.guild.roles, name=role_name)
        if role and role in member.roles:
            await member.remove_roles(role)

    c.execute("SELECT COUNT(*) FROM warnings WHERE user_id=?", (member.id,))
    count = c.fetchone()[0]

    if count <= 0:
        return count

    role = discord.utils.get(member.guild.roles, name=f"경고 {min(count, 5)}회")
    if role:
        await member.add_roles(role)

    return count



# =========================
# 서버 스텟 시스템
# =========================

SERVER_STATS_CATEGORY_NAME = "📊 서버 스텟"


def get_voice_member_count(guild: discord.Guild) -> int:
    return len([
        member for member in guild.members
        if member.voice and member.voice.channel
    ])


async def update_server_stats_for_guild(guild: discord.Guild) -> bool:
    """서버 스텟 카테고리가 있으면 채널 이름을 최신 상태로 갱신합니다."""
    if guild is None:
        return False

    category = discord.utils.get(guild.categories, name=SERVER_STATS_CATEGORY_NAME)
    if category is None:
        return False

    channels = category.voice_channels
    if len(channels) < 4:
        return False

    total_members = guild.member_count
    bot_count = len([member for member in guild.members if member.bot])
    user_count = total_members - bot_count
    voice_count = get_voice_member_count(guild)

    names = [
        f"👥 전체 멤버 : {total_members}",
        f"👤 유저 : {user_count}",
        f"🤖 봇 : {bot_count}",
        f"🔊 음성 접속 : {voice_count}",
    ]

    for channel, name in zip(channels[:4], names):
        if channel.name != name:
            await channel.edit(name=name)

    return True


async def ensure_server_stats_channels(guild: discord.Guild):
    """📊 서버 스텟 카테고리와 기본 스텟 채널 4개를 생성/확인합니다."""
    if guild is None:
        return None, 0

    category = discord.utils.get(guild.categories, name=SERVER_STATS_CATEGORY_NAME)
    if category is None:
        category = await guild.create_category(SERVER_STATS_CATEGORY_NAME)

    base_names = [
        "👥 전체 멤버 : 0",
        "👤 유저 : 0",
        "🤖 봇 : 0",
        "🔊 음성 접속 : 0",
    ]

    created_count = 0
    while len(category.voice_channels) < 4:
        name = base_names[len(category.voice_channels)]
        await guild.create_voice_channel(name, category=category)
        created_count += 1

    await update_server_stats_for_guild(guild)
    return category, created_count


@tasks.loop(minutes=30)
async def update_server_stats():
    """30분마다 모든 서버의 서버 스텟을 자동 갱신합니다. 채널 이름 변경 제한을 피하기 위해 너무 자주 갱신하지 않습니다."""
    for guild in bot.guilds:
        try:
            await update_server_stats_for_guild(guild)
        except Exception as e:
            print(f"❌ 서버 스텟 자동 업데이트 실패 ({guild.name}): {e}")


@tasks.loop(minutes=10)
async def attendance_vip_expire_checker():
    """출석 30일 보상으로 지급된 VIP 1일 역할을 만료 시간이 지나면 자동 회수합니다."""
    now = datetime.datetime.now()
    c.execute(
        "SELECT user_id, effect_name, expires_at FROM user_effects WHERE effect_name LIKE ?",
        ("출석VIP1일:%",)
    )
    rows = c.fetchall()

    for user_id, effect_name, expires_at in rows:
        if not expires_at:
            continue
        try:
            expire_dt = datetime.datetime.fromisoformat(expires_at)
        except ValueError:
            continue
        if now < expire_dt:
            continue

        try:
            guild_id = int(str(effect_name).split(":", 1)[1])
        except (IndexError, ValueError):
            guild_id = 0

        guild = bot.get_guild(guild_id) if guild_id else None
        if guild:
            member = guild.get_member(int(user_id))
            role = discord.utils.get(guild.roles, name="VIP")
            if member and role and role in member.roles:
                try:
                    await member.remove_roles(role, reason="출석 30일 VIP 1일 만료")
                    await send_log(guild, f"⌛ 출석 VIP 1일 만료\n대상: {member.mention}\n역할: {role.mention}", "general")
                except (discord.Forbidden, discord.HTTPException):
                    pass

        c.execute("DELETE FROM user_effects WHERE user_id=? AND effect_name=?", (user_id, effect_name))
        conn.commit()


# 통합 하위명령어로 이동됨: @bot.tree.command(name="서버스텟생성", description="서버 스텟 카테고리와 채널을 생성합니다.")
async def create_server_stats(interaction: discord.Interaction):
    if await reject_if_not_setup_manager(interaction):
        return
    if not interaction.user.guild_permissions.administrator:
        return await safe_interaction_send(interaction, 
            "❌ 관리자만 사용할 수 있습니다.",
            ephemeral=True
        )

    guild = interaction.guild
    if guild is None:
        return await safe_interaction_send(interaction, 
            "❌ 서버에서만 사용할 수 있습니다.",
            ephemeral=True
        )

    await safe_interaction_defer(interaction, ephemeral=True)

    category, created_count = await ensure_server_stats_channels(guild)

    await interaction.followup.send(
        "✅ 서버 스텟 카테고리와 채널을 생성/확인했습니다.\n"
        f"새로 생성된 스텟 채널: **{created_count}개**",
        ephemeral=True
    )
    await send_log(guild, f"📊 서버 스텟 생성\n관리자: {interaction.user.mention}", "general")


