c.execute("""
CREATE TABLE IF NOT EXISTS enhance_reset_state (
    guild_id INTEGER PRIMARY KEY,
    period_key INTEGER DEFAULT 0,
    reset_at TEXT
)
""")
conn.commit()


def get_enhance_period_key():
    today = datetime.date.today()
    days = (today - ENHANCE_RESET_ANCHOR).days
    return max(0, days // ENHANCE_RESET_DAYS)


def ensure_enhance_biweekly_reset(guild_id: int):
    """강화 기록을 2주 단위로 자동 초기화합니다. 첫 실행 시에는 현재 주기만 저장합니다."""
    if not guild_id:
        return False
    current_period = get_enhance_period_key()
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute("SELECT period_key FROM enhance_reset_state WHERE guild_id=?", (guild_id,))
    row = c.fetchone()
    if row is None:
        c.execute(
            "INSERT OR IGNORE INTO enhance_reset_state(guild_id, period_key, reset_at) VALUES (?, ?, ?)",
            (guild_id, current_period, now)
        )
        conn.commit()
        return False
    saved_period = int(row[0] or 0)
    if saved_period == current_period:
        return False
    c.execute("DELETE FROM enhance_items WHERE guild_id=?", (guild_id,))
    c.execute(
        "UPDATE enhance_reset_state SET period_key=?, reset_at=? WHERE guild_id=?",
        (current_period, now, guild_id)
    )
    conn.commit()
    return True


def get_next_enhance_reset_text():
    current_period = get_enhance_period_key()
    next_date = ENHANCE_RESET_ANCHOR + datetime.timedelta(days=(current_period + 1) * ENHANCE_RESET_DAYS)
    return next_date.strftime("%Y-%m-%d")


def get_enhance_milestone_title(level: int):
    return ENHANCE_MILESTONE_TITLES.get(int(level or 0), "")


