# @bot.tree.command(name="퇴장", description="봇을 음성 채널에서 내보냅니다.")
async def tts_leave_command(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    try:
        voice_client = None
        bot_label = "메인 봇"
        if TTS_BOT_TOKEN and tts_sub_bot.is_ready():
            sub_guild = tts_sub_bot.get_guild(interaction.guild.id)
            if sub_guild:
                voice_client = discord.utils.get(tts_sub_bot.voice_clients, guild=sub_guild)
                bot_label = "TTS 서브봇"
        if voice_client is None:
            voice_client = interaction.guild.voice_client
            bot_label = "메인 봇"
        if voice_client is None:
            return await safe_interaction_send(interaction, "❌ 봇이 음성 채널에 들어가 있지 않습니다.", ephemeral=True)

        channel_name = voice_client.channel.name if voice_client.channel else "알 수 없음"
        await voice_client.disconnect(force=True)
        await safe_interaction_send(interaction, f"✅ {bot_label}이 음성 채널에서 퇴장했습니다.", ephemeral=True)
        await send_log(interaction.guild, f"👋 TTS 퇴장\n봇: {bot_label}\n유저: {interaction.user.mention}\n채널: `{channel_name}`", "voice")
    except Exception as e:
        await safe_interaction_send(interaction, f"❌ 퇴장 실패: `{e}`", ephemeral=True)


