    if not interaction.user.guild_permissions.moderate_members:
        return await safe_interaction_send(interaction, "❌ 권한이 없습니다.", ephemeral=True)
    embed = discord.Embed(title="⚠️ 경고 관리 패널", description="아래 버튼으로 경고를 관리하세요.", color=discord.Color.orange())
    await safe_interaction_send(interaction, embed=embed, view=WarnManagePanel(), ephemeral=True)


