class PrefixAttendanceResponseProxy:
    """!출첵 같은 메시지 명령어도 기존 출석 로직을 그대로 재사용하게 해주는 작은 어댑터입니다."""

    def __init__(self, ctx: commands.Context):
        self.ctx = ctx
        self._done = False

    def is_done(self):
        return self._done

    async def send_message(self, *args, **kwargs):
        kwargs.pop("ephemeral", None)
        kwargs.pop("thinking", None)
        self._done = True
        return await self.ctx.reply(*args, mention_author=False, **kwargs)


class PrefixAttendanceFollowupProxy:
    def __init__(self, ctx: commands.Context):
        self.ctx = ctx

    async def send(self, *args, **kwargs):
        kwargs.pop("ephemeral", None)
        kwargs.pop("thinking", None)
        return await self.ctx.reply(*args, mention_author=False, **kwargs)


class PrefixAttendanceInteractionProxy:
    """discord.Interaction 전용 출석 함수를 commands.Context에서도 쓸 수 있게 맞춰줍니다."""

    def __init__(self, ctx: commands.Context):
        self.guild = ctx.guild
        self.user = ctx.author
        self.channel = ctx.channel
        self.response = PrefixAttendanceResponseProxy(ctx)
        self.followup = PrefixAttendanceFollowupProxy(ctx)


@bot.command(name="출첵", aliases=["출석"])
async def prefix_attendance_check(ctx: commands.Context):
    if ctx.guild is None or not isinstance(ctx.author, discord.Member):
        return await ctx.reply("❌ 서버에서만 사용할 수 있습니다.", mention_author=False)
    await attendance(PrefixAttendanceInteractionProxy(ctx))


