async def send_ranking(interaction, query, title, formatter, color=discord.Color.gold()):
    c.execute(query)
    rows = c.fetchall()
    if not rows:
        return await safe_interaction_send(interaction, "아직 데이터가 없습니다.")
    text = "".join(formatter(i, row) for i, row in enumerate(rows, start=1))
    embed = discord.Embed(title=title, description=text, color=color)
    await safe_interaction_send(interaction, embed=embed)


