def resolve_ytdlp_cookie_file():
    """Render Secret File 또는 로컬 cookies.txt 경로를 자동으로 찾습니다."""
    candidates = []

    env_path = os.getenv("YTDLP_COOKIE_FILE", "").strip()
    if env_path:
        candidates.append(env_path)

    # Render Secret Files 기본 경로
    candidates.append("/etc/secrets/cookies.txt")

    # 로컬 실행용: bot.py와 같은 폴더의 cookies.txt
    try:
        candidates.append(str((os.path.dirname(os.path.abspath(__file__)) and os.path.join(os.path.dirname(os.path.abspath(__file__)), "cookies.txt"))))
    except Exception:
        pass

    # Windows 다운로드 폴더에 저장해둔 경우도 자동 탐색
    try:
        home = os.path.expanduser("~")
        if home:
            candidates.append(os.path.join(home, "Downloads", "cookies.txt"))
    except Exception:
        pass

    for path in candidates:
        if path and os.path.exists(path):
            return path
    return env_path


YTDLP_COOKIE_FILE = resolve_ytdlp_cookie_file()

# YouTube 영상마다 제공 포맷이 달라서 특정 포맷만 고르면
# "Requested format is not available" 오류가 날 수 있습니다.
# 아래처럼 오디오 후보를 넓게 두고, 실패하면 여러 클라이언트/포맷으로 재시도합니다.
YTDLP_SAFE_AUDIO_FORMAT = "bestaudio[acodec!=none]/best[acodec!=none]/best"
# YouTube는 클라이언트별로 내려주는 포맷이 다를 수 있어서 web/mweb/ios/android를 순서대로 재시도합니다.
# android를 첫 번째로 두면 일부 환경에서 포맷이 비어 들어오는 경우가 있어 web 계열을 먼저 사용합니다.
YTDLP_FALLBACK_PROFILES = [
    (YTDLP_SAFE_AUDIO_FORMAT, ["web", "mweb", "ios"]),
    ("bestaudio/best", ["web", "mweb", "ios"]),
    ("ba/b", ["ios", "web", "mweb"]),
    ("best[acodec!=none]/bestaudio/best", ["mweb", "web", "ios"]),
    ("best", ["ios", "web", "android"]),
]
YTDLP_YOUTUBE_CLIENT_PROFILES = [
    ["web", "mweb", "ios"],
    ["mweb", "web"],
    ["ios"],
    ["web"],
    ["android"],
]


def check_ytdlp_cookie_file(path: str):
    """cookies.txt가 yt-dlp가 읽을 수 있는 Netscape 형식인지 간단히 확인합니다."""
    if not path or not os.path.exists(path):
        return False, "쿠키 파일 없음"
    try:
        text = open(path, "r", encoding="utf-8", errors="ignore").read(200000)
    except Exception as e:
        return False, f"쿠키 파일 읽기 실패: {e}"

    has_header = ("Netscape HTTP Cookie File" in text) or ("HTTP Cookie File" in text)
    has_youtube = ("youtube.com" in text) or (".youtube.com" in text)
    has_login_cookie = any(name in text for name in ["LOGIN_INFO", "SAPISID", "APISID", "__Secure-1PSID", "__Secure-3PSID"])
    if not has_header:
        return False, "Netscape 형식 아님"
    if not has_youtube:
        return False, "youtube.com 쿠키 없음"
    if not has_login_cookie:
        return False, "로그인 쿠키 부족"
    return True, "정상으로 보임"


def build_ytdl_options(format_value: str = None, player_clients=None):
    """YouTube가 특정 포맷을 막아도 여러 포맷/클라이언트로 재시도할 수 있게 yt-dlp 옵션을 만듭니다."""
    clients = player_clients or ["web", "mweb", "ios"]
    options = {
        # 특정 m4a/webm/format id에 고정하지 않고, 오디오가 있는 후보를 넓게 허용합니다.
        "format": format_value or YTDLP_SAFE_AUDIO_FORMAT,
        "format_sort": ["hasaud", "abr", "tbr", "filesize"],
        "noplaylist": True,
        "quiet": True,
        "no_warnings": True,
        "default_search": "ytsearch1",
        "source_address": "0.0.0.0",
        "force_ipv4": True,
        "skip_download": True,
        "cachedir": False,
        "extract_flat": False,
        "geo_bypass": True,
        "nocheckcertificate": True,
        # 포맷 선택이 실패해도 가능한 정보/formats를 최대한 받아서 아래 코드에서 직접 고릅니다.
        "ignore_no_formats_error": False,
        "retries": 8,
        "fragment_retries": 8,
        "extractor_retries": 3,
        "socket_timeout": 20,
        "http_headers": {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0 Safari/537.36",
            "Accept-Language": "ko-KR,ko;q=0.9,en-US;q=0.8,en;q=0.7",
        },
        "extractor_args": {
            "youtube": {
                # web 하나만 쓰면 일부 영상에서 포맷/봇감지 오류가 나서 여러 클라이언트를 순서대로 시도합니다.
                "player_client": clients,
            }
        },
    }
    if YTDLP_COOKIE_FILE:
        options["cookiefile"] = YTDLP_COOKIE_FILE
    return options


_cookie_ok, _cookie_msg = check_ytdlp_cookie_file(YTDLP_COOKIE_FILE)
if YTDLP_COOKIE_FILE:
    print(f"✅ yt-dlp cookies.txt 사용: {YTDLP_COOKIE_FILE} / 검사: {_cookie_msg}")
else:
    print("⚠️ yt-dlp cookies.txt를 찾지 못했습니다. YouTube 링크가 막힐 수 있습니다.")

YTDL_OPTIONS = build_ytdl_options()

FFMPEG_OPTIONS = {
    # -nostdin: Windows/Render에서 FFmpeg가 표준입력을 잡고 멈추는 문제 방지
    # -reconnect_on_network_error: 스트림 URL이 잠깐 끊길 때 자동 재연결
    "before_options": "-nostdin -reconnect 1 -reconnect_streamed 1 -reconnect_at_eof 1 -reconnect_on_network_error 1 -reconnect_delay_max 5",
    # -loglevel warning: 오류는 보이되 불필요한 로그는 줄임
    "options": "-vn -loglevel warning",
}


def get_ffmpeg_executable():
    """로컬/Render 어디서든 FFmpeg 실행 파일을 안정적으로 찾습니다."""
    env_path = os.getenv("FFMPEG_PATH", "").strip()
    if env_path:
        return env_path

    found = shutil.which("ffmpeg")
    if found:
        return found

    try:
        base_dir = os.path.dirname(os.path.abspath(__file__))
        for name in ("ffmpeg.exe", "ffmpeg"):
            candidate = os.path.join(base_dir, name)
            if os.path.exists(candidate):
                return candidate
    except Exception:
        pass

    # PATH에 있을 수도 있으므로 마지막으로 이름만 넘깁니다.
    return "ffmpeg"


def _safe_ffmpeg_header_value(value):
    return str(value or "").replace("\r", " ").replace("\n", " ").replace('"', "'").strip()


def build_ffmpeg_before_options(track: dict):
    before_options = FFMPEG_OPTIONS["before_options"]
    headers = dict(track.get("http_headers") or {})

    # yt-dlp가 헤더를 안 준 경우에도 기본 헤더를 넣어 YouTube/SoundCloud 403을 줄입니다.
    headers.setdefault(
        "User-Agent",
        "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/125.0 Safari/537.36",
    )
    webpage_url = str(track.get("webpage_url") or "")
    if "youtube.com" in webpage_url or "youtu.be" in webpage_url:
        headers.setdefault("Referer", "https://www.youtube.com/")
    elif "soundcloud.com" in webpage_url:
        headers.setdefault("Referer", "https://soundcloud.com/")

    if headers:
        header_text = "".join(
            f"{_safe_ffmpeg_header_value(k)}: {_safe_ffmpeg_header_value(v)}\r\n"
            for k, v in headers.items()
            if k and v
        )
        if header_text:
            before_options += f' -headers "{header_text}"'
    return before_options


def build_discord_audio_source(track: dict, volume: float):
    """yt-dlp에서 받은 스트림 URL을 Discord에서 실제로 들리게 FFmpeg 소스로 변환합니다."""
    stream_url = track.get("url")
    if not stream_url:
        raise ValueError("재생 URL이 비어있어요.")

    ffmpeg_executable = get_ffmpeg_executable()
    source = discord.FFmpegPCMAudio(
        stream_url,
        executable=ffmpeg_executable,
        before_options=build_ffmpeg_before_options(track),
        options=FFMPEG_OPTIONS["options"],
    )
    return discord.PCMVolumeTransformer(source, volume=volume)

ytdl = yt_dlp.YoutubeDL(YTDL_OPTIONS)


def get_music_queue(guild_id: int):
    if guild_id not in music_queues:
        music_queues[guild_id] = deque()
    return music_queues[guild_id]


def get_music_volume(guild_id: int):
    return volume_levels.get(guild_id, 0.5)


def get_skip_vote_required(voice_channel: discord.VoiceChannel):
    """현재 봇이 들어간 음성방의 실제 사람 수만큼 스킵 필요 표를 계산합니다."""
    if voice_channel is None:
        return 1
    humans = [member for member in voice_channel.members if not member.bot]
    return max(1, len(humans))


def clean_skip_votes(guild_id: int, voice_channel: discord.VoiceChannel):
    """음성방을 나간 사람의 스킵 투표는 자동으로 제거합니다."""
    votes = skip_vote_users.setdefault(guild_id, set())
    valid_user_ids = {member.id for member in voice_channel.members if not member.bot}
    votes.intersection_update(valid_user_ids)
    return votes


def format_duration(seconds):
    if not seconds:
        return "알 수 없음"
    minutes, sec = divmod(int(seconds), 60)
    hours, minutes = divmod(minutes, 60)
    if hours:
        return f"{hours}:{minutes:02d}:{sec:02d}"
    return f"{minutes}:{sec:02d}"


MUSIC_SERVICE_KEYWORDS = {
    "soundcloud": ["soundcloud.com"],
    "melon": ["melon.com", "멜론", "melon"],
    "genie": ["genie.co.kr", "지니뮤직", "지니", "genie"],
    "youtube": ["youtube.com", "youtu.be", "유튜브", "youtube"],
}


def detect_music_service(query: str, info: dict | None = None):
    text = (query or "").lower()
    extractor = ((info or {}).get("extractor_key") or (info or {}).get("extractor") or "").lower()
    if "soundcloud" in extractor or any(word in text for word in MUSIC_SERVICE_KEYWORDS["soundcloud"]):
        return "SoundCloud", "🟧"
    if any(word in text for word in MUSIC_SERVICE_KEYWORDS["melon"]):
        return "Melon", "🍈"
    if any(word in text for word in MUSIC_SERVICE_KEYWORDS["genie"]):
        return "Genie Music", "🧞"
    if "youtube" in extractor or any(word in text for word in MUSIC_SERVICE_KEYWORDS["youtube"]):
        return "YouTube", "▶️"
    return "검색", "🎧"


def clean_music_title(title: str):
    title = html.unescape(title or "").strip()
    for suffix in ["- Melon", "| Melon", "- genie", "| 지니", "- YouTube"]:
        title = title.replace(suffix, "")
    return re.sub(r"\s+", " ", title).strip() or "제목 없음"


def normalize_youtube_title_keyword(title: str):
    """YouTube 영상 제목을 그대로 붙여넣어도 검색이 잘 되게 정리합니다."""
    keyword = clean_music_title(title)
    keyword = re.sub(r"https?://\S+", "", keyword).strip()
    keyword = re.sub(r"\b(youtube|유튜브)\b", "", keyword, flags=re.I).strip()
    # [Playlist], [Cover], (Official Video) 같은 앞/뒤 태그는 검색 방해가 될 수 있어 제거합니다.
    keyword = re.sub(r"^\s*[\[【(（][^\]】)）]{1,40}[\]】)）]\s*", "", keyword).strip()
    keyword = re.sub(r"\s*[\[【(（](official|mv|m/v|video|audio|lyrics?|cover|playlist|live|가사|자막)[^\]】)）]*[\]】)）]\s*$", "", keyword, flags=re.I).strip()
    keyword = re.sub(r"\s+", " ", keyword).strip()
    return keyword or clean_music_title(title)


def fetch_page_title(url: str):
    """멜론/지니뮤직 링크처럼 직접 재생이 어려운 페이지에서 제목만 가져와 검색어로 사용합니다."""
    try:
        req = urllib.request.Request(
            url,
            headers={"User-Agent": "Mozilla/5.0"},
        )
        with urllib.request.urlopen(req, timeout=DASHBOARD_SYNC_TIMEOUT) as resp:
            raw = resp.read(250000)
        page = raw.decode("utf-8", errors="ignore")
        patterns = [
            r'<meta[^>]+property=["\\\']og:title["\\\'][^>]+content=["\\\']([^"\\\']+)',
            r'<meta[^>]+content=["\\\']([^"\\\']+)["\\\'][^>]+property=["\\\']og:title["\\\']',
            r'<title[^>]*>(.*?)</title>',
        ]
        for pattern in patterns:
            match = re.search(pattern, page, re.I | re.S)
            if match:
                return clean_music_title(match.group(1))
    except Exception:
        return None
    return None


def parse_music_source_prefix(query: str):
    """입력값 앞의 검색 기준을 읽습니다.

    사용 예시:
    유튜브: 영상 제목
    yt: 영상 제목
    사클: 음악 제목
    sc: 음악 제목
    """
    raw = (query or "").strip()
    lowered = raw.lower()
    prefix_map = {
        "유튜브:": "youtube",
        "youtube:": "youtube",
        "yt:": "youtube",
        "사클:": "soundcloud",
        "사운드클라우드:": "soundcloud",
        "soundcloud:": "soundcloud",
        "sc:": "soundcloud",
    }
    for prefix, source in prefix_map.items():
        if lowered.startswith(prefix):
            return source, raw[len(prefix):].strip()
    return None, raw


def build_music_search_query(query: str, preferred_source: str = None):
    query = (query or "").strip()
    preferred_source = (preferred_source or "").strip().lower()

    prefix_source, stripped_query = parse_music_source_prefix(query)
    if prefix_source:
        preferred_source = prefix_source
        query = stripped_query

    service, _emoji = detect_music_service(query)
    lower = query.lower()

    # YouTube 직접 링크는 Render에서 계속 막힐 수 있어서 직접 재생은 차단합니다.
    if re.search(r"https?://(www\.)?(youtube\.com|youtu\.be)/", query or "", re.I):
        return "__YOUTUBE_DIRECT_LINK_BLOCKED__", "YouTube", query

    # SoundCloud 직접 링크는 그대로 재생합니다.
    if "soundcloud.com" in lower:
        return query, "SoundCloud", query

    if service in {"Melon", "Genie Music"}:
        page_title = fetch_page_title(query) if lower.startswith(("http://", "https://")) else None
        keyword = page_title or query
        keyword = re.sub(r"https?://\S+", "", keyword).strip() or query
        # 멜론/지니는 직접 재생이 어려워 사클 기준으로 검색합니다.
        return f"scsearch1:{keyword}", service, keyword

    keyword = normalize_youtube_title_keyword(query)

    # 검색 기준을 버튼/접두어로 완전히 분리합니다.
    if preferred_source in {"youtube", "yt", "youtube_title"}:
        return f"ytsearch1:{keyword}", "YouTube 제목 검색", keyword
    if preferred_source in {"soundcloud", "sc", "soundcloud_title"}:
        return f"scsearch1:{keyword}", "SoundCloud 제목 검색", keyword

    # 기본값은 Render에서 더 안정적인 SoundCloud 제목 검색입니다.
    return f"scsearch1:{keyword}", "SoundCloud 제목 검색", keyword

async def extract_music_info(query: str, preferred_source: str = None):
    loop = asyncio.get_running_loop()

    def _is_youtube_service(requested_service: str):
        return requested_service in {"YouTube", "YouTube 제목 검색"}

    def _is_youtube_webpage_url(url: str):
        url = str(url or "").lower()
        return (
            "youtube.com/watch" in url
            or "youtube.com/shorts/" in url
            or "youtu.be/" in url
            or "music.youtube.com/watch" in url
        )

    def _youtube_url_from_info(info: dict):
        if not isinstance(info, dict):
            return None

        for key in ("webpage_url", "original_url", "url"):
            value = str(info.get(key) or "").strip()
            if _is_youtube_webpage_url(value):
                return value

        video_id = str(info.get("id") or "").strip()
        if video_id and re.fullmatch(r"[A-Za-z0-9_-]{8,}", video_id):
            return f"https://www.youtube.com/watch?v={video_id}"

        return None

    def _first_entry(info: dict):
        if isinstance(info, dict) and isinstance(info.get("entries"), list):
            entries = [entry for entry in info.get("entries", []) if entry]
            if not entries:
                raise ValueError("검색 결과가 없습니다.")
            return entries[0]
        return info

    def _pick_audio_stream(info: dict, requested_service: str):
        """yt-dlp 결과에서 Discord/FFmpeg가 바로 재생할 오디오 URL을 직접 고릅니다."""
        if not isinstance(info, dict):
            return None, info

        candidates = []

        # bestvideo+bestaudio 조합으로 받은 경우 오디오 쪽 requested_format을 우선 사용합니다.
        for fmt in info.get("requested_formats") or []:
            if not isinstance(fmt, dict) or not fmt.get("url"):
                continue
            acodec = str(fmt.get("acodec") or "")
            vcodec = str(fmt.get("vcodec") or "")
            if acodec and acodec != "none":
                candidates.append(fmt)

        # 일반 formats 목록에서 오디오 포맷을 직접 고릅니다.
        for fmt in info.get("formats") or []:
            if not isinstance(fmt, dict) or not fmt.get("url"):
                continue

            fmt_url = str(fmt.get("url") or "")
            protocol = str(fmt.get("protocol") or "").lower()
            acodec = str(fmt.get("acodec") or "")
            vcodec = str(fmt.get("vcodec") or "")
            format_note = str(fmt.get("format_note") or "").lower()
            ext = str(fmt.get("ext") or "").lower()

            # 이미지/스토리보드/자막류는 오디오 재생에 쓸 수 없습니다.
            if ext in {"jpg", "png", "webp", "json", "mhtml"}:
                continue
            if "storyboard" in format_note or "storyboard" in fmt_url.lower():
                continue

            # 오디오가 있는 포맷을 우선 후보로 넣습니다. m3u8도 FFmpeg가 재생할 수 있어 완전히 제외하지 않습니다.
            if acodec and acodec != "none":
                candidates.append(fmt)
            elif vcodec == "none" and fmt_url.startswith(("http://", "https://")):
                candidates.append(fmt)
            elif protocol in {"http", "https", "m3u8", "m3u8_native"} and fmt_url.startswith(("http://", "https://")):
                candidates.append(fmt)

        if candidates:
            def score(fmt):
                acodec = str(fmt.get("acodec") or "")
                vcodec = str(fmt.get("vcodec") or "")
                protocol = str(fmt.get("protocol") or "").lower()
                ext = str(fmt.get("ext") or "").lower()
                return (
                    1 if acodec and acodec != "none" else 0,
                    1 if vcodec == "none" else 0,
                    1 if protocol in {"http", "https"} else 0,
                    1 if ext in {"m4a", "webm", "opus", "mp3"} else 0,
                    int(fmt.get("abr") or 0),
                    int(fmt.get("tbr") or 0),
                    int(fmt.get("filesize") or fmt.get("filesize_approx") or 0),
                )

            candidates.sort(key=score, reverse=True)
            chosen = candidates[0]
            merged = {**info, **chosen}
            return chosen.get("url"), merged

        # formats가 없어도 info.url이 실제 CDN/스트림이면 사용할 수 있습니다.
        stream_url = str(info.get("url") or "").strip()
        if stream_url and not _is_youtube_webpage_url(stream_url):
            return stream_url, info

        return None, info

    def _normalize_info(info, original_query, requested_service, searched_keyword):
        info = _first_entry(info)

        detected_service, service_emoji = detect_music_service(original_query, info)
        if requested_service in {"Melon", "Genie Music"}:
            detected_service = requested_service
            service_emoji = "🍈" if requested_service == "Melon" else "🧞"
        elif requested_service == "YouTube 제목 검색":
            detected_service = "YouTube 제목 검색"
            service_emoji = "▶️"
        elif requested_service == "SoundCloud 제목 검색":
            detected_service = "SoundCloud 제목 검색"
            service_emoji = "🟧"

        stream_url, info = _pick_audio_stream(info, requested_service)

        if not stream_url:
            if _is_youtube_service(requested_service):
                cookie_ok, cookie_msg = check_ytdlp_cookie_file(YTDLP_COOKIE_FILE)
                raise ValueError(
                    "YouTube에서 재생 가능한 오디오 포맷을 찾지 못했어요. "
                    "Render/무료 서버에서는 YouTube가 봇 접속을 막는 경우가 있어서 `cookies.txt`가 필요할 수 있어요. "
                    f"쿠키 경로: {YTDLP_COOKIE_FILE or '미설정'} / 쿠키 검사: {cookie_msg}"
                )
            raise ValueError("재생 가능한 오디오 포맷을 찾지 못했어요. `사클 제목`으로 다시 검색해보세요.")

        return {
            "title": clean_music_title(info.get("title", "제목 없음")),
            "url": stream_url,
            "webpage_url": info.get("webpage_url", original_query),
            "duration": info.get("duration", 0),
            "thumbnail": info.get("thumbnail"),
            "service": detected_service,
            "service_emoji": service_emoji,
            "requested_query": original_query,
            "searched_keyword": searched_keyword,
            "uploader": info.get("uploader") or info.get("channel") or "알 수 없음",
            "http_headers": info.get("http_headers") or {},
        }

    def _extract_with_options(search_query: str, requested_service: str, original_query: str, searched_keyword: str, options: dict):
        local_ytdl = yt_dlp.YoutubeDL(options)
        info = local_ytdl.extract_info(search_query, download=False)

        # ytsearch 결과가 얕은 항목으로 들어오면 실제 영상 페이지를 한 번 더 추출합니다.
        if _is_youtube_service(requested_service):
            first = _first_entry(info)
            stream_url, _ = _pick_audio_stream(first, requested_service)
            video_url = _youtube_url_from_info(first)
            if video_url and (not stream_url or _is_youtube_webpage_url(stream_url)):
                info = local_ytdl.extract_info(video_url, download=False)

        return _normalize_info(info, original_query, requested_service, searched_keyword)

    def run_extract():
        search_query, requested_service, searched_keyword = build_music_search_query(query, preferred_source)

        is_youtube_request = _is_youtube_service(requested_service)
        profiles = YTDLP_FALLBACK_PROFILES
        if is_youtube_request:
            profiles = [(YTDLP_SAFE_AUDIO_FORMAT, clients) for clients in YTDLP_YOUTUBE_CLIENT_PROFILES] + YTDLP_FALLBACK_PROFILES

        last_error = None
        youtube_bot_blocked = False

        for retry_format, retry_clients in profiles:
            try:
                options = build_ytdl_options(retry_format, retry_clients)
                return _extract_with_options(search_query, requested_service, query, searched_keyword, options)
            except Exception as e:
                last_error = e
                lower_error = str(e).lower()
                if (
                    "sign in to confirm" in lower_error
                    or "not a bot" in lower_error
                    or "confirm you’re not a bot" in lower_error
                    or "confirm you're not a bot" in lower_error
                    or "use --cookies" in lower_error
                    or "cookies" in lower_error and "youtube" in lower_error
                ):
                    youtube_bot_blocked = True
                continue

        if is_youtube_request:
            cookie_ok, cookie_msg = check_ytdlp_cookie_file(YTDLP_COOKIE_FILE)
            if youtube_bot_blocked:
                raise ValueError(
                    "YouTube가 서버를 봇으로 감지해서 커스텀 봇 재생을 막았어요. "
                    "Render 환경변수나 Secret File로 YouTube `cookies.txt`를 넣어야 할 수 있어요. "
                    f"쿠키 경로: {YTDLP_COOKIE_FILE or '미설정'} / 쿠키 검사: {cookie_msg}"
                ) from last_error
            raise ValueError(
                "YouTube에서 재생 가능한 오디오 포맷을 찾지 못했어요. "
                f"마지막 오류: {str(last_error)[:250]}"
            ) from last_error

        # 자동/기타 검색에서만 SoundCloud로 한 번 더 시도합니다.
        try:
            fallback_ytdl = yt_dlp.YoutubeDL(build_ytdl_options("bestaudio/best", ["web", "mweb", "ios"]))
            fallback_info = fallback_ytdl.extract_info(f"scsearch1:{searched_keyword or query}", download=False)
            return _normalize_info(fallback_info, query, "SoundCloud 제목 검색", searched_keyword or query)
        except Exception:
            pass

        if last_error:
            raise last_error
        raise ValueError("노래 정보를 가져오지 못했어요.")

    return await loop.run_in_executor(None, run_extract)

def build_now_playing_embed(track: dict, *, queued: bool = False):
    status = "대기열 추가" if queued else "현재 재생 중"
    service = track.get("service", "검색")
    service_emoji = track.get("service_emoji", "🎧")
    embed = discord.Embed(
        title=f"{service_emoji} {status} · {service}",
        description=f"**{track.get('title', '제목 없음')}**",
        color=BOT_COLOR,
        url=track.get("webpage_url") or None,
    )
    embed.add_field(name="⏱️ 길이", value=f"`{format_duration(track.get('duration'))}`", inline=True)
    embed.add_field(name="🎤 업로더", value=str(track.get("uploader", "알 수 없음"))[:100], inline=True)
    if service in {"Melon", "Genie Music"}:
        embed.add_field(
            name="📌 안내",
            value="멜론/지니뮤직 링크·검색어는 제목을 기준으로 SoundCloud에서 찾아 재생해요.",
            inline=False,
        )
    if service == "YouTube 제목 검색":
        embed.add_field(
            name="📌 안내",
            value="입력한 제목을 기준으로 YouTube에서 찾아 재생해요. Render에서 막히면 사클 제목 검색을 사용해주세요.",
            inline=False,
        )
    if service == "SoundCloud 제목 검색":
        embed.add_field(
            name="📌 안내",
            value="입력한 제목을 기준으로 SoundCloud에서 찾아 재생해요.",
            inline=False,
        )
    if track.get("thumbnail"):
        embed.set_thumbnail(url=track["thumbnail"])
    embed.set_footer(text="🎵 만능 봇 뮤직 패널")
    return embed


async def send_music_now_playing_box(guild: discord.Guild, track: dict, *, queued: bool = False):
    channel = get_channel_by_id_or_name(guild, 0, [MUSIC_NOW_PLAYING_CHANNEL_NAME, "현재재생", "now-playing"], "text")
    if not channel:
        return
    try:
        await channel.send(embed=build_now_playing_embed(track, queued=queued))
    except (discord.Forbidden, discord.HTTPException):
        pass


async def send_music_play_error_box(guild: discord.Guild, title: str, error: Exception | str):
    channel = get_channel_by_id_or_name(
        guild,
        0,
        [MUSIC_NOW_PLAYING_CHANNEL_NAME, MUSIC_COMMAND_CHANNEL_NAME, "현재재생", "뮤직명령어", "music"],
        "text",
    )
    if not channel:
        return
    err = str(error)
    if len(err) > 900:
        err = err[:900] + "..."
    embed = discord.Embed(
        title="❌ 음악 재생 실패",
        description=(
            f"**{title or '제목 없음'}** 재생을 시작하지 못했어요.\n\n"
            f"```{err}```\n"
            "FFmpeg가 없거나, 스트림 URL이 막혔거나, YouTube/SoundCloud가 헤더를 요구하는 경우일 수 있어요."
        ),
        color=0xFF6B6B,
    )
    try:
        await channel.send(embed=embed)
    except (discord.Forbidden, discord.HTTPException):
        pass


async def ensure_music_voice_after_defer(interaction: discord.Interaction):
    if interaction.guild is None:
        await interaction.followup.send("❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
        return None

    if not interaction.user.voice or not interaction.user.voice.channel:
        await interaction.followup.send("❌ 먼저 음성 채널에 들어가주세요.", ephemeral=True)
        return None

    voice_channel = interaction.user.voice.channel
    voice_client = interaction.guild.voice_client

    if voice_client is None:
        return await voice_channel.connect()

    if voice_client.channel != voice_channel:
        await voice_client.move_to(voice_channel)

    return voice_client


async def play_music_next(guild: discord.Guild):
    voice_client = guild.voice_client
    if voice_client is None:
        return False

    guild_id = guild.id
    queue = get_music_queue(guild_id)

    if loop_enabled.get(guild_id) and now_playing.get(guild_id):
        queue.appendleft(now_playing[guild_id])

    if not queue:
        now_playing[guild_id] = None
        return False

    track = queue.popleft()
    now_playing[guild_id] = track
    skip_vote_users.pop(guild_id, None)

    try:
        source = build_discord_audio_source(track, get_music_volume(guild_id))
        voice_client.play(source, after=lambda error: asyncio.run_coroutine_threadsafe(
            _after_main_music_play(guild, error), bot.loop
        ))
    except Exception as e:
        now_playing[guild_id] = None
        print(f"재생 시작 실패: {e}")
        await send_music_play_error_box(guild, track.get("title", "제목 없음"), e)
        # 다음 대기열이 있으면 멈추지 않고 이어서 시도합니다.
        if queue:
            await play_music_next(guild)
        return False

    await send_music_now_playing_box(guild, track, queued=False)
    return True


async def _after_main_music_play(guild: discord.Guild, error):
    if error:
        print(f"재생 오류: {error}")
        try:
            await send_music_play_error_box(guild, (now_playing.get(guild.id) or {}).get("title", "제목 없음"), error)
        except Exception:
            pass
    try:
        await play_music_next(guild)
    except Exception as e:
        print(f"다음 곡 재생 오류: {e}")


class PlayMusicModal(discord.ui.Modal):
    def __init__(self, source: str = "soundcloud"):
        title = "🎶 사클 제목 검색" if source == "soundcloud" else "🎶 유튜브 제목 검색"
        super().__init__(title=title)
        self.source = source
        label = "SoundCloud 제목 검색" if source == "soundcloud" else "YouTube 제목 검색"
        placeholder = "예: 오늘 하루도 고생한 당신에게 피아노 모음"
        self.query = discord.ui.TextInput(
            label=label,
            placeholder=placeholder,
        required=True,
        max_length=300,
        )
        self.add_item(self.query)

    async def on_submit(self, interaction: discord.Interaction):
        await safe_interaction_defer(interaction, ephemeral=True)

        voice_client = await ensure_music_voice_after_defer(interaction)
        if voice_client is None:
            return

        query_text = str(self.query.value).strip()

        try:
            track = await extract_music_info(query_text, self.source)
        except Exception as e:
            return await interaction.followup.send(
                f"❌ 노래 정보를 가져오지 못했어요.\n`{e}`",
                ephemeral=True,
            )

        queue = get_music_queue(interaction.guild.id)
        queue.append(track)

        if not voice_client.is_playing() and not voice_client.is_paused():
            await play_music_next(interaction.guild)
            msg = f"🎶 바로 재생을 시작했어요!\n{track.get('service_emoji', '🎧')} **{track['title']}**\n서비스: `{track.get('service', '검색')}` ㅣ 길이: `{format_duration(track['duration'])}`"
        else:
            await send_music_now_playing_box(interaction.guild, track, queued=True)
            msg = f"✅ 대기열에 추가했어요!\n{track.get('service_emoji', '🎧')} **{track['title']}**\n서비스: `{track.get('service', '검색')}` ㅣ 길이: `{format_duration(track['duration'])}`"

        await interaction.followup.send(msg, ephemeral=True)


class MusicVolumeModal(discord.ui.Modal, title="🔊 볼륨 설정"):
    volume = discord.ui.TextInput(
        label="볼륨 1~100",
        placeholder="예: 50",
        required=True,
        max_length=3,
    )

    async def on_submit(self, interaction: discord.Interaction):
        try:
            value = int(str(self.volume.value).strip())
        except ValueError:
            return await safe_interaction_send(interaction, "❌ 숫자만 입력해주세요.", ephemeral=True)

        if value < 1 or value > 100:
            return await safe_interaction_send(interaction, "❌ 1부터 100까지만 입력해주세요.", ephemeral=True)

        guild_id = interaction.guild.id
        volume_levels[guild_id] = value / 100

        voice_client = interaction.guild.voice_client
        if voice_client and voice_client.source and isinstance(voice_client.source, discord.PCMVolumeTransformer):
            voice_client.source.volume = value / 100

        await safe_interaction_send(interaction, f"🔊 볼륨을 **{value}%** 로 설정했어요.", ephemeral=True)


class MusicPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="사클 제목", emoji="🟧", style=discord.ButtonStyle.green, custom_id="music_play_sc")
    async def play_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(PlayMusicModal("soundcloud"))

    @discord.ui.button(label="유튜브 제목", emoji="▶️", style=discord.ButtonStyle.red, custom_id="music_play_yt")
    async def play_youtube_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(PlayMusicModal("youtube"))

    @discord.ui.button(label="일시정지", emoji="⏸️", style=discord.ButtonStyle.gray, custom_id="music_pause")
    async def pause_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        vc = interaction.guild.voice_client
        if vc and vc.is_playing():
            vc.pause()
            return await safe_interaction_send(interaction, "⏸️ 음악을 일시정지했어요.", ephemeral=True)
        await safe_interaction_send(interaction, "❌ 현재 재생 중인 음악이 없어요.", ephemeral=True)

    @discord.ui.button(label="다시재생", emoji="▶️", style=discord.ButtonStyle.blurple, custom_id="music_resume")
    async def resume_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        vc = interaction.guild.voice_client
        if vc and vc.is_paused():
            vc.resume()
            return await safe_interaction_send(interaction, "▶️ 음악을 다시 재생했어요.", ephemeral=True)
        await safe_interaction_send(interaction, "❌ 일시정지된 음악이 없어요.", ephemeral=True)

    @discord.ui.button(label="스킵 투표", emoji="⏭️", style=discord.ButtonStyle.red, custom_id="music_skip")
    async def skip_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        vc = interaction.guild.voice_client
        if not vc or not (vc.is_playing() or vc.is_paused()):
            return await safe_interaction_send(interaction, "❌ 스킵할 음악이 없어요.", ephemeral=True)

        if not interaction.user.voice or interaction.user.voice.channel != vc.channel:
            return await safe_interaction_send(interaction, "❌ 같은 음성 채널에 있어야 스킵 투표를 할 수 있어요.", ephemeral=True)

        guild_id = interaction.guild.id
        required_votes = get_skip_vote_required(vc.channel)
        votes = clean_skip_votes(guild_id, vc.channel)

        if interaction.user.id in votes:
            return await safe_interaction_send(interaction, 
                f"⏭️ 이미 스킵 투표했어요. 현재 **{len(votes)}/{required_votes}**",
                ephemeral=True
            )

        votes.add(interaction.user.id)
        vote_count = len(votes)

        if vote_count >= required_votes:
            skip_vote_users.pop(guild_id, None)
            vc.stop()
            return await safe_interaction_send(interaction, 
                f"⏭️ 스킵 투표 **{vote_count}/{required_votes}** 완료! 현재 곡을 스킵했어요.",
                ephemeral=False
            )

        await safe_interaction_send(interaction, 
            f"⏭️ 스킵 투표 완료! 현재 **{vote_count}/{required_votes}**\n음성방에 있는 사람 수만큼 투표하면 현재 곡이 스킵됩니다.",
            ephemeral=True
        )

    @discord.ui.button(label="대기열", emoji="📜", style=discord.ButtonStyle.gray, custom_id="music_queue")
    async def queue_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        guild_id = interaction.guild.id
        queue = get_music_queue(guild_id)
        current = now_playing.get(guild_id)

        text = ""
        if current:
            text += f"🎵 **현재 재생 중**\n{current.get('service_emoji', '🎧')} {current['title']} `[{format_duration(current['duration'])}]`\n\n"

        if queue:
            text += "📜 **대기열**\n"
            for i, track in enumerate(list(queue)[:10], start=1):
                text += f"{i}. {track.get('service_emoji', '🎧')} {track['title']} `[{format_duration(track['duration'])}]`\n"
        else:
            text += "대기 중인 곡이 없어요."

        embed = create_embed("📜 만능 봇 뮤직 대기열", text[:4000])
        await safe_interaction_send(interaction, embed=embed, ephemeral=True)

    @discord.ui.button(label="반복", emoji="🔁", style=discord.ButtonStyle.green, custom_id="music_loop")
    async def loop_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        guild_id = interaction.guild.id
        loop_enabled[guild_id] = not loop_enabled.get(guild_id, False)
        state = "켜짐" if loop_enabled[guild_id] else "꺼짐"
        await safe_interaction_send(interaction, f"🔁 반복 재생: **{state}**", ephemeral=True)

    @discord.ui.button(label="셔플", emoji="🔀", style=discord.ButtonStyle.gray, custom_id="music_shuffle")
    async def shuffle_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        queue = get_music_queue(interaction.guild.id)
        if len(queue) < 2:
            return await safe_interaction_send(interaction, "❌ 섞을 대기열이 부족해요. 노래가 2곡 이상 있어야 합니다.", ephemeral=True)
        items = list(queue)
        random.shuffle(items)
        queue.clear()
        queue.extend(items)
        await safe_interaction_send(interaction, f"🔀 대기열 **{len(queue)}곡**을 랜덤으로 섞었어요.", ephemeral=True)

    @discord.ui.button(label="볼륨", emoji="🔊", style=discord.ButtonStyle.blurple, custom_id="music_volume")
    async def volume_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.send_modal(MusicVolumeModal())

    @discord.ui.button(label="종료", emoji="❌", style=discord.ButtonStyle.red, custom_id="music_leave")
    async def leave_button(self, interaction: discord.Interaction, button: discord.ui.Button):
        vc = interaction.guild.voice_client
        if vc:
            music_queues.pop(interaction.guild.id, None)
            now_playing.pop(interaction.guild.id, None)
            loop_enabled.pop(interaction.guild.id, None)
            skip_vote_users.pop(interaction.guild.id, None)
            await vc.disconnect()
            return await safe_interaction_send(interaction, "❌ 음악을 종료하고 음성 채널에서 나갔어요.", ephemeral=True)
        await safe_interaction_send(interaction, "❌ 봇이 음성 채널에 없어요.", ephemeral=True)


