class VoteView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)
        self.yes = 0
        self.no = 0
        self.voters = set()

    @discord.ui.button(label="👍 찬성", style=discord.ButtonStyle.green)
    async def vote_yes(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id in self.voters:
            return await safe_interaction_send(interaction, "❌ 이미 투표했습니다.", ephemeral=True)
        self.voters.add(interaction.user.id)
        self.yes += 1
        await safe_interaction_send(interaction, f"✅ 찬성 투표 완료!\n찬성: {self.yes}표 / 반대: {self.no}표", ephemeral=True)

    @discord.ui.button(label="👎 반대", style=discord.ButtonStyle.danger)
    async def vote_no(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user.id in self.voters:
            return await safe_interaction_send(interaction, "❌ 이미 투표했습니다.", ephemeral=True)
        self.voters.add(interaction.user.id)
        self.no += 1
        await safe_interaction_send(interaction, f"✅ 반대 투표 완료!\n찬성: {self.yes}표 / 반대: {self.no}표", ephemeral=True)


# 통합 하위명령어로 이동됨: @bot.tree.command(name="투표", description="찬반 투표를 생성합니다.")
async def vote(interaction: discord.Interaction, title: str):
    embed = discord.Embed(title="📊 투표", description=f"**{title}**\n\n👍 찬성\n👎 반대", color=discord.Color.blurple())
    embed.set_footer(text=f"투표 생성자: {interaction.user}")
    await safe_interaction_send(interaction, embed=embed, view=VoteView())


# 통합 하위명령어로 이동됨: @bot.tree.command(name="추첨", description="온라인 멤버 중 랜덤으로 추첨합니다.")
async def draw(interaction: discord.Interaction, count: int):
    if count < 1:
        return await safe_interaction_send(interaction, "❌ 1명 이상 입력해주세요.", ephemeral=True)
    members = [member for member in interaction.guild.members if not member.bot and member.status != discord.Status.offline]
    if not members:
        return await safe_interaction_send(interaction, "❌ 추첨 가능한 온라인 멤버가 없습니다.", ephemeral=True)
    winners = random.sample(members, min(count, len(members)))
    text = "".join(f"**{i}.** {member.mention}\n" for i, member in enumerate(winners, start=1))
    embed = discord.Embed(title="🎉 추첨 결과", description=text, color=discord.Color.gold())
    await safe_interaction_send(interaction, embed=embed)


