# =====================================================
# 내전 모집 시스템
# =====================================================

def _scrim_config_default(guild: discord.Guild, host: discord.Member = None):
    return {
        "title": "🎮 내전 모집",
        "game_name": "종합게임",
        "max_members": 10,
        "description": "아래 버튼으로 내전에 참가하거나 취소할 수 있어요.",
        "color": "5865F2",
        "image_url": "",
        "footer": "만능 봇 | 내전 모집",
        "content": "",
        "host_id": host.id if host else 0,
        "host_name": str(host) if host else "",
    }


def _scrim_safe_max_members(value, default=10):
    try:
        max_members = int(str(value).strip())
    except (TypeError, ValueError):
        return default
    return max(2, min(30, max_members))


def _scrim_render_text(text: str, config: dict, members=None, guild: discord.Guild = None):
    members = members or []
    guild_name = guild.name if guild else "서버"
    member_text = "\n".join([f"{i}. {member.mention}" for i, member in enumerate(members, start=1)]) or "아직 참가자가 없습니다."
    return (text or "") \
        .replace("{game}", str(config.get("game_name") or "종합게임")) \
        .replace("{max}", str(config.get("max_members") or 10)) \
        .replace("{current}", str(len(members))) \
        .replace("{members}", member_text) \
        .replace("{server}", guild_name) \
        .replace("{host}", f"<@{config.get('host_id')}>" if config.get("host_id") else str(config.get("host_name") or ""))


def build_scrim_embed(config: dict, guild: discord.Guild = None, members=None, preview: bool = False):
    members = members or []
    max_members = _scrim_safe_max_members(config.get("max_members"), 10)
    status = "🎉 모집 완료!" if len(members) >= max_members else "모집 중"
    member_text = "\n".join([f"{i}. {member.mention}" for i, member in enumerate(members, start=1)]) or "아직 참가자가 없습니다."

    title = _scrim_render_text(config.get("title") or "🎮 {game} 내전 모집", config, members, guild)[:256]
    description = _scrim_render_text(config.get("description") or "아래 버튼으로 내전에 참가하거나 취소할 수 있어요.", config, members, guild)
    if preview:
        description = "🧩 **미리보기입니다. `전송하기` 버튼을 누르면 채널에 올라가요.**\n\n" + description

    description = (
        f"{description}\n\n"
        f"━━━━━━━━━━━━━━━━━━━━\n"
        f"🎮 게임: **{config.get('game_name') or '종합게임'}**\n"
        f"📌 상태: **{status}**\n"
        f"👥 현재 인원: **{len(members)} / {max_members}명**\n\n"
        f"**참가자 목록**\n{member_text}"
    )[:4096]

    embed = discord.Embed(
        title=title,
        description=description,
        color=normalize_embed_color(str(config.get("color") or "5865F2"))
    )
    image_url = safe_url(config.get("image_url") or "")
    if image_url:
        embed.set_image(url=image_url)
    footer = _scrim_render_text(config.get("footer") or "참가 / 취소 버튼으로 신청할 수 있어요.", config, members, guild)[:2048]
    if footer:
        embed.set_footer(text=footer)
    if guild and guild.icon:
        embed.set_thumbnail(url=guild.icon.url)
    return embed


class ScrimRecruitView(discord.ui.View):
    def __init__(self, config_or_game_name, max_members: int = None):
        super().__init__(timeout=None)
        if isinstance(config_or_game_name, dict):
            self.config = dict(config_or_game_name)
        else:
            self.config = _scrim_config_default(None)
            self.config["game_name"] = str(config_or_game_name or "종합게임")
            self.config["max_members"] = _scrim_safe_max_members(max_members, 10)
            self.config["title"] = "🎮 {game} 내전 모집"
        self.config["max_members"] = _scrim_safe_max_members(self.config.get("max_members"), 10)
        self.members = []

    def make_embed(self, guild: discord.Guild = None):
        return build_scrim_embed(self.config, guild=guild, members=self.members)

    @discord.ui.button(label="참가", emoji="✅", style=discord.ButtonStyle.green, custom_id="rize_scrim_join")
    async def join_scrim(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user in self.members:
            return await safe_interaction_send(interaction, "❌ 이미 참가했어요.", ephemeral=True)

        if len(self.members) >= self.config.get("max_members", 10):
            return await safe_interaction_send(interaction, "❌ 이미 모집이 완료되었어요.", ephemeral=True)

        self.members.append(interaction.user)
        await safe_interaction_edit(interaction, embed=self.make_embed(interaction.guild), view=self)

    @discord.ui.button(label="취소", emoji="❌", style=discord.ButtonStyle.red, custom_id="rize_scrim_leave")
    async def leave_scrim(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.user not in self.members:
            return await safe_interaction_send(interaction, "❌ 아직 참가하지 않았어요.", ephemeral=True)

        self.members.remove(interaction.user)
        await safe_interaction_edit(interaction, embed=self.make_embed(interaction.guild), view=self)


class ScrimContentModal(discord.ui.Modal, title="내전 모집 만들기/수정"):
    def __init__(self, config=None):
        super().__init__()
        config = dict(config or {})
        self.title_input.default = str(config.get("title") or "🎮 {game} 내전 모집")[:100]
        self.game_name.default = str(config.get("game_name") or "종합게임")[:80]
        self.max_members.default = str(config.get("max_members") or 10)[:5]
        self.description.default = str(config.get("description") or "아래 버튼으로 내전에 참가하거나 취소할 수 있어요.")[:1000]
        self.image_url.default = str(config.get("image_url") or "")[:300]
        self.config = config

    title_input = discord.ui.TextInput(label="제목", placeholder="예: 🎮 {game} 내전 모집", required=True, max_length=100)
    game_name = discord.ui.TextInput(label="게임 이름", placeholder="예: 롤, 발로란트, 마인크래프트", required=True, max_length=80)
    max_members = discord.ui.TextInput(label="모집 인원", placeholder="2~30 사이 숫자", required=True, max_length=5)
    description = discord.ui.TextInput(label="내용", placeholder="내전 안내 내용을 적어주세요. {game}, {max}, {host} 사용 가능", required=True, style=discord.TextStyle.paragraph, max_length=1000)
    image_url = discord.ui.TextInput(label="이미지/GIF URL", placeholder="비워도 됩니다", required=False, max_length=300)

    async def on_submit(self, interaction: discord.Interaction):
        config = dict(self.config or _scrim_config_default(interaction.guild, interaction.user))
        config.update({
            "title": self.title_input.value.strip() or "🎮 {game} 내전 모집",
            "game_name": self.game_name.value.strip() or "종합게임",
            "max_members": _scrim_safe_max_members(self.max_members.value, 10),
            "description": self.description.value.strip() or "아래 버튼으로 내전에 참가하거나 취소할 수 있어요.",
            "image_url": self.image_url.value.strip(),
            "host_id": interaction.user.id,
            "host_name": str(interaction.user),
        })
        view = ScrimDraftView(config, interaction.user.id)
        await safe_interaction_send(interaction, embed=build_scrim_embed(config, interaction.guild, preview=True), view=view, ephemeral=True)


class ScrimStyleModal(discord.ui.Modal, title="내전 모집 디자인 수정"):
    def __init__(self, config=None, owner_id: int = 0):
        super().__init__()
        self.config = dict(config or {})
        self.owner_id = owner_id
        self.color.default = str(self.config.get("color") or "5865F2")[:10]
        self.footer.default = str(self.config.get("footer") or "만능 봇 | 내전 모집")[:200]
        self.content.default = str(self.config.get("content") or "")[:200]

    color = discord.ui.TextInput(label="색상 HEX", placeholder="예: 5865F2 / FFB6C1", required=False, max_length=10)
    footer = discord.ui.TextInput(label="하단 문구", placeholder="예: 참가 / 취소 버튼으로 신청할 수 있어요.", required=False, max_length=200)
    content = discord.ui.TextInput(label="전송할 멘션/문구", placeholder="예: @everyone 오늘 내전 모집합니다!", required=False, style=discord.TextStyle.paragraph, max_length=200)

