class ScrimDraftView(discord.ui.View):
    def __init__(self, config: dict, owner_id: int):
        super().__init__(timeout=600)
        self.config = dict(config)
        self.owner_id = owner_id

    async def _is_owner(self, interaction: discord.Interaction):
        if interaction.user.id == self.owner_id or await can_manage_bot_in_guild(interaction):
            return True
        await safe_interaction_send(interaction, "❌ 이 내전 모집 초안을 만든 사람만 수정/전송할 수 있어요.", ephemeral=True)
        return False

    @discord.ui.button(label="내용 수정", emoji="✏️", style=discord.ButtonStyle.green)
    async def edit_content(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._is_owner(interaction):
            return
        await interaction.response.send_modal(ScrimContentModal(self.config))

    @discord.ui.button(label="디자인 수정", emoji="🎨", style=discord.ButtonStyle.blurple)
    async def edit_style(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._is_owner(interaction):
            return
        await interaction.response.send_modal(ScrimStyleModal(self.config, self.owner_id))

    @discord.ui.button(label="전송하기", emoji="🚀", style=discord.ButtonStyle.success)
    async def send_scrim(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._is_owner(interaction):
            return
        content = (self.config.get("content") or "").strip()
        # @everyone/@here는 관리 권한이 있는 사람만 그대로 보내고, 일반 유저는 제거합니다.
        if not interaction.user.guild_permissions.mention_everyone:
            content = content.replace("@everyone", "everyone").replace("@here", "here")
        try:
            await interaction.channel.send(
                content=content or None,
                embed=build_scrim_embed(self.config, interaction.guild),
                view=ScrimRecruitView(self.config)
            )
            for item in self.children:
                item.disabled = True
            await safe_interaction_edit(interaction, 
                content="✅ 내전 모집을 현재 채널에 전송했어요.",
                embed=build_scrim_embed(self.config, interaction.guild, preview=True),
                view=self
            )
        except (discord.Forbidden, discord.HTTPException):
            await safe_interaction_send(interaction, "❌ 이 채널에 메시지를 보낼 수 없어요. 봇 권한을 확인해주세요.", ephemeral=True)

    @discord.ui.button(label="취소", emoji="🗑️", style=discord.ButtonStyle.danger)
    async def cancel(self, interaction: discord.Interaction, button: discord.ui.Button):
        if not await self._is_owner(interaction):
            return
        for item in self.children:
            item.disabled = True
        await safe_interaction_edit(interaction, content="🗑️ 내전 모집 만들기를 취소했어요.", embed=None, view=self)


# 통합 하위명령어로 이동됨: @bot.tree.command(name="내전", description="내전 모집을 박스형으로 직접 꾸민 뒤 전송합니다.")
async def scrim_recruit(interaction: discord.Interaction):
    await interaction.response.send_modal(ScrimContentModal(_scrim_config_default(interaction.guild, interaction.user)))


