class CleanModal(discord.ui.Modal, title="메시지 청소"):
    amount = discord.ui.TextInput(label="삭제할 메시지 개수", placeholder="1 이상", required=True, max_length=10)

    async def on_submit(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.manage_messages:
            return await safe_interaction_send(interaction, "❌ 메시지 관리 권한이 필요해요.", ephemeral=True)

        try:
            amount = int(self.amount.value)
        except ValueError:
            return await safe_interaction_send(interaction, "❌ 숫자만 입력해주세요.", ephemeral=True)

        if amount < 1:
            return await safe_interaction_send(interaction, "❌ 1개 이상 입력해주세요.", ephemeral=True)

        await safe_interaction_defer(interaction, ephemeral=True)
        deleted_count = await purge_messages_unlimited(interaction.channel, amount)
        await interaction.followup.send(f"🧹 메시지 {deleted_count}개를 삭제했어요.", ephemeral=True)


class KickModal(discord.ui.Modal, title="유저 킥"):
    user_id = discord.ui.TextInput(label="유저 ID", placeholder="킥할 유저 ID", required=True)
    reason = discord.ui.TextInput(label="사유", placeholder="사유를 입력하세요", required=False, max_length=500)

    async def on_submit(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.kick_members:
            return await safe_interaction_send(interaction, "❌ 킥 권한이 필요해요.", ephemeral=True)

        try:
            target_id = int(self.user_id.value)
        except ValueError:
            return await safe_interaction_send(interaction, "❌ 유저 ID는 숫자만 입력해주세요.", ephemeral=True)

        member = interaction.guild.get_member(target_id)
        if member is None:
            return await safe_interaction_send(interaction, "❌ 해당 유저를 서버에서 찾을 수 없어요.", ephemeral=True)

        if member == interaction.user:
            return await safe_interaction_send(interaction, "❌ 자기 자신은 킥할 수 없어요.", ephemeral=True)

        reason = self.reason.value or "사유 없음"
        await member.kick(reason=reason)
        await safe_interaction_send(interaction, f"🔨 {member} 님을 킥했어요.\n사유: {reason}", ephemeral=True)

        if "send_log" in globals():
            await send_log(interaction.guild, f"🔨 킥\n대상: {member}\n관리자: {interaction.user}\n사유: {reason}", "punishment")


class BanModal(discord.ui.Modal, title="유저 밴"):
    user_id = discord.ui.TextInput(label="유저 ID", placeholder="밴할 유저 ID", required=True)
    reason = discord.ui.TextInput(label="사유", placeholder="사유를 입력하세요", required=False, max_length=500)

    async def on_submit(self, interaction: discord.Interaction):
        if not interaction.user.guild_permissions.ban_members:
            return await safe_interaction_send(interaction, "❌ 밴 권한이 필요해요.", ephemeral=True)

        try:
            target_id = int(self.user_id.value)
        except ValueError:
            return await safe_interaction_send(interaction, "❌ 유저 ID는 숫자만 입력해주세요.", ephemeral=True)

        member = interaction.guild.get_member(target_id)
        if member is None:
            return await safe_interaction_send(interaction, "❌ 해당 유저를 서버에서 찾을 수 없어요.", ephemeral=True)

        if member == interaction.user:
            return await safe_interaction_send(interaction, "❌ 자기 자신은 밴할 수 없어요.", ephemeral=True)

        reason = self.reason.value or "사유 없음"
        await member.ban(reason=reason)
        await safe_interaction_send(interaction, f"⛔ {member} 님을 밴했어요.\n사유: {reason}", ephemeral=True)

        if "send_log" in globals():
            await send_log(interaction.guild, f"⛔ 밴\n대상: {member}\n관리자: {interaction.user}\n사유: {reason}", "punishment")


