@bot.tree.command(name="패널", description="모든 패널을 단계별 통합 메뉴로 엽니다.")
async def unified_panel_command(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)
    if await reject_if_not_setup_manager(interaction):
        return
    if await reject_if_not_bot_manager(interaction):
        return

    # 패널은 버튼/임베드를 많이 준비하므로 3초 제한으로 Unknown interaction이 뜨지 않게
    # 먼저 defer 후 followup으로 전송합니다. 이미 응답된 상호작용도 안전하게 처리합니다.
    try:
        if not interaction.response.is_done():
            await safe_interaction_defer(interaction, ephemeral=True)
        await interaction.followup.send(
            embed=build_unified_panel_home_embed(),
            view=UnifiedPanelHomeView(),
            ephemeral=True,
        )
    except discord.HTTPException as e:
        code = getattr(e, "code", None)
        if code not in (40060, 10062):
            raise

