DAILY_MISSION_CHAT_TARGET = 20
DAILY_MISSION_REWARD_POINT = 500
DAILY_MISSION_REWARD_BOX = 1



def _parse_int_or_default(value, default: int, minimum: int = 0):
    try:
        parsed = int(str(value).strip())
    except (TypeError, ValueError):
        parsed = default
    return max(minimum, parsed)


def parse_reward_bundle(value: str, default_point: int = 0, default_box: int = 0):
    """`포인트,랜덤박스` 형식의 입력을 안전하게 해석합니다."""
    raw = (value or "").strip()
    if not raw:
        return default_point, default_box
    parts = [part.strip() for part in raw.replace("/", ",").split(",")]
    point = _parse_int_or_default(parts[0] if len(parts) >= 1 else default_point, default_point, 0)
    box = _parse_int_or_default(parts[1] if len(parts) >= 2 else default_box, default_box, 0)
    return point, box


