WEEKLY_MISSION_CHAMPION_TITLE = "주간미션 1등"


def get_weekly_mission_score(message_count: int, attendance_count: int):
    # 출석은 하루 단위라 채팅보다 무게를 조금 더 줍니다.
    return int(message_count or 0) + int(attendance_count or 0) * 10


def get_weekly_mission_leader(guild_id: int):
    current_week = week_key()
    c.execute(
        """
        SELECT user_id, message_count, attendance_count,
               (COALESCE(message_count, 0) + COALESCE(attendance_count, 0) * 10) AS score
        FROM weekly_mission_progress
        WHERE guild_id=? AND week_key=?
        ORDER BY score DESC, message_count DESC, attendance_count DESC, user_id ASC
        LIMIT 1
        """,
        (guild_id, current_week)
    )
    row = c.fetchone()
    if not row or int(row[3] or 0) <= 0:
        return None
    return {"user_id": int(row[0]), "message_count": int(row[1] or 0), "attendance_count": int(row[2] or 0), "score": int(row[3] or 0)}


async def sync_weekly_mission_champion_title(guild: discord.Guild):
    """주간미션 현재 1등에게 칭호를 이동합니다."""
    if guild is None:
        return
    leader = get_weekly_mission_leader(guild.id)
    if not leader:
        return
    current_week = week_key()
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute(
        "SELECT user_id FROM weekly_mission_champions WHERE guild_id=? AND week_key=?",
        (guild.id, current_week)
    )
    row = c.fetchone()
    previous_user_id = int(row[0]) if row and row[0] else 0
    new_user_id = leader["user_id"]
    if previous_user_id == new_user_id:
        c.execute(
            "UPDATE weekly_mission_champions SET score=?, updated_at=? WHERE guild_id=? AND week_key=?",
            (leader["score"], now, guild.id, current_week)
        )
        conn.commit()
        return

    if previous_user_id:
        remove_user_title(guild.id, previous_user_id, WEEKLY_MISSION_CHAMPION_TITLE)

    add_user_title(guild.id, new_user_id, WEEKLY_MISSION_CHAMPION_TITLE)
    equip_user_title(guild.id, new_user_id, WEEKLY_MISSION_CHAMPION_TITLE)
    c.execute(
        """
        INSERT INTO weekly_mission_champions(guild_id, week_key, user_id, score, updated_at)
        VALUES (?, ?, ?, ?, ?)
        ON CONFLICT(guild_id, week_key) DO UPDATE SET
            user_id=excluded.user_id,
            score=excluded.score,
            updated_at=excluded.updated_at
        """,
        (guild.id, current_week, new_user_id, leader["score"], now)
    )
    conn.commit()

    try:
        new_member = guild.get_member(new_user_id) or await guild.fetch_member(new_user_id)
    except Exception:
        new_member = None
    try:
        old_member = guild.get_member(previous_user_id) if previous_user_id else None
    except Exception:
        old_member = None

    notice = (
        f"🏷️ 주간미션 1등 칭호 이동\n"
        f"새 1등: {new_member.mention if new_member else f'`{new_user_id}`'}\n"
        f"점수: **{leader['score']}점** / 채팅 {leader['message_count']}회 / 출석 {leader['attendance_count']}일"
    )
    if old_member:
        notice += f"\n이전 1등: {old_member.mention}"
    await send_log(guild, notice, "general")

