def today_key():
    return datetime.datetime.now().strftime("%Y-%m-%d")


def week_key():
    year, week, _ = datetime.date.today().isocalendar()
    return f"{year}-W{week:02d}"


def normalize_coupon_code(code: str):
    code = (code or "").strip().upper()
    code = re.sub(r"\s+", "", code)
    return code


def parse_coupon_expire(value: str):
    value = (value or "").strip()
    if not value:
        return None
    for fmt in ("%Y-%m-%d %H:%M", "%Y-%m-%d"):
        try:
            return datetime.datetime.strptime(value, fmt).strftime("%Y-%m-%d %H:%M:%S")
        except ValueError:
            pass
    return "INVALID"


def get_daily_mission_settings(guild_id: int):
    ensure_dashboard_sync_for_guild(guild_id)
    c.execute(
        """
        SELECT chat_target, reward_point, reward_box, mission_title, mission_description,
               attendance_required, image_url, color
        FROM daily_mission_settings
        WHERE guild_id=?
        """,
        (guild_id,)
    )
    row = c.fetchone()
    if not row:
        return {
            "title": "🎯 오늘의 일일미션",
            "description": "채팅과 출석을 완료하고 오늘의 보상을 받아가세요!",
            "chat_target": DAILY_MISSION_CHAT_TARGET,
            "attendance_required": 1,
            "reward_point": DAILY_MISSION_REWARD_POINT,
            "reward_box": DAILY_MISSION_REWARD_BOX,
            "image_url": "",
            "color": "57F287",
        }
    return {
        "chat_target": max(1, int(row[0] or DAILY_MISSION_CHAT_TARGET)),
        "reward_point": max(0, int(row[1] or DAILY_MISSION_REWARD_POINT)),
        "reward_box": max(0, int(row[2] or DAILY_MISSION_REWARD_BOX)),
        "title": row[3] or "🎯 오늘의 일일미션",
        "description": row[4] or "채팅과 출석을 완료하고 오늘의 보상을 받아가세요!",
        "attendance_required": 1 if row[5] is None else int(row[5] or 0),
        "image_url": row[6] or "",
        "color": row[7] or "57F287",
    }


def get_weekly_mission_settings(guild_id: int):
    c.execute(
        """
        SELECT mission_title, mission_description, chat_target, attendance_target,
               reward_point, reward_box, image_url, color
        FROM weekly_mission_settings
        WHERE guild_id=?
        """,
        (guild_id,)
    )
    row = c.fetchone()
    if not row:
        return {
            "title": "🗓️ 이번 주 주간미션",
            "description": "1주일 동안 꾸준히 활동하고 주간 보상을 받아가세요!",
            "chat_target": 100,
            "attendance_target": 3,
            "reward_point": 3000,
            "reward_box": 3,
            "image_url": "",
            "color": "9B7CFF",
        }
    return {
        "title": row[0] or "🗓️ 이번 주 주간미션",
        "description": row[1] or "1주일 동안 꾸준히 활동하고 주간 보상을 받아가세요!",
        "chat_target": max(1, int(row[2] or 100)),
        "attendance_target": max(0, int(row[3] or 3)),
        "reward_point": max(0, int(row[4] or 3000)),
        "reward_box": max(0, int(row[5] or 3)),
        "image_url": row[6] or "",
        "color": row[7] or "9B7CFF",
    }


def ensure_daily_mission_progress(guild_id: int, user_id: int):
    mission_date = today_key()
    c.execute(
        """
        SELECT message_count, attendance_done, claimed
        FROM daily_mission_progress
        WHERE guild_id=? AND user_id=? AND mission_date=?
        """,
        (guild_id, user_id, mission_date)
    )
    row = c.fetchone()

    c.execute("SELECT last_attendance FROM users WHERE guild_id=? AND user_id=?", (guild_id, user_id))
    attendance_row = c.fetchone()
    attendance_done_now = 1 if attendance_row and attendance_row[0] == mission_date else 0

    if row is None:
        c.execute(
            """
            INSERT OR IGNORE INTO daily_mission_progress(
                guild_id, user_id, mission_date, message_count, attendance_done, claimed
            ) VALUES (?, ?, ?, 0, ?, 0)
            """,
            (guild_id, user_id, mission_date, attendance_done_now)
        )
        conn.commit()
        return 0, attendance_done_now, 0

    message_count, attendance_done, claimed = row
    if attendance_done_now and not attendance_done:
        attendance_done = 1
        c.execute(
            "UPDATE daily_mission_progress SET attendance_done=1 WHERE guild_id=? AND user_id=? AND mission_date=?",
            (guild_id, user_id, mission_date)
        )
        conn.commit()
    return int(message_count or 0), int(attendance_done or 0), int(claimed or 0)


def ensure_weekly_mission_progress(guild_id: int, user_id: int):
    current_week = week_key()
    c.execute(
        """
        SELECT message_count, attendance_count, claimed
        FROM weekly_mission_progress
        WHERE guild_id=? AND user_id=? AND week_key=?
        """,
        (guild_id, user_id, current_week)
    )
    row = c.fetchone()
    if row is None:
        c.execute(
            """
            INSERT OR IGNORE INTO weekly_mission_progress(
                guild_id, user_id, week_key, message_count, attendance_count, claimed
            ) VALUES (?, ?, ?, 0, 0, 0)
            """,
            (guild_id, user_id, current_week)
        )
        conn.commit()
        return 0, 0, 0
    return int(row[0] or 0), int(row[1] or 0), int(row[2] or 0)


def add_daily_mission_message_progress(guild_id: int, user_id: int):
    mission_date = today_key()
    settings = get_daily_mission_settings(guild_id)
    message_count, attendance_done, claimed = ensure_daily_mission_progress(guild_id, user_id)
    if claimed or message_count >= settings["chat_target"]:
        return message_count, attendance_done, claimed
    message_count += 1
    c.execute(
        """
        UPDATE daily_mission_progress
        SET message_count=?
        WHERE guild_id=? AND user_id=? AND mission_date=?
        """,
        (message_count, guild_id, user_id, mission_date)
    )
    conn.commit()
    return message_count, attendance_done, claimed


def add_weekly_mission_message_progress(guild_id: int, user_id: int):
    current_week = week_key()
    settings = get_weekly_mission_settings(guild_id)
    message_count, attendance_count, claimed = ensure_weekly_mission_progress(guild_id, user_id)
    # 주간미션 1등 칭호는 “많이 사용한 사람” 기준이라 목표 달성/보상 수령 후에도 카운트합니다.
    message_count += 1
    c.execute(
        """
        UPDATE weekly_mission_progress
        SET message_count=?
        WHERE guild_id=? AND user_id=? AND week_key=?
        """,
        (message_count, guild_id, user_id, current_week)
    )
    conn.commit()
    return message_count, attendance_count, claimed


def mark_daily_mission_attendance(guild_id: int, user_id: int):
    mission_date = today_key()
    ensure_daily_mission_progress(guild_id, user_id)
    c.execute(
        """
        UPDATE daily_mission_progress
        SET attendance_done=1
        WHERE guild_id=? AND user_id=? AND mission_date=?
        """,
        (guild_id, user_id, mission_date)
    )
    conn.commit()


def mark_weekly_mission_attendance(guild_id: int, user_id: int):
    current_week = week_key()
    today = today_key()
    ensure_weekly_mission_progress(guild_id, user_id)
    c.execute(
        """
        INSERT OR IGNORE INTO weekly_mission_attendance_days(guild_id, user_id, week_key, attendance_date)
        VALUES (?, ?, ?, ?)
        """,
        (guild_id, user_id, current_week, today)
    )
    c.execute(
        "SELECT COUNT(*) FROM weekly_mission_attendance_days WHERE guild_id=? AND user_id=? AND week_key=?",
        (guild_id, user_id, current_week)
    )
    attendance_count = int(c.fetchone()[0] or 0)
    c.execute(
        "UPDATE weekly_mission_progress SET attendance_count=? WHERE guild_id=? AND user_id=? AND week_key=?",
        (attendance_count, guild_id, user_id, current_week)
    )
    conn.commit()


def mission_progress_bar(current: int, target: int):
    target = max(1, int(target or 1))
    progress_bar_count = min(10, int((min(current, target) / target) * 10))
    return "▰" * progress_bar_count + "▱" * (10 - progress_bar_count)


def _apply_optional_embed_media(embed: discord.Embed, image_url: str = "", footer: str = ""):
    if image_url:
        safe = safe_url(image_url)
        if safe:
            embed.set_image(url=safe)
    if footer:
        embed.set_footer(text=footer[:2048])


def build_daily_mission_embed(guild_id: int, user: discord.User):
    settings = get_daily_mission_settings(guild_id)
    message_count, attendance_done, claimed = ensure_daily_mission_progress(guild_id, user.id)
    chat_done = message_count >= settings["chat_target"]
    attendance_ok = bool(attendance_done) if settings["attendance_required"] else True

    embed = discord.Embed(
        title=settings["title"][:256],
        description=(
            f"{settings['description']}\n\n"
            f"{user.mention}님의 오늘 미션 진행도입니다.\n\n"
            f"💬 채팅 미션: **{min(message_count, settings['chat_target'])}/{settings['chat_target']}회**\n"
            f"{mission_progress_bar(message_count, settings['chat_target'])}\n"
            f"📅 출석 미션: {'완료 ✅' if attendance_ok else '미완료 ❌'}\n\n"
            f"🎁 완료 보상: **{settings['reward_point']:,}P + 랜덤박스 {settings['reward_box']}개**"
        )[:4096],
        color=discord.Color.green() if chat_done and attendance_ok and not claimed else normalize_embed_color(settings.get("color", "57F287"))
    )
    if claimed:
        embed.add_field(name="보상 상태", value="오늘 미션 보상을 이미 받았습니다. ✅", inline=False)
    elif chat_done and attendance_ok:
        embed.add_field(name="보상 상태", value="아래 `일일 보상받기` 버튼으로 보상을 받을 수 있어요!", inline=False)
    else:
        todo = [f"채팅 {settings['chat_target']}회"]
        if settings["attendance_required"]:
            todo.append("출석 1회")
        embed.add_field(name="남은 할 일", value=" / ".join(todo) + "를 완료하면 보상을 받을 수 있어요.", inline=False)
    _apply_optional_embed_media(embed, settings.get("image_url", ""), "일일미션은 매일 날짜가 바뀌면 다시 진행할 수 있습니다.")
    return embed


