async def send_daily_mission_status(interaction: discord.Interaction, user: discord.User = None):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)
    user = user or interaction.user
    embed = build_daily_mission_embed(interaction.guild.id, user)
    await safe_interaction_send(interaction, embed=embed, view=MissionPanelView(), ephemeral=True)


