class MissionSettingsModal(discord.ui.Modal):
    def __init__(self, mission_kind: str, guild_id: int):
        self.mission_kind = mission_kind
        self.guild_id = guild_id
        current = get_weekly_mission_settings(guild_id) if mission_kind == "weekly" else get_daily_mission_settings(guild_id)
        super().__init__(title="주간미션 수정" if mission_kind == "weekly" else "일일미션 수정")
        self.title_input = discord.ui.TextInput(label="미션 제목", default=current["title"][:100], max_length=100, required=True)
        self.desc_input = discord.ui.TextInput(label="미션 설명", default=current["description"][:900], style=discord.TextStyle.paragraph, max_length=900, required=True)
        self.chat_input = discord.ui.TextInput(label="채팅 목표 횟수", default=str(current["chat_target"]), max_length=8, required=True)
        target_default = str(current["attendance_target"] if mission_kind == "weekly" else current["attendance_required"])
        target_label = "출석 목표 일수" if mission_kind == "weekly" else "출석 필요 여부 1=필요 / 0=안함"
        self.attendance_input = discord.ui.TextInput(label=target_label, default=target_default, max_length=8, required=True)
        self.reward_input = discord.ui.TextInput(label="보상 포인트,랜덤박스", default=f"{current['reward_point']},{current['reward_box']}", placeholder="예: 500,1", max_length=30, required=True)
        for item in [self.title_input, self.desc_input, self.chat_input, self.attendance_input, self.reward_input]:
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        if await reject_if_not_bot_manager(interaction):
            return
        chat_target = _parse_int_or_default(self.chat_input.value, 20 if self.mission_kind == "daily" else 100, 1)
        attendance_target = _parse_int_or_default(self.attendance_input.value, 1 if self.mission_kind == "daily" else 3, 0)
        reward_point, reward_box = parse_reward_bundle(self.reward_input.value, 500 if self.mission_kind == "daily" else 3000, 1 if self.mission_kind == "daily" else 3)
        now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        if self.mission_kind == "weekly":
            c.execute(
                """
                INSERT INTO weekly_mission_settings(
                    guild_id, mission_title, mission_description, chat_target, attendance_target,
                    reward_point, reward_box, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(guild_id) DO UPDATE SET
                    mission_title=excluded.mission_title,
                    mission_description=excluded.mission_description,
                    chat_target=excluded.chat_target,
                    attendance_target=excluded.attendance_target,
                    reward_point=excluded.reward_point,
                    reward_box=excluded.reward_box,
                    updated_at=excluded.updated_at
                """,
                (interaction.guild.id, str(self.title_input.value), str(self.desc_input.value), chat_target, attendance_target, reward_point, reward_box, now)
            )
            label = "주간미션"
        else:
            c.execute(
                """
                INSERT INTO daily_mission_settings(
                    guild_id, chat_target, reward_point, reward_box, mission_title,
                    mission_description, attendance_required, updated_at
                ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(guild_id) DO UPDATE SET
                    chat_target=excluded.chat_target,
                    reward_point=excluded.reward_point,
                    reward_box=excluded.reward_box,
                    mission_title=excluded.mission_title,
                    mission_description=excluded.mission_description,
                    attendance_required=excluded.attendance_required,
                    updated_at=excluded.updated_at
                """,
                (interaction.guild.id, chat_target, reward_point, reward_box, str(self.title_input.value), str(self.desc_input.value), 1 if attendance_target else 0, now)
            )
            label = "일일미션"
        conn.commit()
        await safe_interaction_send(interaction, f"✅ {label} 설정을 저장했어요. `/미션`에서 바로 확인할 수 있습니다.", ephemeral=True)


