async def claim_daily_mission_reward_interaction(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    guild_id = interaction.guild.id
    user_id = interaction.user.id
    mission_date = today_key()
    settings = get_daily_mission_settings(guild_id)
    message_count, attendance_done, claimed = ensure_daily_mission_progress(guild_id, user_id)
    attendance_ok = bool(attendance_done) if settings["attendance_required"] else True

    if claimed:
        return await safe_interaction_send(interaction, "❌ 오늘 미션 보상은 이미 받았습니다.", ephemeral=True)
    if message_count < settings["chat_target"] or not attendance_ok:
        return await safe_interaction_send(interaction, 
            f"❌ 아직 일일미션이 완료되지 않았습니다.\n채팅: **{message_count}/{settings['chat_target']}회**\n출석: {'완료' if attendance_ok else '미완료'}",
            ephemeral=True
        )

    now_point = get_user_point(guild_id, user_id)
    set_user_point(guild_id, user_id, now_point + settings["reward_point"])
    if settings["reward_box"] > 0:
        c.execute("INSERT INTO inventory VALUES (?, ?, ?)", (user_id, "랜덤박스", settings["reward_box"]))
    c.execute(
        """
        UPDATE daily_mission_progress
        SET claimed=1, claimed_at=?
        WHERE guild_id=? AND user_id=? AND mission_date=?
        """,
        (datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S"), guild_id, user_id, mission_date)
    )
    conn.commit()

    embed = discord.Embed(
        title="🎁 일일미션 보상 지급 완료!",
        description=(
            f"{interaction.user.mention}님 오늘 미션을 완료했어요!\n\n"
            f"💰 포인트: **+{settings['reward_point']:,}P**\n"
            f"🎁 랜덤박스: **+{settings['reward_box']}개**\n"
            f"💎 현재 포인트: **{get_user_point(guild_id, user_id):,}P**"
        ),
        color=discord.Color.green()
    )
    await safe_interaction_send(interaction, embed=embed)
    await send_log(interaction.guild, f"🎯 일일미션 보상 지급\n대상: {interaction.user.mention}\n보상: {settings['reward_point']}P + 랜덤박스 {settings['reward_box']}개", "general")


async def claim_weekly_mission_reward_interaction(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    guild_id = interaction.guild.id
    user_id = interaction.user.id
    current_week = week_key()
    settings = get_weekly_mission_settings(guild_id)
    message_count, attendance_count, claimed = ensure_weekly_mission_progress(guild_id, user_id)

    if claimed:
        return await safe_interaction_send(interaction, "❌ 이번 주 미션 보상은 이미 받았습니다.", ephemeral=True)
    if message_count < settings["chat_target"] or attendance_count < settings["attendance_target"]:
        return await safe_interaction_send(interaction, 
            f"❌ 아직 주간미션이 완료되지 않았습니다.\n채팅: **{message_count}/{settings['chat_target']}회**\n출석: **{attendance_count}/{settings['attendance_target']}일**",
            ephemeral=True
        )

    now_point = get_user_point(guild_id, user_id)
    set_user_point(guild_id, user_id, now_point + settings["reward_point"])
    if settings["reward_box"] > 0:
        c.execute("INSERT INTO inventory VALUES (?, ?, ?)", (user_id, "랜덤박스", settings["reward_box"]))
    c.execute(
        """
        UPDATE weekly_mission_progress
        SET claimed=1, claimed_at=?
        WHERE guild_id=? AND user_id=? AND week_key=?
        """,
        (datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S"), guild_id, user_id, current_week)
    )
    conn.commit()

    embed = discord.Embed(
        title="🎁 주간미션 보상 지급 완료!",
        description=(
            f"{interaction.user.mention}님 이번 주 미션을 완료했어요!\n\n"
            f"💰 포인트: **+{settings['reward_point']:,}P**\n"
            f"🎁 랜덤박스: **+{settings['reward_box']}개**\n"
            f"💎 현재 포인트: **{get_user_point(guild_id, user_id):,}P**"
        ),
        color=discord.Color.green()
    )
    await safe_interaction_send(interaction, embed=embed)
    await send_log(interaction.guild, f"🗓️ 주간미션 보상 지급\n대상: {interaction.user.mention}\n보상: {settings['reward_point']}P + 랜덤박스 {settings['reward_box']}개", "general")


