async def process_coupon_use(interaction: discord.Interaction, raw_code: str):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

    code = normalize_coupon_code(raw_code)
    if not code:
        return await safe_interaction_send(interaction, "❌ 쿠폰 코드를 입력해주세요.", ephemeral=True)

    c.execute(
        """
        SELECT reward_point, item_name, item_amount, max_uses, used_count, expires_at, is_active
        FROM coupon_codes
        WHERE guild_id=? AND code=?
        """,
        (interaction.guild.id, code)
    )
    row = c.fetchone()
    if not row:
        return await safe_interaction_send(interaction, "❌ 존재하지 않는 쿠폰입니다.", ephemeral=True)

    reward_point, item_name, item_amount, max_uses, used_count, expires_at, is_active = row
    if not is_active:
        return await safe_interaction_send(interaction, "❌ 비활성화된 쿠폰입니다.", ephemeral=True)
    if expires_at:
        try:
            expire_dt = datetime.datetime.strptime(expires_at, "%Y-%m-%d %H:%M:%S")
            if datetime.datetime.now() > expire_dt:
                return await safe_interaction_send(interaction, "❌ 만료된 쿠폰입니다.", ephemeral=True)
        except ValueError:
            pass
    if used_count >= max_uses:
        return await safe_interaction_send(interaction, "❌ 사용 가능 횟수가 모두 소진된 쿠폰입니다.", ephemeral=True)

    c.execute(
        "SELECT 1 FROM coupon_claims WHERE guild_id=? AND code=? AND user_id=?",
        (interaction.guild.id, code, interaction.user.id)
    )
    if c.fetchone():
        return await safe_interaction_send(interaction, "❌ 이미 사용한 쿠폰입니다.", ephemeral=True)

    reward_lines = []
    if reward_point and reward_point > 0:
        current = get_user_point(interaction.guild.id, interaction.user.id)
        set_user_point(interaction.guild.id, interaction.user.id, current + int(reward_point))
        reward_lines.append(f"💰 {int(reward_point):,}P")
    if item_name and item_amount and int(item_amount) > 0:
        c.execute("INSERT INTO inventory VALUES (?, ?, ?)", (interaction.user.id, normalize_shop_item(item_name), int(item_amount)))
        reward_lines.append(f"🎁 {normalize_shop_item(item_name)} {int(item_amount)}개")

    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute("INSERT INTO coupon_claims(guild_id, code, user_id, claimed_at) VALUES (?, ?, ?, ?)", (interaction.guild.id, code, interaction.user.id, now))
    c.execute("UPDATE coupon_codes SET used_count=used_count+1 WHERE guild_id=? AND code=?", (interaction.guild.id, code))
    conn.commit()

    embed = discord.Embed(
        title="🎟️ 쿠폰 사용 완료!",
        description=(
            f"쿠폰 `{code}` 사용 완료!\n\n"
            f"받은 보상\n" + "\n".join(reward_lines)
        ),
        color=discord.Color.gold()
    )
    await safe_interaction_send(interaction, embed=embed)
    await send_log(interaction.guild, f"🎟️ 쿠폰 사용\n유저: {interaction.user.mention}\n코드: `{code}`\n보상: {' / '.join(reward_lines)}", "general")


class CouponUseModal(discord.ui.Modal):
    def __init__(self):
        super().__init__(title="쿠폰 코드 입력")
        self.code = discord.ui.TextInput(label="쿠폰 코드", placeholder="예: WELCOME1000", max_length=30, required=True)
        self.add_item(self.code)

    async def on_submit(self, interaction: discord.Interaction):
        await process_coupon_use(interaction, self.code.value)


class CouponCreateModal(discord.ui.Modal):
    def __init__(self):
        super().__init__(title="쿠폰 생성")
        self.code = discord.ui.TextInput(label="쿠폰 코드", placeholder="예: WELCOME1000", max_length=30, required=True)
        self.point = discord.ui.TextInput(label="포인트 보상", placeholder="예: 1000 / 없으면 0", default="0", max_length=12, required=True)
        self.item_name = discord.ui.TextInput(label="아이템명", placeholder="예: 랜덤박스 / 없으면 비워두기", required=False, max_length=50)
        self.item_amount = discord.ui.TextInput(label="아이템 개수", placeholder="예: 1 / 없으면 0", default="0", max_length=8, required=True)
        self.uses_expire = discord.ui.TextInput(label="사용횟수,만료일", placeholder="예: 10,2026-06-30 23:59 / 만료일 생략 가능", default="1,", max_length=40, required=True)
        for item in [self.code, self.point, self.item_name, self.item_amount, self.uses_expire]:
            self.add_item(item)

    async def on_submit(self, interaction: discord.Interaction):
        if await reject_if_not_bot_manager(interaction):
            return
        if interaction.guild is None:
            return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)
        code = normalize_coupon_code(self.code.value)
        if not re.fullmatch(r"[A-Z0-9_-]{3,30}", code):
            return await safe_interaction_send(interaction, "❌ 쿠폰 코드는 영문/숫자/_/- 조합 3~30자로 입력해주세요.", ephemeral=True)
        point = _parse_int_or_default(self.point.value, 0, 0)
        item_name = normalize_shop_item(str(self.item_name.value).strip()) if str(self.item_name.value).strip() else ""
        item_amount = _parse_int_or_default(self.item_amount.value, 0, 0)
        usage_parts = [x.strip() for x in str(self.uses_expire.value).split(",", 1)]
        max_uses = _parse_int_or_default(usage_parts[0] if usage_parts else 1, 1, 1)
        expires_at = parse_coupon_expire(usage_parts[1] if len(usage_parts) >= 2 else "")
        if expires_at == "INVALID":
            return await safe_interaction_send(interaction, "❌ 만료일 형식이 올바르지 않습니다. 예: `2026-06-30 23:59`", ephemeral=True)
        if point <= 0 and (not item_name or item_amount <= 0):
            return await safe_interaction_send(interaction, "❌ 포인트 또는 아이템 보상 중 하나는 꼭 있어야 합니다.", ephemeral=True)
        now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        c.execute(
            """
            INSERT OR REPLACE INTO coupon_codes(
                guild_id, code, reward_point, item_name, item_amount,
                max_uses, used_count, expires_at, is_active, created_by, created_at
            ) VALUES (?, ?, ?, ?, ?, ?, COALESCE((SELECT used_count FROM coupon_codes WHERE guild_id=? AND code=?), 0), ?, 1, ?, ?)
            """,
            (interaction.guild.id, code, point, item_name, item_amount, max_uses, interaction.guild.id, code, expires_at, interaction.user.id, now)
        )
        conn.commit()
        rewards = []
        if point > 0:
            rewards.append(f"💰 {point:,}P")
        if item_name and item_amount > 0:
            rewards.append(f"🎁 {item_name} {item_amount}개")
        await safe_interaction_send(interaction, 
            embed=discord.Embed(
                title="🎟️ 쿠폰 생성 완료",
                description=f"코드: `{code}`\n보상: {' / '.join(rewards)}\n사용 가능 횟수: **{max_uses}회**\n만료일: **{expires_at or '없음'}**",
                color=discord.Color.gold(),
            ),
            ephemeral=True,
        )
        await send_log(interaction.guild, f"🎟️ 쿠폰 생성\n관리자: {interaction.user.mention}\n코드: `{code}`\n보상: {' / '.join(rewards)}", "general")


class CouponDeleteModal(discord.ui.Modal):
    def __init__(self):
        super().__init__(title="쿠폰 비활성화")
        self.code = discord.ui.TextInput(label="비활성화할 쿠폰 코드", placeholder="예: WELCOME1000", max_length=30, required=True)
        self.add_item(self.code)

    async def on_submit(self, interaction: discord.Interaction):
        if await reject_if_not_bot_manager(interaction):
            return
        code = normalize_coupon_code(self.code.value)
        c.execute("UPDATE coupon_codes SET is_active=0 WHERE guild_id=? AND code=?", (interaction.guild.id, code))
        changed = c.rowcount
        conn.commit()
        if not changed:
            return await safe_interaction_send(interaction, "❌ 해당 쿠폰을 찾을 수 없습니다.", ephemeral=True)
        await safe_interaction_send(interaction, f"✅ 쿠폰 `{code}`를 비활성화했습니다.", ephemeral=True)
        await send_log(interaction.guild, f"🎟️ 쿠폰 비활성화\n관리자: {interaction.user.mention}\n코드: `{code}`", "general")


