class TitleAdminModal(discord.ui.Modal):
    def __init__(self, mode: str):
        self.mode = mode
        modal_title = "👑 관리자 칭호 지급" if mode == "grant" else "🗑️ 관리자 칭호 회수"
        super().__init__(title=modal_title)
        self.user_input = discord.ui.TextInput(
            label="유저 멘션 또는 유저 ID",
            placeholder="예: @냥이 또는 123456789012345678",
            required=True,
            max_length=80
        )
        self.title_input = discord.ui.TextInput(
            label="칭호 이름",
            placeholder="예: 서버수호자, 이벤트왕, 레전드",
            required=True,
            max_length=30
        )
        self.add_item(self.user_input)
        self.add_item(self.title_input)

    async def on_submit(self, interaction: discord.Interaction):
        if await reject_if_not_bot_manager(interaction):
            return
        if interaction.guild is None:
            return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)

        user_id = parse_discord_user_id(str(self.user_input.value))
        if not user_id:
            return await safe_interaction_send(interaction, "❌ 유저 멘션 또는 유저 ID를 정확히 입력해주세요.", ephemeral=True)

        member = interaction.guild.get_member(user_id)
        if member is None:
            try:
                member = await interaction.guild.fetch_member(user_id)
            except (discord.NotFound, discord.HTTPException):
                member = None

        if member is None:
            return await safe_interaction_send(interaction, "❌ 해당 유저를 서버에서 찾을 수 없습니다.", ephemeral=True)

        title_name = normalize_title_name(str(self.title_input.value))
        if not title_name:
            return await safe_interaction_send(interaction, "❌ 칭호 이름을 입력해주세요.", ephemeral=True)

        if self.mode == "grant":
            changed = add_user_title(interaction.guild.id, member.id, title_name)
            result = "지급했습니다" if changed else "이미 보유 중입니다"
            await safe_interaction_send(interaction, f"✅ {member.mention}님에게 `{title_name}` 칭호를 {result}.", ephemeral=True)
            await send_log(interaction.guild, f"🏷️ 칭호 지급\n관리자: {interaction.user.mention}\n대상: {member.mention}\n칭호: `{title_name}`", "general")
        else:
            changed = remove_user_title(interaction.guild.id, member.id, title_name)
            if not changed:
                return await safe_interaction_send(interaction, "❌ 해당 유저가 그 칭호를 보유하고 있지 않습니다.", ephemeral=True)
            await safe_interaction_send(interaction, f"✅ {member.mention}님의 `{title_name}` 칭호를 회수했습니다.", ephemeral=True)
            await send_log(interaction.guild, f"🏷️ 칭호 회수\n관리자: {interaction.user.mention}\n대상: {member.mention}\n칭호: `{title_name}`", "general")


