def _target_channel_text(target_channel_id: int):
    return f"<#{target_channel_id}>" if target_channel_id else "없음"


def _make_category_embed(title: str, description: str, target_channel_id: int):
    embed = discord.Embed(
        title=title,
        description=(
            f"🎯 **전송 대상 채널:** {_target_channel_text(target_channel_id)}\n\n"
            f"{description}"
        ),
        color=BOT_COLOR
    )
    if bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)
    return embed


class FriendEmbedItemButton(discord.ui.Button):
    """친목섭 카테고리 안에 들어가는 실제 채널/패널 임베드 수정 버튼입니다."""

    def __init__(self, item: dict, target_channel_id: int = 0, row: int = 0):
        self.item = item
        self.target_channel_id = target_channel_id

        if item.get("kind") == "panel":
            meta = PANEL_CUSTOM_EMBED_DISPLAY_META.get(item.get("panel_key"), {})
            label = meta.get("name", item.get("panel_key", "패널"))[:80]
            emoji = meta.get("emoji", "🧩")
            style = UnifiedPanelCustomEmbedButton.STYLE_BY_PANEL_KEY.get(item.get("panel_key"), discord.ButtonStyle.gray)
        else:
            label = item.get("label", "임베드")[:80]
            emoji = item.get("emoji")
            style = item.get("style", discord.ButtonStyle.gray)

        super().__init__(label=label, emoji=emoji, style=style, row=row)

    async def callback(self, interaction: discord.Interaction):
        if await reject_if_not_setup_manager(interaction):
            return

        kind = self.item.get("kind")
        if kind == "welcome":
            return await interaction.response.send_modal(
                UnifiedWelcomeEmbedEditModal(interaction.guild.id, self.target_channel_id)
            )

        if kind == "auto":
            embed_type = self.item.get("embed_type")
            display_name = self.item.get("label", embed_type)
            if not embed_type:
                return await safe_interaction_send(interaction, "❌ 연결되지 않은 자동 임베드입니다.", ephemeral=True)
            return await interaction.response.send_modal(
                UnifiedAutoEmbedEditModal(interaction.guild.id, embed_type, display_name, self.target_channel_id)
            )

        if kind == "panel":
            panel_key = self.item.get("panel_key")
            embed_type = PANEL_CUSTOM_EMBED_TYPES.get(panel_key, "")
            meta = PANEL_CUSTOM_EMBED_DISPLAY_META.get(panel_key, {})
            display_name = meta.get("name", panel_key)
            if not embed_type:
                return await safe_interaction_send(interaction, "❌ 아직 연결되지 않은 패널 임베드입니다.", ephemeral=True)
            return await interaction.response.send_modal(
                UnifiedAutoEmbedEditModal(interaction.guild.id, embed_type, display_name, self.target_channel_id)
            )

        await safe_interaction_send(interaction, "❌ 알 수 없는 임베드 항목입니다.", ephemeral=True)


class SupportEmbedItemButton(discord.ui.Button):
    """지원서버 카테고리 안에 들어가는 실제 채널 임베드 수정 버튼입니다."""

    STYLE_BY_SUPPORT_KEY = {
        "support_ticket": discord.ButtonStyle.green,
        "support_notice": discord.ButtonStyle.blurple,
        "support_rules": discord.ButtonStyle.blurple,
        "support_usage": discord.ButtonStyle.blurple,
        "support_commands": discord.ButtonStyle.gray,
        "support_faq": discord.ButtonStyle.gray,
        "support_welcome": discord.ButtonStyle.green,
        "support_boost": discord.ButtonStyle.green,
        "support_update": discord.ButtonStyle.green,
        "support_patch": discord.ButtonStyle.blurple,
        "support_status": discord.ButtonStyle.green,
        "support_diary": discord.ButtonStyle.gray,
        "support_music_test": discord.ButtonStyle.blurple,
        "support_tts_test": discord.ButtonStyle.green,
        "support_enhance_test": discord.ButtonStyle.gray,
        "support_economy_test": discord.ButtonStyle.green,
        "support_event_test": discord.ButtonStyle.blurple,
    }

    def __init__(self, support_key: str, target_channel_id: int = 0, row: int = 0):
        meta = SUPPORT_PANEL_CUSTOM_EMBED_DISPLAY_META.get(support_key, {})
        super().__init__(
            label=meta.get("name", support_key)[:80],
            emoji=meta.get("emoji"),
            style=self.STYLE_BY_SUPPORT_KEY.get(support_key, discord.ButtonStyle.gray),
            row=row,
        )
        self.support_key = support_key
        self.embed_type = SUPPORT_PANEL_CUSTOM_EMBED_TYPES.get(support_key, "")
        self.display_name = meta.get("name", support_key)
        self.target_channel_id = target_channel_id

    async def callback(self, interaction: discord.Interaction):
        if await reject_if_not_support_embed_owner(interaction):
            return
        if not self.embed_type:
            return await safe_interaction_send(interaction, "❌ 아직 연결되지 않은 지원서버 임베드입니다.", ephemeral=True)
        await interaction.response.send_modal(
            UnifiedAutoEmbedEditModal(
                interaction.guild.id,
                self.embed_type,
                self.display_name,
                self.target_channel_id,
            )
        )


