# =========================
# 커스텀 음성 봇 시스템
# =========================
# Discord 정책상 한 봇 계정이 여러 명의 봇처럼 동시에 음성방에 들어갈 수는 없습니다.
# 그래서 /커스텀은 CUSTOM_BOT_TOKEN_1~3 환경변수에 등록한 보조 봇 계정을
# 서버별로 이름/입장 음성방을 설정해서 관리하는 방식으로 동작합니다.

CUSTOM_BOT_TOKENS = {
    1: os.getenv("CUSTOM_BOT_TOKEN_1", "").strip(),
    2: os.getenv("CUSTOM_BOT_TOKEN_2", "").strip(),
    3: os.getenv("CUSTOM_BOT_TOKEN_3", "").strip(),
}

TTS_BOT_TOKEN = os.getenv("TTS_BOT_TOKEN", "").strip()


class TTSSubBotClient(discord.Client):
    """TTS 전용 서브봇입니다. 메인봇은 명령어/채팅 감지를 담당하고, 이 봇은 음성 입장과 TTS 재생을 담당합니다."""

    def __init__(self):
        tts_intents = discord.Intents.default()
        tts_intents.guilds = True
        tts_intents.voice_states = True
        super().__init__(intents=tts_intents)

    async def on_ready(self):
        print(f"✅ TTS 서브봇 로그인 완료: {self.user}")

    async def on_voice_state_update(self, member: discord.Member, before: discord.VoiceState, after: discord.VoiceState):
        # TTS 서브봇 자신이 음성방을 이동하면 별도 안내 없이 조용히 유지합니다.
        return


tts_sub_bot = TTSSubBotClient()


def is_tts_subbot_enabled() -> bool:
    return bool(TTS_BOT_TOKEN and tts_sub_bot and tts_sub_bot.is_ready())


def get_tts_subbot_guild(guild_id: int):
    if not is_tts_subbot_enabled():
        return None
    try:
        return tts_sub_bot.get_guild(int(guild_id))
    except Exception:
        return None


async def connect_tts_voice_client(guild: discord.Guild, voice_channel: discord.VoiceChannel):
    """TTS_BOT_TOKEN이 있으면 TTS 서브봇을, 없으면 메인봇을 음성방에 연결합니다."""
    if guild is None or voice_channel is None:
        return None, "❌ TTS 통방을 찾지 못했습니다."

    # TTS 서브봇 토큰이 있으면 서브봇으로 재생합니다.
    if TTS_BOT_TOKEN:
        if not tts_sub_bot.is_ready():
            return None, "❌ TTS 서브봇이 아직 로그인 중입니다. 잠시 후 다시 시도해주세요."
        sub_guild = tts_sub_bot.get_guild(guild.id)
        if sub_guild is None:
            return None, "❌ TTS 서브봇이 이 서버에 초대되어 있지 않습니다. TTS 서브봇을 서버에 초대해주세요."
        sub_channel = sub_guild.get_channel(voice_channel.id)
        if not isinstance(sub_channel, discord.VoiceChannel):
            return None, "❌ TTS 서브봇이 이 음성 채널을 찾지 못했습니다. 권한을 확인해주세요."

        existing = discord.utils.get(tts_sub_bot.voice_clients, guild=sub_guild)
        if existing is None:
            return await sub_channel.connect(), None
        if existing.channel and existing.channel.id != sub_channel.id:
            await existing.move_to(sub_channel)
        return existing, None

    # TTS 서브봇 토큰이 없으면 기존처럼 메인봇이 재생합니다.
    existing = guild.voice_client
    if existing is None:
        return await voice_channel.connect(), None
    if existing.channel != voice_channel:
        await existing.move_to(voice_channel)
    return existing, None


async def ensure_tts_subbot_join_voice(guild: discord.Guild, voice_channel: discord.VoiceChannel):
    """유저가 TTS 통방에 들어오면 TTS 서브봇을 자동 입장시킵니다."""
    if not TTS_BOT_TOKEN or not tts_sub_bot.is_ready():
        return False
    if guild is None or voice_channel is None:
        return False
    if voice_channel.name not in TTS_VOICE_CHANNEL_NAMES:
        return False
    voice_client, error = await connect_tts_voice_client(guild, voice_channel)
    if error:
        return False
    return voice_client is not None


async def disconnect_empty_tts_subbot_for_guild(guild: discord.Guild):
    """TTS 서브봇이 있는 통방에 사람이 없으면 자동 퇴장합니다."""
    if not TTS_BOT_TOKEN or not tts_sub_bot.is_ready() or guild is None:
        return False
    sub_guild = tts_sub_bot.get_guild(guild.id)
    if sub_guild is None:
        return False
    changed = False
    for vc in list(tts_sub_bot.voice_clients):
        try:
            if vc.guild.id != sub_guild.id or vc.channel is None:
                continue
            humans = [m for m in vc.channel.members if not m.bot]
            if humans:
                continue
            if vc.is_playing() or vc.is_paused():
                vc.stop()
            channel_name = vc.channel.name
            await vc.disconnect(force=True)
            changed = True
            try:
                await send_log(guild, f"👋 TTS 서브봇 자동 퇴장\n사유: 음성 채널에 유저가 없어 자동 퇴장했습니다.\n채널: `{channel_name}`", "voice")
            except Exception:
                pass
        except Exception as e:
            print(f"❌ TTS 서브봇 자동 퇴장 실패: {e}")
    return changed

CUSTOM_BOT_CLIENTS = {}

def ensure_custom_bot_tables():
    c.execute("""
    CREATE TABLE IF NOT EXISTS custom_voice_bots (
        guild_id INTEGER,
        slot INTEGER,
        bot_name TEXT,
        avatar_url TEXT,
        voice_channel_id INTEGER DEFAULT 0,
        enabled INTEGER DEFAULT 1,
        created_by INTEGER DEFAULT 0,
        updated_at TEXT,
        PRIMARY KEY (guild_id, slot)
    )
    """)
    conn.commit()


ensure_custom_bot_tables()


def get_custom_voice_bot_rows(guild_id: int):
    c.execute(
        """
        SELECT slot, bot_name, avatar_url, voice_channel_id, enabled, updated_at
        FROM custom_voice_bots
        WHERE guild_id=?
        ORDER BY slot ASC
        """,
        (guild_id,)
    )
    return c.fetchall()


def get_custom_voice_bot_setting(guild_id: int, slot: int):
    c.execute(
        """
        SELECT slot, bot_name, avatar_url, voice_channel_id, enabled, updated_at
        FROM custom_voice_bots
        WHERE guild_id=? AND slot=?
        """,
        (guild_id, slot)
    )
    return c.fetchone()


def save_custom_voice_bot_setting(guild_id: int, slot: int, bot_name: str, avatar_url: str, voice_channel_id: int, created_by: int):
    now = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    c.execute(
        """
        INSERT INTO custom_voice_bots(guild_id, slot, bot_name, avatar_url, voice_channel_id, enabled, created_by, updated_at)
        VALUES (?, ?, ?, ?, ?, 1, ?, ?)
        ON CONFLICT(guild_id, slot) DO UPDATE SET
            bot_name=excluded.bot_name,
            avatar_url=excluded.avatar_url,
            voice_channel_id=excluded.voice_channel_id,
            enabled=1,
            created_by=excluded.created_by,
            updated_at=excluded.updated_at
        """,
        (guild_id, slot, bot_name[:32], avatar_url[:500], int(voice_channel_id or 0), created_by, now)
    )
    conn.commit()


def resolve_custom_voice_channel(guild: discord.Guild, raw_value: str):
    value = (raw_value or "").strip()
    if not guild or not value:
        return None
    channel_id_text = value.replace("<#", "").replace(">", "").strip()
    if channel_id_text.isdigit():
        channel = guild.get_channel(int(channel_id_text))
        if isinstance(channel, discord.VoiceChannel):
            return channel
    lowered = value.lower().replace(" ", "")
    for channel in guild.voice_channels:
        if channel.name == value or (channel.name or "").lower().replace(" ", "") == lowered:
            return channel
    for channel in guild.voice_channels:
        if lowered and lowered in (channel.name or "").lower().replace(" ", ""):
            return channel
    return None


class CustomVoiceBotClient(discord.Client):
    def __init__(self, slot: int):
        custom_intents = discord.Intents.default()
        custom_intents.guilds = True
        custom_intents.voice_states = True
        super().__init__(intents=custom_intents)
        self.slot = slot

    async def on_ready(self):
        print(f"✅ 커스텀 봇 {self.slot}번 로그인: {self.user}")
        # 이제 커스텀 봇은 저장된 설정으로 자동 입장하지 않습니다.
        # 관리자가 /커스텀에서 직접 현재 통방으로 초대했을 때만 입장합니다.

    async def on_voice_state_update(self, member: discord.Member, before: discord.VoiceState, after: discord.VoiceState):
        # 관리자가 커스텀 봇을 다른 통방으로 이동시킨 경우에도,
        # 이동한 통방의 채팅채널에 뮤직패널을 자동으로 준비합니다.
        if self.user is None or member.id != self.user.id:
            return
        if before.channel == after.channel or after.channel is None:
            return
        if not isinstance(after.channel, discord.VoiceChannel):
            return
        try:
            main_guild = bot.get_guild(after.channel.guild.id) or after.channel.guild
            main_voice_channel = main_guild.get_channel(after.channel.id) if main_guild else after.channel
            if not isinstance(main_voice_channel, discord.VoiceChannel):
                main_voice_channel = after.channel
            await send_custom_music_panel_to_voice_channel(main_guild, self.slot, main_voice_channel, None, connect=False)
        except Exception as e:
            print(f"⚠️ 커스텀 봇 {self.slot}번 통방 패널 자동 전송 실패: {e}")

async def custom_bot_connect_slot(slot: int, guild_id: int, voice_channel_id: int, nickname: str):
    client = CUSTOM_BOT_CLIENTS.get(slot)
    if not client:
        return f"⚠️ {slot}번 보조 봇 토큰이 없습니다. Render 환경변수 `CUSTOM_BOT_TOKEN_{slot}`에 보조 봇 토큰을 넣어주세요."
    if not client.is_ready():
        return f"⚠️ {slot}번 보조 봇이 아직 로그인 중입니다. 잠시 후 다시 눌러주세요."

    guild = client.get_guild(int(guild_id))
    if guild is None:
        return f"❌ {slot}번 보조 봇이 이 서버에 초대되어 있지 않습니다. 같은 서버에 초대해주세요."

    channel = guild.get_channel(int(voice_channel_id or 0))
    if not isinstance(channel, discord.VoiceChannel):
        return "❌ 선택한 통방/음성채널을 찾지 못했습니다. 먼저 통방에 들어간 뒤 다시 눌러주세요."

    try:
        member = guild.get_member(client.user.id)
        if member and nickname:
            await member.edit(nick=nickname[:32], reason="커스텀 봇 이름 설정")
    except (discord.Forbidden, discord.HTTPException):
        pass

    try:
        existing = None
        for vc in list(client.voice_clients):
            if vc.guild and vc.guild.id == guild.id:
                existing = vc
                break
        if existing:
            if existing.channel and existing.channel.id == channel.id:
                return f"✅ {slot}번 커스텀 봇이 이미 **{channel.name}**에 있어요."
            await existing.move_to(channel)
            return f"✅ {slot}번 커스텀 봇을 **{channel.name}**으로 이동했어요."
        await channel.connect(self_deaf=True, reconnect=True)
        return f"✅ {slot}번 커스텀 봇을 **{channel.name}**에 입장시켰어요."
    except discord.Forbidden:
        return "❌ 보조 봇에게 음성 채널 접속/말하기 권한이 없습니다."
    except Exception as e:
        return f"❌ 커스텀 봇 입장 실패: `{e}`"


async def custom_bot_disconnect_slot(slot: int, guild_id: int):
    client = CUSTOM_BOT_CLIENTS.get(slot)
    if not client:
        return f"⚠️ {slot}번 보조 봇 토큰이 없습니다."
    disconnected = False
    for vc in list(client.voice_clients):
        if vc.guild and vc.guild.id == guild_id:
            try:
                await vc.disconnect(force=True)
                disconnected = True
            except Exception:
                pass
    key = custom_music_key(slot, guild_id) if "custom_music_key" in globals() else (slot, guild_id)
    if "CUSTOM_MUSIC_QUEUES" in globals():
        CUSTOM_MUSIC_QUEUES.pop(key, None)
        CUSTOM_MUSIC_NOW_PLAYING.pop(key, None)
        CUSTOM_MUSIC_LOOP_ENABLED.pop(key, None)
        CUSTOM_MUSIC_SKIP_VOTE_USERS.pop(key, None)
    return f"✅ {slot}번 커스텀 봇을 퇴장시켰어요." if disconnected else f"ℹ️ {slot}번 커스텀 봇은 이 서버 음성방에 없어요."


async def disconnect_empty_custom_voice_clients_for_guild(guild: discord.Guild):
    """커스텀 보조 봇도 통방에 유저가 없으면 자동 퇴장합니다."""
    if guild is None:
        return 0
    disconnected = 0
    for slot, client in list(CUSTOM_BOT_CLIENTS.items()):
        if not client:
            continue
        for vc in list(getattr(client, "voice_clients", [])):
            try:
                if not vc.guild or vc.guild.id != guild.id or vc.channel is None:
                    continue
                humans = [member for member in vc.channel.members if not member.bot]
                if humans:
                    continue
                channel_name = vc.channel.name
                try:
                    if vc.is_playing() or vc.is_paused():
                        vc.stop()
                except Exception:
                    pass
                key = custom_music_key(int(slot), int(guild.id)) if "custom_music_key" in globals() else (int(slot), int(guild.id))
                if "CUSTOM_MUSIC_QUEUES" in globals():
                    CUSTOM_MUSIC_QUEUES.pop(key, None)
                    CUSTOM_MUSIC_NOW_PLAYING.pop(key, None)
                    CUSTOM_MUSIC_LOOP_ENABLED.pop(key, None)
                    CUSTOM_MUSIC_SKIP_VOTE_USERS.pop(key, None)
                await vc.disconnect(force=True)
                disconnected += 1
                await send_log(guild, f"👋 커스텀 봇 자동 퇴장\n{slot}번 보조 봇이 유저가 없는 통방에서 자동으로 나갔습니다.\n채널: `{channel_name}`", "voice")
            except Exception as e:
                print(f"⚠️ 커스텀 봇 {slot}번 자동 퇴장 실패: {e}")
    return disconnected


@tasks.loop(seconds=30)
async def auto_disconnect_empty_custom_voice_clients():
    for guild in list(bot.guilds):
        try:
            await disconnect_empty_custom_voice_clients_for_guild(guild)
        except Exception as e:
            print(f"⚠️ 커스텀 봇 자동 퇴장 검사 실패: {e}")


def build_custom_bot_panel_embed(guild: discord.Guild):
    embed = discord.Embed(
        title="🤖 커스텀 보조 봇 통방 입장",
        description=(
            "이제 커스텀 봇 만들기/수정 없이 사용할 수 있어요.\n"
            "먼저 원하는 통방/음성채널에 들어간 다음 아래 번호 버튼을 누르면,\n"
            "해당 보조 봇이 그 통방으로 들어오고 통방 채팅채널에 뮤직패널이 자동 전송됩니다.\n\n"
            "⚙️ 실제로 여러 보조 봇이 보이려면 Render 환경변수에 "
            "`CUSTOM_BOT_TOKEN_1`, `CUSTOM_BOT_TOKEN_2`, `CUSTOM_BOT_TOKEN_3` 토큰이 있어야 해요."
        ),
        color=0x9B7CFF,
    )
    for slot in (1, 2, 3):
        token_state = "✅ 토큰 있음" if CUSTOM_BOT_TOKENS.get(slot) else "⚠️ 토큰 없음"
        client = CUSTOM_BOT_CLIENTS.get(slot)
        bot_name = get_custom_music_bot_label(guild.id, slot)
        voice_client = get_custom_music_voice_client(slot, guild.id)
        if voice_client and getattr(voice_client, "channel", None):
            channel_text = voice_client.channel.mention
            live_state = "🟢 통방 입장 중"
        else:
            channel_text = "미입장"
            live_state = "⚪ 대기 중"
        login_state = "온라인" if client and client.is_ready() else "로그인 대기"
        value = (
            f"이름: **{bot_name}**\n"
            f"상태: {token_state} / {login_state}\n"
            f"현재 통방: {channel_text}\n"
            f"입장 상태: {live_state}"
        )
        embed.add_field(name=f"🎧 {slot}번 커스텀 봇", value=value, inline=True)
    if bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)
    embed.set_footer(text="만능 봇 | /커스텀 1·2·3 통방 입장")
    return embed




# =========================
# 커스텀 보조 봇 뮤직 패널
# =========================
# 메인 뮤직 패널은 메인 봇 1개만 음성 재생을 처리합니다.
# 아래 커스텀 뮤직 패널은 CUSTOM_BOT_TOKEN_1~3에 연결된 보조 봇마다
# 독립 대기열/반복/볼륨/스킵 투표를 가지도록 분리해서 동작합니다.

CUSTOM_MUSIC_QUEUES = {}
CUSTOM_MUSIC_NOW_PLAYING = {}
CUSTOM_MUSIC_LOOP_ENABLED = {}
CUSTOM_MUSIC_VOLUME_LEVELS = {}
CUSTOM_MUSIC_SKIP_VOTE_USERS = {}
CUSTOM_MUSIC_PANEL_LAST_SENT = {}
CUSTOM_MUSIC_PANEL_MESSAGES = {}


def custom_music_key(slot: int, guild_id: int):
    return (int(slot), int(guild_id))


def get_custom_music_queue(slot: int, guild_id: int):
    key = custom_music_key(slot, guild_id)
    if key not in CUSTOM_MUSIC_QUEUES:
        CUSTOM_MUSIC_QUEUES[key] = deque()
    return CUSTOM_MUSIC_QUEUES[key]


def get_custom_music_volume(slot: int, guild_id: int):
    return CUSTOM_MUSIC_VOLUME_LEVELS.get(custom_music_key(slot, guild_id), 0.5)


def get_custom_music_voice_client(slot: int, guild_id: int):
    client = CUSTOM_BOT_CLIENTS.get(int(slot))
    if not client:
        return None
    for vc in list(client.voice_clients):
        if vc.guild and vc.guild.id == int(guild_id):
            return vc
    return None


def get_custom_music_bot_label(guild_id: int, slot: int):
    client = CUSTOM_BOT_CLIENTS.get(int(slot))
    if client and getattr(client, "user", None):
        return getattr(client.user, "display_name", None) or getattr(client.user, "name", None) or f"커스텀봇 {slot}"
    row = get_custom_voice_bot_setting(int(guild_id), int(slot))
    if row and row[1]:
        return row[1]
    return f"커스텀봇 {slot}"

