# =========================
# 직접 역할 만들기 박스형 모달
# =========================
ROLE_MAKER_COLOR_PRESETS = {
    "하늘": COLOR_SKY,
    "하늘색": COLOR_SKY,
    "연하늘": COLOR_SOFT_SKY,
    "핑크": COLOR_PINK,
    "연핑크": COLOR_PINK,
    "보라": COLOR_LAVENDER,
    "연보라": COLOR_LAVENDER,
    "민트": COLOR_MINT,
    "초록": COLOR_GREEN,
    "연초록": COLOR_GREEN,
    "골드": COLOR_GOLD,
    "노랑": COLOR_GOLD,
    "경고": COLOR_WARNING,
    "빨강": COLOR_WARNING,
    "회색": COLOR_GRAY,
    "그레이": COLOR_GRAY,
    "기본": 0,
    "없음": 0,
}


def parse_role_maker_color(raw_color: str):
    raw = (raw_color or "").strip()
    if not raw:
        return discord.Color.default(), "기본"

    key = raw.replace(" ", "").lower()
    for preset_name, preset_value in ROLE_MAKER_COLOR_PRESETS.items():
        if key == preset_name.lower():
            if preset_value == 0:
                return discord.Color.default(), "기본"
            return discord.Color(preset_value), f"#{preset_value:06X}"

    cleaned = raw.replace("#", "").replace("0x", "").replace("0X", "").strip()
    if len(cleaned) == 6:
        try:
            value = int(cleaned, 16)
            if 0 <= value <= 0xFFFFFF:
                return discord.Color(value), f"#{value:06X}"
        except ValueError:
            pass

    raise ValueError("색상은 `#87CEFA`, `87CEFA`, `하늘색`, `핑크`, `보라`, `민트`, `골드`, `기본` 중 하나로 입력해주세요.")


def parse_role_maker_bool(raw_text: str, *, default: bool = False):
    text = (raw_text or "").strip().lower().replace(" ", "")
    if not text:
        return default
    yes_values = {"y", "yes", "true", "1", "on", "예", "네", "ㅇ", "ㅇㅇ", "켜기", "사용", "보이게", "표시"}
    no_values = {"n", "no", "false", "0", "off", "아니오", "아니", "ㄴ", "ㄴㄴ", "끄기", "미사용", "숨김"}
    if text in yes_values:
        return True
    if text in no_values:
        return False
    return default


def validate_custom_role_name(role_name: str):
    name = (role_name or "").strip()
    if not name:
        raise ValueError("역할 이름을 입력해주세요.")
    if len(name) > 100:
        raise ValueError("역할 이름은 100자 이하로 입력해주세요.")
    blocked = {"@everyone", "everyone", "@here", "here"}
    if name.lower().replace(" ", "") in blocked:
        raise ValueError("이 이름은 역할 이름으로 사용할 수 없어요.")
    return name


def build_role_maker_help_embed(guild: discord.Guild):
    embed = discord.Embed(
        title="📦 직접 역할 만들기 패널",
        description=(
            "━━━━━━━━━━━━━━━━━━━━\n"
            "아래 **역할 만들기 열기** 버튼을 누르면 박스형 입력창으로 원하는 역할을 만들 수 있어요.\n"
            "기존에 같은 이름의 역할이 있으면 새로 만들지 않고 색상/표시 옵션만 수정합니다.\n"
            "━━━━━━━━━━━━━━━━━━━━"
        ),
        color=FRIEND_SERVER_COLORS.get("role", BOT_COLOR),
    )
    embed.add_field(
        name="📝 입력 예시",
        value=(
            "역할 이름: `로블록스할사람?`\n"
            "색상: `#87CEFA` 또는 `하늘색`\n"
            "상단 표시: `예` / `아니오`\n"
            "멘션 가능: `예` / `아니오`\n"
            "내게 지급: `예` / `아니오`"
        ),
        inline=False,
    )
    embed.add_field(
        name="🛡️ 안전 설정",
        value=(
            "새 역할은 기본 권한 없이 생성됩니다.\n"
            "관리자/역할관리 권한은 자동으로 넣지 않아서 안전합니다.\n"
            "봇 역할이 만들 역할보다 아래에 있으면 디스코드 권한 때문에 실패할 수 있어요."
        ),
        inline=False,
    )
    embed.add_field(
        name="✅ 이번 업그레이드 반영",
        value="`/역할만들기` → 박스형 임베드 패널 → 버튼 클릭 → 직접 역할 생성 흐름으로 정리했습니다.",
        inline=False,
    )
    if guild and guild.icon:
        embed.set_thumbnail(url=guild.icon.url)
    elif bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)
    embed.set_footer(text="만능 봇 | 직접 역할 만들기")
