class RoleMakerPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=300)

    @discord.ui.button(label="역할 만들기 열기", emoji="🎨", style=discord.ButtonStyle.green)
    async def open_maker(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.guild is None:
            return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
        if await reject_if_not_setup_manager(interaction):
            return
        await interaction.response.send_modal(RoleMakerModal())

    @discord.ui.button(label="사용법 다시보기", emoji="📘", style=discord.ButtonStyle.blurple)
    async def show_help(self, interaction: discord.Interaction, button: discord.ui.Button):
        if interaction.guild is None:
            return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
        await safe_interaction_send(interaction, embed=build_role_maker_help_embed(interaction.guild), ephemeral=True)


class RoleMakerModal(discord.ui.Modal, title="🎨 역할 만들기"):
    role_name = discord.ui.TextInput(
        label="역할 이름",
        placeholder="예: 로블록스할사람?, 그림러, 새벽반",
        max_length=100,
        required=True,
    )
    role_color = discord.ui.TextInput(
        label="색상",
        placeholder="#87CEFA / 하늘색 / 핑크 / 보라 / 민트 / 골드 / 기본",
        max_length=20,
        required=False,
        default="#87CEFA",
    )
    hoist = discord.ui.TextInput(
        label="상단 표시",
        placeholder="예 또는 아니오",
        max_length=10,
        required=False,
        default="아니오",
    )
    mentionable = discord.ui.TextInput(
        label="멘션 가능",
        placeholder="예 또는 아니오",
        max_length=10,
        required=False,
        default="아니오",
    )
    give_to_me = discord.ui.TextInput(
        label="내게 바로 지급",
        placeholder="예 또는 아니오",
        max_length=10,
        required=False,
        default="아니오",
    )

    async def on_submit(self, interaction: discord.Interaction):
        guild = interaction.guild
        if guild is None:
            return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)

        if await reject_if_not_setup_manager(interaction):
            return

        await safe_interaction_defer(interaction, ephemeral=True)

        try:
            name = validate_custom_role_name(str(self.role_name.value))
            color, color_text = parse_role_maker_color(str(self.role_color.value))
            hoist_value = parse_role_maker_bool(str(self.hoist.value), default=False)
            mentionable_value = parse_role_maker_bool(str(self.mentionable.value), default=False)
            give_to_me_value = parse_role_maker_bool(str(self.give_to_me.value), default=False)
        except ValueError as e:
            embed = create_embed("❌ 역할 만들기 실패", str(e), FRIEND_SERVER_COLORS.get("warning", COLOR_WARNING))
            return await interaction.followup.send(embed=embed, ephemeral=True)

        bot_member = guild.me or guild.get_member(bot.user.id if bot.user else 0)
        if not bot_member or not bot_member.guild_permissions.manage_roles:
            embed = create_embed(
                "❌ 역할 만들기 실패",
                "봇에게 `역할 관리` 권한이 없어요.\n봇 역할 위치와 권한을 먼저 확인해주세요.",
                FRIEND_SERVER_COLORS.get("warning", COLOR_WARNING),
            )
            return await interaction.followup.send(embed=embed, ephemeral=True)

        existing_role = discord.utils.get(guild.roles, name=name)
        created = False
        try:
            if existing_role:
                if existing_role >= bot_member.top_role:
                    embed = create_embed(
                        "❌ 역할 수정 실패",
                        f"`{existing_role.name}` 역할이 봇 역할보다 위에 있어 수정할 수 없어요.",
                        FRIEND_SERVER_COLORS.get("warning", COLOR_WARNING),
                    )
                    return await interaction.followup.send(embed=embed, ephemeral=True)
                role = await existing_role.edit(
                    color=color,
                    hoist=hoist_value,
                    mentionable=mentionable_value,
                    reason=f"/역할만들기 사용: {interaction.user}",
                )
            else:
                role = await guild.create_role(
                    name=name,
                    color=color,
                    permissions=discord.Permissions.none(),
                    hoist=hoist_value,
                    mentionable=mentionable_value,
                    reason=f"/역할만들기 사용: {interaction.user}",
                )
                created = True

            if give_to_me_value and isinstance(interaction.user, discord.Member):
                try:
                    await interaction.user.add_roles(role, reason="/역할만들기 생성자 자동 지급")
                except discord.Forbidden:
                    pass
        except discord.Forbidden:
            embed = create_embed(
                "❌ 역할 만들기 실패",
                "역할을 만들거나 수정할 권한이 부족해요.\n봇 역할을 새로 만들 역할보다 위로 올려주세요.",
                FRIEND_SERVER_COLORS.get("warning", COLOR_WARNING),
            )
            return await interaction.followup.send(embed=embed, ephemeral=True)
        except discord.HTTPException as e:
            embed = create_embed("❌ 역할 만들기 실패", f"Discord 오류가 발생했어요.\n`{e}`", FRIEND_SERVER_COLORS.get("warning", COLOR_WARNING))
            return await interaction.followup.send(embed=embed, ephemeral=True)

        embed = discord.Embed(
            title="✅ 역할 만들기 완료",
            description=(
                "직접 입력한 정보로 역할을 준비했어요.\n\n"
                "━━━━━━━━━━━━━━━━━━━━"
            ),
            color=FRIEND_SERVER_COLORS.get("role", BOT_COLOR),
        )
        embed.add_field(name="역할", value=role.mention, inline=True)
        embed.add_field(name="상태", value="새로 생성" if created else "기존 역할 수정", inline=True)
        embed.add_field(name="색상", value=color_text, inline=True)
        embed.add_field(name="상단 표시", value="예" if hoist_value else "아니오", inline=True)
        embed.add_field(name="멘션 가능", value="예" if mentionable_value else "아니오", inline=True)
        embed.add_field(name="내게 지급", value="예" if give_to_me_value else "아니오", inline=True)
        embed.add_field(
            name="안내",
            value="이 역할은 안전을 위해 기본 권한 없이 생성돼요. 채널별 권한은 디스코드 역할 설정에서 따로 조정하면 돼요.",
            inline=False,
        )
        if guild.icon:
            embed.set_thumbnail(url=guild.icon.url)
        embed.set_footer(text=f"{guild.name} | 만능 봇 역할 만들기")
        await interaction.followup.send(embed=embed, ephemeral=True)


async def open_role_maker_modal(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
    if await reject_if_not_setup_manager(interaction):
        return
    await safe_interaction_send(interaction, 
        embed=build_role_maker_help_embed(interaction.guild),
        view=RoleMakerPanelView(),
        ephemeral=True,
    )



