def build_ultimate_section_embed(guild: discord.Guild, section_key: str):
    emoji, title, desc = ULTIMATE_SECTIONS.get(section_key, ULTIMATE_SECTIONS["home"])
    embed = discord.Embed(title=f"{emoji} 만능 센터 · {title}", description=f"{desc}\n\n━━━━━━━━━━━━━━━━━━", color=SKY_BLUE)
    if bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)

    if section_key == "setup":
        embed.add_field(name="📦 자동 생성/복구", value="`/서버 친목섭`\n`/서버 기본카테고리`\n`/서버 서버스텟생성`\n`/만능 전체자동생성`", inline=False)
        embed.add_field(name="추가 복구", value="생일 채널, 개발로그, 서버스텟, 기본 패널까지 함께 점검합니다.", inline=False)
    elif section_key == "panel":
        embed.add_field(name="🎛️ 패널", value="`/패널` 또는 `/만능 빠른패널`로 열 수 있어요.\n도움말, 경제, 상점, 티켓, 뮤직, 인증, 게임역할, 보안, 경고, 관리도구, 이벤트, 칭호, 개발로그, 생일", inline=False)
    elif section_key == "embed":
        embed.add_field(name="🧩 임베드 꾸미기", value="`/임베드 설정` · 채널 ID로 임베드 전송\n`/임베드 버튼붙이기` · 기존 임베드에 버튼 추가\n`/임베드 버튼자동설정` · 자동 버튼 연결 설정", inline=False)
        embed.add_field(name="추가된 버튼", value="생일 등록 버튼까지 `/임베드 버튼붙이기`에서 선택할 수 있어요.", inline=False)
    elif section_key == "admin":
        embed.add_field(name="🛡️ 관리/보안", value="`/관리 패널` `청소` `킥` `밴` `경고조회`\n`/설정` 그룹과 `/관리 검열켜기`로 검열/보안 옵션을 관리합니다.", inline=False)
    elif section_key == "economy":
        embed.add_field(name="💰 경제", value="`/출첵` `!출첵` `/경제 잔액` `/경제 송금` `/경제 상점` `/경제 구매`\n`/주식 시장` `/쿠폰 사용` `/칭호 패널`", inline=False)
    elif section_key == "event":
        embed.add_field(name="🎉 이벤트", value="`/이벤트 패널` `/이벤트 목록` `/이벤트 종료` `/이벤트 개인보상` `/이벤트 팀보상`\n`/커뮤니티 투표` `/커뮤니티 추첨` `/커뮤니티 미션`", inline=False)
    elif section_key == "voice":
        embed.add_field(name="🎵 뮤직/TTS", value="`/음성 입장` `/음성 퇴장` `/음성 목소리변경` `/음성 목소리목록`\n뮤직 버튼 패널과 TTS 채널 자동 생성도 지원합니다.", inline=False)
    elif section_key == "birthday":
        embed.add_field(name="🎂 생일", value="`/생일 패널` `/생일 등록` `/생일 수정` `/생일 확인` `/생일 목록` `/생일 삭제`\n버튼으로 등록/수정/삭제하고 생일기록 채널을 자동 정리합니다.", inline=False)
    elif section_key == "health":
        embed = build_ultimate_health_embed(guild)
    else:
        return build_ultimate_home_embed(guild)
    embed.set_footer(text="/만능 패널 · 하늘색 완성형 센터")
    return embed


def build_ultimate_health_embed(guild: discord.Guild):
    guild_id = guild.id if guild else 0
    root_commands = len(bot.tree.get_commands())
    channel_names = ["🎫-문의하기", "✅-인증채널", "🎵-뮤직명령어", "🛒-상점", "🎂-생일등록", "🎁-생일기록", "📋-일반로그"]
    found = 0
    missing = []
    if guild:
        for name in channel_names:
            ch = discord.utils.get(guild.text_channels, name=name)
            if ch:
                found += 1
            else:
                missing.append(name)
    embed = discord.Embed(title="🔍 만능 봇 서버 점검", description="현재 봇과 서버 상태를 빠르게 확인했어요.", color=SKY_BLUE)
    embed.add_field(name="🤖 봇", value=f"루트 명령어: `{root_commands}`개\n서버 수: `{len(bot.guilds)}`개\n지연시간: `{round(bot.latency * 1000)}ms`", inline=True)
    embed.add_field(name="📦 서버", value=f"채널: `{len(guild.channels) if guild else 0}`개\n역할: `{len(guild.roles) if guild else 0}`개\n멤버: `{guild.member_count if guild else 0}`명", inline=True)
    embed.add_field(name="🗂️ 필수 채널", value=f"확인: `{found}/{len(channel_names)}`\n누락: `{', '.join(missing[:4]) if missing else '없음 ✅'}`", inline=False)
    embed.add_field(name="🧾 DB", value=f"생일: `{ultimate_sql_count('SELECT COUNT(*) FROM birthday_records WHERE guild_id=?', (guild_id,))}`개\n쿠폰: `{ultimate_sql_count('SELECT COUNT(*) FROM coupon_codes WHERE guild_id=?', (guild_id,))}`개\n이벤트: `{ultimate_sql_count('SELECT COUNT(*) FROM scheduled_events WHERE guild_id=?', (guild_id,))}`개", inline=True)
    embed.add_field(name="🌐 대시보드", value=f"동기화: `{'켜짐' if DASHBOARD_SYNC_ENABLED else '꺼짐'}`\nURL: `{DASHBOARD_SYNC_URL or '미설정'}`", inline=True)
    embed.set_footer(text="누락 채널은 /만능 전체자동생성 으로 복구할 수 있어요.")
    return embed



def ultimate_box(title: str, lines, emoji: str = "🩵"):
    """임베드 field 안에 들어가는 박스형 텍스트를 만듭니다."""
    if isinstance(lines, str):
        lines = [lines]
    clean_lines = [str(line) for line in lines if str(line).strip()]
    if not clean_lines:
        clean_lines = ["내용 없음"]
    body = "\n".join(f"│ {line}" for line in clean_lines)
    return f"╭─ {emoji} **{title}**\n{body}\n╰────────────────────"


