class UltimateQuickPanelSelect(discord.ui.Select):
    def __init__(self):
        options = [
            discord.SelectOption(
                label=item["label"],
                value=item["value"],
                description=item["desc"][:100],
                emoji=item["emoji"],
            )
            for item in ULTIMATE_QUICK_PANEL_CHOICES
        ]
        super().__init__(placeholder="열고 싶은 패널을 선택해주세요", min_values=1, max_values=1, options=options, custom_id="ultimate_quick_panel_select")

    async def callback(self, interaction: discord.Interaction):
        if await reject_if_not_ultimate_manager(interaction, "만능 빠른패널 선택"):
            return
        value = self.values[0]
        await safe_interaction_edit(interaction, embed=build_ultimate_quick_panel_embed(value), view=UltimateQuickPanelOpenView(value))


