async def run_ultimate_full_setup(interaction: discord.Interaction):
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있습니다.", ephemeral=True)
    if await reject_if_not_setup_manager(interaction):
        return
    if await reject_if_not_bot_manager(interaction):
        return
    if not interaction.user.guild_permissions.manage_channels:
        return await safe_interaction_send(interaction, "❌ 전체 자동생성은 채널 관리 권한이 필요합니다.", ephemeral=True)

    await safe_interaction_defer(interaction, ephemeral=True)
    guild = interaction.guild
    result_lines = []

    try:
        results = await auto_create_selected_panel(guild, "all", interaction.user)
        result_lines.extend(results or [])
    except Exception as e:
        result_lines.append(f"⚠️ 기본 패널 복구 실패: {e}")

    try:
        category, created_count = await ensure_server_stats_channels(guild)
        result_lines.append(f"📊 서버스텟: {category.name if category else '미설정'} / 새로 생성 {created_count}개")
    except Exception as e:
        result_lines.append(f"⚠️ 서버스텟 점검 실패: {e}")

    try:
        await create_birthday_channels(guild)
        result_lines.append("🎂 생일 시스템: 생일등록/생일기록 채널 점검 완료")
    except Exception as e:
        result_lines.append(f"⚠️ 생일 시스템 점검 실패: {e}")

    try:
        devlog_result = await ensure_development_log_channels(guild)
        if isinstance(devlog_result, dict):
            result_lines.append(f"📈 개발로그: 생성 {len(devlog_result.get('created', []))}개 / 정리 {len(devlog_result.get('updated', []))}개")
        else:
            result_lines.append("📈 개발로그: 점검 완료")
    except Exception as e:
        result_lines.append(f"⚠️ 개발로그 점검 실패: {e}")

    try:
        synced = ensure_dashboard_sync_for_guild(guild.id, force=True)
        result_lines.append(f"🌐 대시보드 동기화: {'완료' if synced else '건너뜀/실패'}")
    except Exception as e:
        result_lines.append(f"⚠️ 대시보드 동기화 실패: {e}")

    embed = build_ultimate_full_setup_result_embed(guild, result_lines)
    await interaction.followup.send(embed=embed, ephemeral=True)
    try:
        await send_log(guild, f"🩵 만능 전체 자동생성 실행\n관리자: {interaction.user.mention}", "general")
    except Exception:
        pass


