async def reject_if_not_ultimate_manager(interaction: discord.Interaction, action_name: str = "만능 관리센터"):
    """/만능 명령어와 만능 버튼을 관리자/봇 관리자만 사용할 수 있게 막습니다."""
    if interaction.guild is None:
        embed = discord.Embed(
            title="❌ 서버 전용 기능",
            description="`/만능` 관리센터는 디스코드 서버 안에서만 사용할 수 있어요.",
            color=0xED4245,
        )
    elif await can_manage_bot_in_guild(interaction):
        return False
    else:
        embed = discord.Embed(
            title="🔒 만능 관리센터 권한 없음",
            description=(
                f"`{action_name}` 기능은 **관리자 전용**이에요.\n\n"
                "아래 권한 중 하나가 있어야 사용할 수 있습니다.\n"
                "━━━━━━━━━━━━━━━━━━"
            ),
            color=0xED4245,
        )
        embed.add_field(
            name="✅ 사용 가능 대상",
            value=(
                "`서버 관리자 권한`\n"
                "`대표` · `부대표` · `총관리자` · `부관리자`\n"
                "`운영진` · `관리자` · `팀장` · `부팀장`"
            ),
            inline=False,
        )
        embed.add_field(
            name="🩵 안내",
            value="일반 유저는 `/생일`, `/잔액`, `/출첵`, `!출첵`, `/랭크` 같은 일반 명령어를 사용하면 됩니다.",
            inline=False,
        )
        embed.set_footer(text="만능 봇 | /만능 관리자 전용")

    try:
        if interaction.response.is_done():
            await interaction.followup.send(embed=embed, ephemeral=True)
        else:
            await safe_interaction_send(interaction, embed=embed, ephemeral=True)
    except Exception:
        pass
    return True


