def create_maneung_database_backup_file():
    timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    backup_path = os.path.join(tempfile.gettempdir(), f"maneung_database_backup_{timestamp}.db")
    if os.path.exists("database.db"):
        conn.commit()
        shutil.copy2("database.db", backup_path)
    else:
        with open(backup_path, "w", encoding="utf-8") as fp:
            fp.write("database.db 파일이 아직 생성되지 않았습니다.\n")
    return backup_path


def build_maneung_usage_embed(guild: discord.Guild, limit: int = 10):
    guild_id = guild.id if guild else 0
    try:
        c.execute(
            """
            SELECT command_name, user_id, channel_id, created_at
            FROM command_usage_logs
            WHERE guild_id=?
            ORDER BY log_id DESC
            LIMIT ?
            """,
            (guild_id, max(1, min(int(limit), 20)))
        )
        rows = c.fetchall()
    except Exception:
        rows = []

    embed = discord.Embed(
        title="📊 만능 봇 명령어 사용기록",
        description="최근 서버에서 사용된 슬래시 명령어 기록입니다.",
        color=SKY_BLUE,
    )
    if rows:
        lines = []
        for command_name, user_id, channel_id, created_at in rows:
            user_text = f"<@{user_id}>" if user_id else "알 수 없음"
            channel_text = f"<#{channel_id}>" if channel_id else "알 수 없음"
            lines.append(f"`/{maneung_safe_text(command_name, 60)}` · {user_text} · {channel_text} · `{created_at}`")
        embed.add_field(name="최근 기록", value="\n".join(lines)[:1024], inline=False)
    else:
        embed.add_field(name="최근 기록", value="아직 기록된 명령어가 없어요.", inline=False)
    embed.set_footer(text="명령어가 정상 완료되면 자동으로 기록됩니다.")
    return embed


def build_maneung_error_embed(guild: discord.Guild, limit: int = 8):
    guild_id = guild.id if guild else 0
    try:
        c.execute(
            """
            SELECT command_name, error_type, error_text, user_id, created_at
            FROM bot_runtime_errors
            WHERE guild_id=?
            ORDER BY error_id DESC
            LIMIT ?
            """,
            (guild_id, max(1, min(int(limit), 15)))
        )
        rows = c.fetchall()
    except Exception:
        rows = []

    embed = discord.Embed(
        title="🧯 만능 봇 오류기록",
        description="최근 앱 명령어 오류를 저장해서 문제 원인을 찾기 쉽게 만들었어요.",
        color=0xFFB347,
    )
    if rows:
        lines = []
        for command_name, error_type, error_text, user_id, created_at in rows:
            lines.append(
                f"`/{maneung_safe_text(command_name, 60)}` · `{maneung_safe_text(error_type, 40)}` · <@{user_id}>\n"
                f"└ `{created_at}` · {maneung_safe_text(error_text, 130)}"
            )
        embed.add_field(name="최근 오류", value="\n".join(lines)[:1024], inline=False)
    else:
        embed.add_field(name="최근 오류", value="최근 저장된 오류가 없어요 ✅", inline=False)
    embed.set_footer(text="오류가 생겨도 가능한 경우 사용자에게 안내 메시지를 보내도록 업그레이드했습니다.")
    return embed


def create_maneung_server_report_file(guild: discord.Guild):
    timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    safe_guild = re.sub(r"[^0-9A-Za-z가-힣_-]+", "_", guild.name if guild else "server")[:40]
    path = os.path.join(tempfile.gettempdir(), f"maneung_report_{safe_guild}_{timestamp}.txt")
    guild_id = guild.id if guild else 0

    expected_channels = [
        "📋-일반로그", "⚠️-경고로그", "⛔-처벌로그", "💬-채팅로그", "🔊-음성로그",
        "🎫-문의하기", "✅-인증채널", "🎵-뮤직명령어", "🔊-tts", "🛒-상점",
        "💰-포인트", "📈-주식", "📅-출석체크", "⚒️-강화", "🎂-생일등록", "🎁-생일기록",
    ]
    existing = {ch.name for ch in guild.text_channels} if guild else set()
    missing = [name for name in expected_channels if name not in existing]

    try:
        c.execute(
            "SELECT command_name, user_id, created_at FROM command_usage_logs WHERE guild_id=? ORDER BY log_id DESC LIMIT 15",
            (guild_id,)
        )
        usage_rows = c.fetchall()
    except Exception:
        usage_rows = []

    lines = []
    lines.append("만능 봇 서버 리포트")
    lines.append("=" * 40)
    lines.append(f"생성 시간: {maneung_now_text()}")
    lines.append(f"봇 버전: {MANEUNG_UPGRADE_VERSION}")
    lines.append(f"업타임: {maneung_human_timedelta(datetime.datetime.now() - MANEUNG_UPGRADE_STARTED_AT)}")
    lines.append(f"DB 크기: {maneung_database_size_text()}")
    lines.append("")
    if guild:
        lines.append("[서버]")
        lines.append(f"이름: {guild.name}")
        lines.append(f"ID: {guild.id}")
        lines.append(f"멤버: {guild.member_count or 0}")
        lines.append(f"채널: {len(guild.channels)}")
        lines.append(f"역할: {len(guild.roles)}")
        lines.append("")
    lines.append("[DB 카운트]")
    for table_name in [
        "users", "inventory", "warnings", "birthday_records", "scheduled_events",
        "coupon_codes", "stock_holdings", "command_usage_logs", "bot_runtime_errors"
    ]:
        lines.append(f"{table_name}: {maneung_count_table(table_name, 'guild_id=?', (guild_id,)) if table_name not in ['inventory', 'warnings'] else maneung_count_table(table_name)}")
    lines.append("")
    lines.append("[누락된 주요 채널]")
    lines.extend(missing if missing else ["누락 없음"])
    lines.append("")
    lines.append("[최근 명령어]")
    if usage_rows:
        for command_name, user_id, created_at in usage_rows:
            lines.append(f"/{command_name} | user={user_id} | {created_at}")
    else:
        lines.append("기록 없음")

    with open(path, "w", encoding="utf-8") as fp:
        fp.write("\n".join(lines))
    return path


async def send_maneung_database_backup(interaction: discord.Interaction):
    if await reject_if_not_ultimate_manager(interaction, "/만능 백업"):
        return
    if not interaction.response.is_done():
        await safe_interaction_defer(interaction, ephemeral=True)
    backup_path = create_maneung_database_backup_file()
    try:
        await interaction.followup.send(
            content="✅ `database.db` 백업을 만들었어요. 중요한 업데이트 전에는 이 파일을 따로 보관해주세요.",
            file=discord.File(backup_path, filename=os.path.basename(backup_path)),
            ephemeral=True,
        )
    finally:
        try:
            os.remove(backup_path)
        except OSError:
            pass


async def send_maneung_server_report(interaction: discord.Interaction):
    if await reject_if_not_ultimate_manager(interaction, "/만능 서버리포트"):
        return
    if interaction.guild is None:
        return await safe_interaction_send(interaction, "❌ 서버에서만 사용할 수 있어요.", ephemeral=True)
    if not interaction.response.is_done():
        await safe_interaction_defer(interaction, ephemeral=True)
    report_path = create_maneung_server_report_file(interaction.guild)
    try:
        await interaction.followup.send(
            content="✅ 서버 리포트를 만들었어요. 누락 채널이 있으면 `/만능 전체자동생성`으로 복구할 수 있어요.",
            file=discord.File(report_path, filename=os.path.basename(report_path)),
            ephemeral=True,
        )
    finally:
        try:
            os.remove(report_path)
        except OSError:
            pass


