@bot.listen("on_app_command_completion")
async def maneung_v180_command_usage_logger(interaction: discord.Interaction, command: app_commands.Command):
    try:
        guild_id = interaction.guild.id if interaction.guild else 0
        channel_id = interaction.channel.id if interaction.channel else 0
        user_id = interaction.user.id if interaction.user else 0
        command_name = getattr(command, "qualified_name", None) or getattr(command, "name", "unknown")
        c.execute(
            """
            INSERT INTO command_usage_logs(guild_id, channel_id, user_id, command_name, created_at)
            VALUES (?, ?, ?, ?, ?)
            """,
            (guild_id, channel_id, user_id, command_name, maneung_now_text())
        )
        conn.commit()
    except Exception:
        pass


async def maneung_safe_interaction_reply(interaction: discord.Interaction, *, embed=None, content: str | None = None, ephemeral: bool = True):
    """상호작용 응답 상태와 만료 여부를 보고 안전하게 응답합니다."""
    if interaction is None:
        return False
    try:
        if interaction.response.is_done():
            await interaction.followup.send(content=content, embed=embed, ephemeral=ephemeral)
        else:
            await safe_interaction_send(interaction, content=content, embed=embed, ephemeral=ephemeral)
        return True
    except discord.NotFound:
        # 10062 Unknown interaction: 3초 제한 초과/만료된 상호작용은 조용히 무시합니다.
        return False
    except discord.HTTPException as e:
        # 40060 Interaction already acknowledged, 10062 Unknown interaction은 추가 로그를 만들지 않습니다.
        if getattr(e, "code", None) in (40060, 10062):
            return False
        raise
    except Exception:
        return False


@bot.tree.error
async def maneung_v180_tree_error_handler(interaction: discord.Interaction, error: app_commands.AppCommandError):
    original = getattr(error, "original", error)
    command_name = "unknown"
    try:
        if interaction and interaction.command:
            command_name = interaction.command.qualified_name
    except Exception:
        pass

    error_type = type(original).__name__
    error_text = maneung_safe_text(original, 700)
    error_code = getattr(original, "code", None)

    # 이미 응답된 상호작용/만료된 상호작용은 오류 로그를 계속 불리지 않게 무시합니다.
    if isinstance(original, (discord.NotFound, discord.HTTPException)) and error_code in (40060, 10062):
        return

    # 통합 명령어로 옮겨진 예전 명령어를 눌렀을 때는 일반 오류 로그를 남기지 않습니다.
    if isinstance(error, app_commands.CommandNotFound) or isinstance(original, app_commands.CommandNotFound):
        moved = {
            "친목섭": "/서버 친목섭 또는 /친목섭",
            "통합상점": "/경제 상점",
            "인벤토리": "/경제 인벤토리",
            "미션": "/커뮤니티 미션 또는 /미션",
        }
        missing = getattr(error, "name", "") or getattr(original, "name", "") or command_name
        guide = moved.get(str(missing), "/만능 명령어")
        embed = discord.Embed(
            title="🔄 명령어가 정리되었어요",
            description=(
                f"`/{maneung_safe_text(missing, 80)}` 명령어는 현재 명령어 목록과 맞지 않아요.\n"
                f"대신 **{guide}** 를 사용해 주세요.\n\n"
                "명령어가 계속 안 보이면 `/만능 슬래시동기화` 후 디스코드를 새로고침해 주세요."
            ),
            color=COLOR_SOFT_SKY,
        )
        await maneung_safe_interaction_reply(interaction, embed=embed, ephemeral=True)
        return

    guild_id = interaction.guild.id if interaction and interaction.guild else 0
    channel_id = interaction.channel.id if interaction and interaction.channel else 0
    user_id = interaction.user.id if interaction and interaction.user else 0

    try:
        c.execute(
            """
            INSERT INTO bot_runtime_errors(guild_id, channel_id, user_id, command_name, error_type, error_text, created_at)
            VALUES (?, ?, ?, ?, ?, ?, ?)
            """,
            (guild_id, channel_id, user_id, command_name, error_type, error_text, maneung_now_text())
        )
        conn.commit()
    except Exception:
        pass

    if isinstance(original, discord.Forbidden):
        user_message = "봇 권한이 부족해서 실행하지 못했어요. 봇 역할을 채널/역할보다 위로 올리고 `관리자` 또는 필요한 권한을 주세요."
    elif isinstance(original, discord.HTTPException):
        user_message = "디스코드 API 요청 중 오류가 났어요. 잠시 뒤 다시 시도하거나 `/만능 오류기록`을 확인해주세요."
    elif isinstance(error, app_commands.CheckFailure):
        user_message = "이 명령어를 사용할 권한이 없어요."
    else:
        user_message = "명령어 처리 중 오류가 났어요. 오류는 `/만능 오류기록`에 저장했습니다."

    embed = discord.Embed(
        title="🧯 명령어 오류 안내",
        description=user_message,
        color=COLOR_WARNING,
    )
    embed.add_field(name="명령어", value=f"`/{maneung_safe_text(command_name, 80)}`", inline=True)
    embed.add_field(name="오류 종류", value=f"`{maneung_safe_text(error_type, 80)}`", inline=True)
    embed.add_field(name="확인 방법", value="관리자는 `/만능 오류기록`으로 최근 오류를 볼 수 있어요.", inline=False)

    await maneung_safe_interaction_reply(interaction, embed=embed, ephemeral=True)

    try:
        if interaction.guild:
            await send_log(
                interaction.guild,
                f"🧯 앱 명령어 오류\n명령어: `/{command_name}`\n사용자: <@{user_id}>\n오류: `{error_type}` - {error_text[:300]}",
                "general"
            )
    except Exception:
        pass


