def maneung_v190_checkmark(ok: bool):
    return "✅" if ok else "❌"


def maneung_v190_unique_names(names):
    result = []
    seen = set()
    for name in names:
        key = (name or "").strip()
        if key and key not in seen:
            seen.add(key)
            result.append(key)
    return result


def maneung_v190_channel_audit(guild: discord.Guild):
    if guild is None:
        return [], [], [], []
    text_existing = {channel.name for channel in guild.text_channels}
    voice_existing = {channel.name for channel in guild.voice_channels}
    required_text = maneung_v190_unique_names(MANEUNG_V190_REQUIRED_TEXT_CHANNELS)
    required_voice = maneung_v190_unique_names(MANEUNG_V190_REQUIRED_VOICE_CHANNELS)
    missing_text = [name for name in required_text if name not in text_existing]
    missing_voice = [name for name in required_voice if name not in voice_existing]
    return required_text, missing_text, required_voice, missing_voice


def maneung_v190_permission_audit(guild: discord.Guild):
    if guild is None or guild.me is None:
        return [], []
    perms = guild.me.guild_permissions
    rows = []
    missing = []
    for attr, label in MANEUNG_V190_IMPORTANT_PERMISSIONS:
        ok = bool(getattr(perms, attr, False))
        rows.append((label, ok))
        if not ok:
            missing.append(label)
    return rows, missing


