def create_maneung_v190_command_export_file(guild: discord.Guild = None):
    timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
    path = os.path.join(tempfile.gettempdir(), f"maneung_commands_v190_{timestamp}.txt")
    lines = []
    lines.append("만능 봇 슬래시 명령어 목록")
    lines.append("=" * 40)
    lines.append(f"생성 시간: {maneung_now_text()}")
    lines.append(f"버전: {MANEUNG_UPGRADE_VERSION}")
    if guild:
        lines.append(f"서버: {guild.name} ({guild.id})")
    lines.append("")
    try:
        commands_list = list(bot.tree.walk_commands())
    except Exception:
        commands_list = []
    for command in sorted(commands_list, key=lambda cmd: getattr(cmd, "qualified_name", getattr(cmd, "name", ""))):
        name = getattr(command, "qualified_name", getattr(command, "name", "unknown"))
        desc = getattr(command, "description", "") or "설명 없음"
        lines.append(f"/{name} - {desc}")
    if not commands_list:
        lines.append("명령어 목록을 불러오지 못했습니다.")
    with open(path, "w", encoding="utf-8") as fp:
        fp.write("\n".join(lines))
    return path


async def send_maneung_v190_command_export(interaction: discord.Interaction):
    if await reject_if_not_ultimate_manager(interaction, "/만능 명령어내보내기"):
        return
    if not interaction.response.is_done():
        await safe_interaction_defer(interaction, ephemeral=True)
    path = create_maneung_v190_command_export_file(interaction.guild)
    try:
        await interaction.followup.send(
            content="✅ 현재 봇에 등록된 슬래시 명령어 목록을 TXT 파일로 만들었어요.",
            file=discord.File(path, filename=os.path.basename(path)),
            ephemeral=True,
        )
    finally:
        try:
            os.remove(path)
        except OSError:
            pass


