MANEUNG_V193_INDEXES = [
    ("warnings", "idx_warnings_user_time", "user_id, time"),
    ("users", "idx_users_guild_point", "guild_id, point DESC"),
    ("users", "idx_users_guild_attendance", "guild_id, attendance_count DESC"),
    ("inventory", "idx_inventory_user_item", "user_id, item_name"),
    ("daily_rewards", "idx_daily_rewards_guild_user", "guild_id, user_id"),
    ("levels", "idx_levels_exp", "exp DESC"),
    ("voice_levels", "idx_voice_levels_exp", "exp DESC"),
    ("security_logs", "idx_security_logs_guild_time", "guild_id, created_at DESC"),
    ("scheduled_events", "idx_scheduled_events_guild_time", "guild_id, event_time, is_sent"),
    ("event_results", "idx_event_results_guild_time", "guild_id, created_at DESC"),
    ("stock_logs", "idx_stock_logs_guild_user_time", "guild_id, user_id, created_at DESC"),
    ("stock_holdings", "idx_stock_holdings_guild_user", "guild_id, user_id"),
    ("birthday_records", "idx_birthday_records_guild_date", "guild_id, month, day"),
    ("command_usage_logs", "idx_command_usage_guild_time", "guild_id, created_at DESC"),
    ("bot_runtime_errors", "idx_runtime_errors_guild_time", "guild_id, created_at DESC"),
]


def maneung_table_exists(table_name: str) -> bool:
    try:
        with DB_MUTEX:
            c.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table_name,))
            return c.fetchone() is not None
    except sqlite3.Error:
        return False


def ensure_maneung_performance_indexes():
    created_or_checked = 0
    skipped = []
    with DB_MUTEX:
        for table_name, index_name, columns in MANEUNG_V193_INDEXES:
            try:
                c.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table_name,))
                if c.fetchone() is None:
                    skipped.append(table_name)
                    continue
                c.execute(f"CREATE INDEX IF NOT EXISTS {index_name} ON {table_name}({columns})")
                created_or_checked += 1
            except sqlite3.Error:
                skipped.append(table_name)
        try:
            conn.commit()
        except sqlite3.Error:
            pass
    return created_or_checked, sorted(set(skipped))


def run_maneung_db_maintenance():
    """DB 최적화 작업은 별도 스레드에서 실행해 디스코드 이벤트 루프를 막지 않게 합니다.

    전역 cursor를 다른 스레드에서 공유하지 않도록 별도 SQLite 연결을 사용합니다.
    """
    result = {
        "ok": True,
        "indexes": 0,
        "skipped": [],
        "db_size": 0,
        "error": "",
    }
    db = None
    try:
        db = sqlite3.connect(DATABASE_PATH, timeout=30)
        try:
            db.execute("PRAGMA journal_mode=WAL")
            db.execute("PRAGMA synchronous=NORMAL")
            db.execute("PRAGMA busy_timeout=30000")
            db.execute("PRAGMA temp_store=MEMORY")
        except sqlite3.Error:
            pass
        cur = db.cursor()
        for table_name, index_name, columns in MANEUNG_V193_INDEXES:
            try:
                cur.execute("SELECT 1 FROM sqlite_master WHERE type='table' AND name=?", (table_name,))
                if cur.fetchone() is None:
                    result["skipped"].append(table_name)
                    continue
                cur.execute(f"CREATE INDEX IF NOT EXISTS {index_name} ON {table_name}({columns})")
                result["indexes"] += 1
            except sqlite3.Error:
                result["skipped"].append(table_name)
        db.commit()
        try:
            db.execute("PRAGMA optimize")
            db.commit()
        except sqlite3.Error:
            pass
        try:
            if os.path.exists(DATABASE_PATH):
                result["db_size"] = os.path.getsize(DATABASE_PATH)
        except OSError:
            pass
    except Exception as e:
        result["ok"] = False
        result["error"] = f"{type(e).__name__}: {e}"
    finally:
        try:
            if db:
                db.close()
        except Exception:
            pass
    result["skipped"] = sorted(set(result.get("skipped") or []))
    return result

def build_maneung_db_maintenance_embed(result: dict):
    ok = bool(result.get("ok"))
    size = int(result.get("db_size") or 0)
    size_text = f"{size / 1024 / 1024:.2f} MB" if size else "확인 불가"
    embed = discord.Embed(
        title="⚡ DB 최적화 완료" if ok else "⚠️ DB 최적화 실패",
        description=(
            "SQLite WAL/인덱스/PRAGMA optimize를 적용했어요.\n"
            "무거운 DB 작업은 별도 스레드에서 처리해서 봇 반응 지연을 줄였습니다."
            if ok else "최적화 도중 오류가 발생했어요. `/만능 오류기록`도 같이 확인해주세요."
        ),
        color=COLOR_GREEN if ok else COLOR_WARNING,
    )
    embed.add_field(
        name="📊 결과",
        value=ultimate_box("DB", [
            f"확인/생성 인덱스: `{result.get('indexes', 0)}`개",
            f"DB 파일 크기: `{size_text}`",
            f"건너뛴 테이블: `{len(result.get('skipped') or [])}`개",
        ], "⚡")[:1024],
        inline=False,
    )
    if result.get("skipped"):
        embed.add_field(
            name="건너뛴 테이블",
            value=", ".join(f"`{x}`" for x in (result.get("skipped") or [])[:12]) or "없음",
            inline=False,
        )
    if result.get("error"):
        embed.add_field(name="오류", value=f"`{maneung_safe_text(result['error'], 900)}`", inline=False)
    embed.set_footer(text="만능 봇 | v193 DB 최적화")
    return embed


@ultimate_group.command(name="db최적화", description="SQLite DB 인덱스와 런타임 성능 옵션을 최적화합니다.")
async def ultimate_group_db_optimize(interaction: discord.Interaction):
    if await reject_if_not_ultimate_manager(interaction, "/만능 db최적화"):
        return
    await safe_interaction_defer(interaction, ephemeral=True)
    result = await asyncio.to_thread(run_maneung_db_maintenance)
    await safe_interaction_send(interaction, embed=build_maneung_db_maintenance_embed(result), ephemeral=True)


@tasks.loop(minutes=30)
async def maneung_runtime_cleanup_loop():
    """오래된 도배/쿨타임 캐시를 주기적으로 정리해 장시간 실행 시 메모리 증가를 줄입니다."""
    now = datetime.datetime.now().timestamp()
    try:
        for key, values in list(spam_tracker.items()):
            spam_tracker[key] = [t for t in values if now - float(t) <= max(SPAM_TIME * 3, 60)]
            if not spam_tracker[key]:
                spam_tracker.pop(key, None)
        for key, values in list(repeat_message_tracker.items()):
            repeat_message_tracker[key] = [(msg, ts) for msg, ts in values if now - float(ts) <= max(CENSOR_REPEAT_WINDOW * 3, 90)]
            if not repeat_message_tracker[key]:
                repeat_message_tracker.pop(key, None)
        for key, values in list(attachment_spam_tracker.items()):
            attachment_spam_tracker[key] = [(count, ts) for count, ts in values if now - float(ts) <= max(CENSOR_ATTACHMENT_WINDOW * 3, 120)]
            if not attachment_spam_tracker[key]:
                attachment_spam_tracker.pop(key, None)
        for key, ts in list(ENHANCE_COOLDOWNS.items()):
            if now - float(ts) > ENHANCE_COOLDOWN_SECONDS * 10:
                ENHANCE_COOLDOWNS.pop(key, None)
    except Exception as e:
        print(f"⚠️ 런타임 캐시 정리 실패: {e}")


