async def utility_dday(interaction: discord.Interaction, date: str, title: str = "일정"):
    try:
        target = datetime.datetime.strptime(date.strip(), "%Y-%m-%d").date()
    except ValueError:
        await safe_interaction_send(interaction, embed=mnb_simple_embed("⚠️ 날짜 오류", "날짜는 `YYYY-MM-DD` 형식으로 입력해주세요.", COLOR_WARNING), ephemeral=True)
        return
    today = mnb_now_kst().date()
    diff = (target - today).days
    if diff > 0:
        text = f"**{title}**까지 `D-{diff}`"
    elif diff == 0:
        text = f"**{title}**은/는 오늘이에요!"
    else:
        text = f"**{title}**은/는 `D+{abs(diff)}` 지났어요."
    await safe_interaction_send(interaction, embed=mnb_simple_embed("📅 디데이", text))


