def build_mnb_utility_panel_embed():
    embed = discord.Embed(
        title="🧰 편의 기능 통합 패널",
        description=(
            "`/편의` 하나로 25개 편의 기능을 모두 사용할 수 있어요.\n"
            "아래 선택 메뉴에서 원하는 기능을 고르면 바로 실행되거나 입력창이 열립니다."
        ),
        color=COLOR_SKY,
    )
    left = []
    right = []
    for index, (name, emoji, desc) in enumerate(MNB_UTILITY_PANEL_OPTIONS, 1):
        line = f"`{index:02}` {emoji} **{name}** — {desc}"
        if index <= 13:
            left.append(line)
        else:
            right.append(line)
    embed.add_field(name="📦 빠른 기능", value="\n".join(left)[:1024], inline=False)
    embed.add_field(name="🧩 입력 기능", value="\n".join(right)[:1024], inline=False)
    embed.add_field(
        name="안내",
        value="기존처럼 `/편의 핑` 식으로 펼쳐지지 않고, 이제 슬래시 목록에는 `/편의` 한 개만 보이게 정리했습니다.",
        inline=False,
    )
    embed.set_footer(text="만능 봇 | /편의 통합 패널")
    return embed


def mnb_find_member_from_text(guild: discord.Guild, query: str, default_member: discord.Member = None):
    if guild is None:
        return default_member
    raw = (query or "").strip()
    if not raw:
        return default_member
    cleaned = raw.replace("<@!", "").replace("<@", "").replace(">", "").strip()
    if cleaned.isdigit():
        return guild.get_member(int(cleaned)) or default_member
    lowered = raw.lower()
    for member in guild.members:
        if member.name.lower() == lowered or member.display_name.lower() == lowered:
            return member
    for member in guild.members:
        if lowered in member.name.lower() or lowered in member.display_name.lower():
            return member
    return default_member


def mnb_find_role_from_text(guild: discord.Guild, query: str):
    if guild is None:
        return None
    raw = (query or "").strip()
    cleaned = raw.replace("<@&", "").replace(">", "").strip()
    if cleaned.isdigit():
        role = guild.get_role(int(cleaned))
        if role:
            return role
    lowered = raw.lower()
    for role in guild.roles:
        if role.name.lower() == lowered:
            return role
    for role in guild.roles:
        if lowered and lowered in role.name.lower():
            return role
    return None


def mnb_find_text_channel_from_text(guild: discord.Guild, query: str, default_channel=None):
    if guild is None:
        return default_channel
    raw = (query or "").strip()
    if not raw:
        return default_channel
    cleaned = raw.replace("<#", "").replace(">", "").strip()
    if cleaned.isdigit():
        channel = guild.get_channel(int(cleaned))
        if isinstance(channel, discord.TextChannel):
            return channel
    lowered = raw.lstrip("#").lower()
    for channel in guild.text_channels:
        if channel.name.lower() == lowered:
            return channel
    for channel in guild.text_channels:
        if lowered and lowered in channel.name.lower():
            return channel
    return default_channel


class MnbUtilityInputModal(discord.ui.Modal):
    def __init__(self, mode: str):
        self.mode = mode
        title_map = {
            "유저정보": "유저정보 입력",
            "아바타": "아바타 입력",
            "주사위": "주사위 입력",
            "랜덤숫자": "랜덤숫자 입력",
            "선택": "선택 항목 입력",
            "셔플": "셔플 항목 입력",
            "퍼센트": "퍼센트 계산 입력",
            "계산": "계산식 입력",
            "글자수": "글자수 입력",
            "거꾸로": "거꾸로 입력",
            "대소문자": "대소문자 입력",
            "공지미리보기": "공지 미리보기 입력",
            "타이머": "타이머 입력",
            "투표간단": "간단 투표 입력",
            "디데이": "디데이 입력",
            "색상": "색상 입력",
            "역할정보": "역할정보 입력",
            "채널정보": "채널정보 입력",
        }
        super().__init__(title=title_map.get(mode, "편의 기능 입력"))
        self.first = None
        self.second = None
        self.third = None

        def add_first(label, placeholder="", required=True, max_length=200, default=None, style=discord.TextStyle.short):
            self.first = discord.ui.TextInput(label=label, placeholder=placeholder, required=required, max_length=max_length, default=default, style=style)
            self.add_item(self.first)

        def add_second(label, placeholder="", required=True, max_length=200, default=None, style=discord.TextStyle.short):
            self.second = discord.ui.TextInput(label=label, placeholder=placeholder, required=required, max_length=max_length, default=default, style=style)
            self.add_item(self.second)

        if mode in ("유저정보", "아바타"):
            add_first("유저 멘션/ID/닉네임", "비우면 내 정보로 실행", required=False)
        elif mode == "주사위":
            add_first("면 수", "예: 6", default="6")
            add_second("개수", "예: 1", default="1")
        elif mode == "랜덤숫자":
            add_first("최소값", "예: 1", default="1")
            add_second("최대값", "예: 100", default="100")
        elif mode in ("선택", "셔플"):
            add_first("항목들", "예: 피자, 치킨, 햄버거", max_length=1500, style=discord.TextStyle.paragraph)
        elif mode == "퍼센트":
            add_first("일부 값", "예: 25")
            add_second("전체 값", "예: 100")
        elif mode == "계산":
            add_first("계산식", "예: (10+5)*2")
        elif mode in ("글자수", "거꾸로"):
            add_first("문장", "처리할 문장을 입력", max_length=1900, style=discord.TextStyle.paragraph)
        elif mode == "대소문자":
            add_first("모드", "upper / lower / title", default="upper")
            add_second("문장", "영문 문장을 입력", max_length=1900, style=discord.TextStyle.paragraph)
        elif mode == "공지미리보기":
            add_first("공지 제목", "예: 서버 공지")
            add_second("공지 내용", "공지 내용을 입력", max_length=3800, style=discord.TextStyle.paragraph)
        elif mode == "타이머":
            add_first("초", "1~3600", default="60")
            add_second("메모", "예: 물 마시기", required=False, max_length=300)
        elif mode == "투표간단":
            add_first("투표 질문", "예: 오늘 내전 할까요?", max_length=1900, style=discord.TextStyle.paragraph)
        elif mode == "디데이":
            add_first("날짜", "YYYY-MM-DD", default=mnb_now_kst().strftime("%Y-%m-%d"))
            add_second("일정 이름", "예: 크리스마스", required=False, default="일정")
        elif mode == "색상":
            add_first("HEX 색상", "예: #87CEFA", default="#87CEFA")
        elif mode == "역할정보":
            add_first("역할 멘션/ID/이름", "예: 관리자")
        elif mode == "채널정보":
            add_first("채널 멘션/ID/이름", "비우면 현재 채널", required=False)
        else:
            add_first("입력", "값을 입력해주세요")

    async def on_submit(self, interaction: discord.Interaction):
        try:
            a = str(self.first.value).strip() if self.first else ""
            b = str(self.second.value).strip() if self.second else ""
            mode = self.mode
            if mode == "유저정보":
                member = mnb_find_member_from_text(interaction.guild, a, interaction.user)
                return await utility_user_info(interaction, member)
            if mode == "아바타":
                member = mnb_find_member_from_text(interaction.guild, a, interaction.user)
                return await utility_avatar(interaction, member)
            if mode == "주사위":
                sides = max(2, min(1000, int(a or 6)))
                count = max(1, min(20, int(b or 1)))
                return await utility_dice(interaction, sides, count)
            if mode == "랜덤숫자":
                return await utility_random_number(interaction, int(a), int(b))
            if mode == "선택":
                return await utility_choose(interaction, a)
            if mode == "셔플":
                return await utility_shuffle(interaction, a)
            if mode == "퍼센트":
                return await utility_percent(interaction, float(a), float(b))
            if mode == "계산":
                return await utility_calculate(interaction, a)
            if mode == "글자수":
                return await utility_text_count(interaction, a)
            if mode == "거꾸로":
                return await utility_reverse(interaction, a)
            if mode == "대소문자":
                return await utility_case(interaction, a, b)
            if mode == "공지미리보기":
                return await utility_notice_preview(interaction, a, b)
            if mode == "타이머":
                seconds = max(1, min(3600, int(a or 60)))
                return await utility_timer(interaction, seconds, b)
            if mode == "투표간단":
                return await utility_simple_vote(interaction, a)
            if mode == "디데이":
                return await utility_dday(interaction, a, b or "일정")
            if mode == "색상":
                return await utility_color(interaction, a)
            if mode == "역할정보":
                role = mnb_find_role_from_text(interaction.guild, a)
                if role is None:
                    return await safe_interaction_send(interaction, embed=mnb_simple_embed("⚠️ 역할 오류", "역할을 찾을 수 없어요. 역할 이름/ID/멘션을 확인해주세요.", COLOR_WARNING), ephemeral=True)
                return await utility_role_info(interaction, role)
            if mode == "채널정보":
                channel = mnb_find_text_channel_from_text(interaction.guild, a, interaction.channel)
                return await utility_channel_info(interaction, channel)
        except Exception as e:
            await safe_interaction_send(interaction, embed=mnb_simple_embed("⚠️ 입력 처리 실패", f"입력값을 확인해주세요.\n`{maneung_safe_text(e, 600) if 'maneung_safe_text' in globals() else str(e)}`", COLOR_WARNING), ephemeral=True)


class MnbUtilitySelect(discord.ui.Select):
    def __init__(self):
        options = [
            discord.SelectOption(label=name, value=name, description=desc[:100], emoji=emoji)
            for name, emoji, desc in MNB_UTILITY_PANEL_OPTIONS
        ]
        super().__init__(placeholder="사용할 편의 기능을 선택해주세요", min_values=1, max_values=1, options=options, custom_id="mnb_utility_panel_select")

    async def callback(self, interaction: discord.Interaction):
        mode = self.values[0]
        direct_actions = {
            "핑": utility_ping,
            "업타임": utility_uptime,
            "서버시간": utility_server_time,
            "내정보": utility_my_info,
            "서버아이콘": utility_server_icon,
            "코인": utility_coin,
            "서버요약": utility_server_summary,
        }
        if mode in direct_actions:
            return await direct_actions[mode](interaction)
        await interaction.response.send_modal(MnbUtilityInputModal(mode))


class MnbUtilityPanelView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=600)
        self.add_item(MnbUtilitySelect())

    @discord.ui.button(label="새로고침", emoji="🔄", style=discord.ButtonStyle.gray, custom_id="mnb_utility_panel_refresh")
    async def refresh(self, interaction: discord.Interaction, button: discord.ui.Button):
        await safe_interaction_edit(interaction, embed=build_mnb_utility_panel_embed(), view=MnbUtilityPanelView())


