# =========================
# v198 통합상점 상점 채널 자동 생성/복구
# =========================
SHOP_AUTOPANEL_LOCKS = {}
SHOP_PANEL_MARKER = "mnb_shop_panel_v210"
SHOP_PANEL_HISTORY_LIMIT = 300


SHOP_AUTOPANEL_CHANNEL_NAMES = [
    SHOP_CHANNEL_NAME,
    "🛒︱상점", "🛒ㅣ상점", "🛒-상점", "상점", "shop", "store",
]


async def ensure_integrated_shop_panel_for_guild(guild: discord.Guild, *, create_missing: bool = True):
    """서버의 상점 채널에 /통합상점 패널을 자동 생성/갱신합니다."""
    result = {
        "channel": None,
        "created_channel": False,
        "panel_changed": False,
    }
    if guild is None:
        return result

    saved_shop_channel_id = get_saved_channel_id(guild.id, "shop_channel_id")
    shop_channel = get_channel_by_id_or_name(
        guild,
        saved_shop_channel_id,
        SHOP_AUTOPANEL_CHANNEL_NAMES,
        "text",
    )

    if shop_channel is None and create_missing:
        shop_category = await get_or_create_category_under_rule(guild, SHOP_CATEGORY_NAME)
        await apply_member_category_permissions(guild, shop_category)
        shop_channel = await get_or_create_text_channel(guild, SHOP_CHANNEL_NAME, shop_category)
        result["created_channel"] = True
    elif shop_channel is not None and create_missing and shop_channel.category is None:
        # 상점 채널이 카테고리 밖에 있으면 보기 좋게 상점 카테고리로 정리합니다.
        try:
            shop_category = await get_or_create_category_under_rule(guild, SHOP_CATEGORY_NAME)
            await shop_channel.edit(category=shop_category, reason="통합상점 자동 패널 채널 정리")
        except discord.HTTPException:
            pass

    if shop_channel is None:
        return result

    result["channel"] = shop_channel
    try:
        save_guild_channel_ids(
            guild,
            shop_channel_id=shop_channel,
            shop_category_id=shop_channel.category if shop_channel.category else 0,
        )
    except Exception:
        pass

    # 예전 안내 임베드는 정리하고, 실제 구매 버튼이 붙은 통합상점 패널만 1개 유지합니다.
    lock = SHOP_AUTOPANEL_LOCKS.setdefault(guild.id, asyncio.Lock())
    async with lock:
        await delete_shop_point_auto_embeds(shop_channel)
        result["panel_changed"] = await send_integrated_shop_panel_to_channel(shop_channel, refresh_existing=True)
    return result


def is_latest_shop_panel_message(message: discord.Message) -> bool:
    """v210 이후 실제 상점 채널에 남길 최신 통합상점 패널인지 확인합니다."""
    if message is None or message.author != bot.user or not message.embeds:
        return False
    embed = message.embeds[0]
    footer_text = getattr(embed.footer, "text", "") or ""
    return SHOP_PANEL_MARKER in footer_text


def is_any_old_or_duplicate_shop_panel_message(message: discord.Message) -> bool:
    """구버전 통합상점/상점 안내 메시지인지 넓게 감지합니다.

    이미지에 나온 예전 임베드처럼 제목이 '만능 봇 통합 상점'이고
    구버전 버튼이 붙은 메시지도 삭제 대상에 포함합니다.
    단, v210 마커가 들어간 최신 패널은 절대 삭제하지 않습니다.
    """
    if message is None or message.author != bot.user or not message.embeds:
        return False
    if is_latest_shop_panel_message(message):
        return False

    embed = message.embeds[0]
    title = embed.title or ""
    description = embed.description or ""
    footer_text = getattr(embed.footer, "text", "") or ""
    combined = f"{title}\n{description}\n{footer_text}"

    old_keywords = [
        "상점 자동 안내",
        "통합 상점 안내",
        "만능 봇 통합 상점",
        "통합상점",
        "Sky Shop",
    ]
    if any(keyword in combined for keyword in old_keywords):
        return True
    if message_has_shop_components(message):
        return True
    return False


async def cleanup_all_shop_panel_duplicates(channel: discord.TextChannel):
    """상점 채널에서 최신 패널 1개만 남기고 나머지 상점 패널/구버전 안내를 정리합니다."""
    latest_panels = []
    old_or_duplicate_messages = []
    try:
        async for msg in channel.history(limit=SHOP_PANEL_HISTORY_LIMIT):
            if is_latest_shop_panel_message(msg):
                latest_panels.append(msg)
            elif is_obsolete_shop_guide_message(msg) or is_any_old_or_duplicate_shop_panel_message(msg):
                old_or_duplicate_messages.append(msg)
    except discord.HTTPException:
        pass

    # 최신 v210 패널도 여러 개면 가장 최근 1개만 유지합니다.
    keep = latest_panels[0] if latest_panels else None
    delete_targets = old_or_duplicate_messages + (latest_panels[1:] if len(latest_panels) > 1 else [])

    deleted_count = 0
    for msg in delete_targets:
        if keep is not None and msg.id == keep.id:
            continue
        try:
            await msg.delete()
            deleted_count += 1
        except discord.HTTPException:
            pass
    return keep, deleted_count


async def mnb_shop_open_channel_panel_response(interaction: discord.Interaction):
    """/통합상점, /경제 상점, 추가기능의 상점 버튼 공통 처리입니다.

    유저에게 임베드 상점을 또 띄우지 않고, 상점 채널의 단일 패널만 생성/갱신합니다.
    그래서 이미지처럼 통합상점 메시지가 2개씩 보이는 문제를 차단합니다.
    """
    await safe_interaction_defer(interaction, ephemeral=True, thinking=True)

    if interaction.guild is None:
        embed = discord.Embed(
            title="❌ 서버 전용 기능",
            description="통합상점 자동 패널은 서버 안에서만 사용할 수 있어요.",
            color=COLOR_WARNING,
        )
        return await safe_interaction_send(interaction, embed=embed, ephemeral=True)

    try:
        result = await ensure_integrated_shop_panel_for_guild(interaction.guild, create_missing=True)
        channel = result.get("channel")
        if channel is None:
            embed = discord.Embed(
                title="⚠️ 상점 채널 확인 실패",
                description="상점 채널을 찾거나 만들지 못했어요. 봇에게 채널 관리 권한이 있는지 확인해주세요.",
                color=COLOR_WARNING,
            )
            return await safe_interaction_send(interaction, embed=embed, ephemeral=True)

        embed = discord.Embed(
            title="✅ 통합상점 정리 완료",
            description=(
                f"{channel.mention} 채널에 **최신 통합상점 패널 1개만** 남겨뒀어요.\n"
                "구버전 안내 임베드와 중복 상점 패널은 자동 정리됩니다.\n\n"
                "상점 이용은 상점 채널에 있는 버튼/선택 메뉴로 하면 됩니다."
            ),
            color=COLOR_MINT,
        )
        embed.set_footer(text=f"만능 봇 | 통합상점 단일 패널 | {SHOP_PANEL_MARKER}")
        return await safe_interaction_send(interaction, embed=embed, ephemeral=True)
    except Exception as e:
        embed = discord.Embed(
            title="⚠️ 통합상점 정리 실패",
            description=f"오류: `{str(e)[:700]}`",
            color=COLOR_WARNING,
        )
        return await safe_interaction_send(interaction, embed=embed, ephemeral=True)


