def build_mnb_extra_panel_embed():
    embed = discord.Embed(
        title="🧩 추가기능 통합 패널",
        description=(
            "새 기능들을 따로 여러 명령어로 만들지 않고 **/추가기능 하나**에 전부 묶었어요.\n"
            "아래 선택 메뉴에서 원하는 기능을 고르면 바로 실행되거나 입력 박스가 열립니다.\n\n"
            "━━━━━━━━━━━━━━━━━━━━"
        ),
        color=COLOR_LAVENDER,
    )
    lines = [f"{emoji} **{name}** · {desc}" for name, emoji, desc in MNB_EXTRA_FEATURE_OPTIONS]
    mid = (len(lines) + 1) // 2
    embed.add_field(name="✨ 바로쓰기/추천", value="\n".join(lines[:mid]), inline=False)
    embed.add_field(name="🧰 입력형 도구", value="\n".join(lines[mid:]), inline=False)
    embed.add_field(
        name="안내",
        value="기능이 계속 늘어나도 슬래시 목록을 복잡하게 만들지 않고, 이런 식으로 패널 안에 묶어서 추가할 수 있어요.",
        inline=False,
    )
    embed.set_footer(text="만능 봇 | /추가기능 통합 패널")
    if bot.user:
        embed.set_thumbnail(url=bot.user.display_avatar.url)
    return embed


def mnb_extra_random_embed(title: str, result: str, *, color: int = COLOR_LAVENDER):
    embed = discord.Embed(title=title, description=result, color=color)
